"""
Parameterized generator for GH967_pymc_7844.

Source PR:    https://github.com/pymc-devs/pymc/pull/7844
Source Issue: https://github.com/pymc-devs/pymc/issues/7397

Seed varies: renames 'actually' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH967_pymc_7844'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH967_pymc_7844'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('actually', 'actually' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH967_pymc_7844',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 7844,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/7844",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pymc/model/core.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nfrom __future__ import annotations\n\nimport functools\nimport sys\nimport threading\nimport types\nimport warnings\n\nfrom collections.abc import Iterable, Sequence\nfrom typing import (\n    Literal,\n    cast,\n    overload,\n)\n\nimport numpy as np\nimport pytensor\nimport pytensor.sparse as sparse\nimport pytensor.tensor as pt\nimport scipy.sparse as sps\n\nfrom pytensor.compile import DeepCopyOp, Function, ProfileStats, get_mode\nfrom pytensor.compile.sharedvalue import SharedVariable\nfrom pytensor.graph.basic import Constant, Variable, ancestors, graph_inputs\nfrom pytensor.tensor.random.op import RandomVariable\nfrom pytensor.tensor.random.type import RandomType\nfrom pytensor.tensor.variable import TensorConstant, TensorVariable\n\nfrom pymc.blocking import DictToArrayBijection, RaveledVars\nfrom pymc.data import MinibatchOp, is_valid_observed\nfrom pymc.exceptions import (\n    BlockModelAccessError,\n    ImputationWarning,\n    SamplingError,\n    ShapeError,\n    ShapeWarning,\n)\nfrom pymc.initial_point import PointType, make_initial_point_fn\nfrom pymc.logprob.basic import transformed_conditional_logp\nfrom pymc.logprob.transforms import Transform\nfrom pymc.logprob.utils import ParameterValueError, replace_rvs_by_values\nfrom pymc.model_graph import model_to_graphviz, model_to_mermaid\nfrom pymc.pytensorf import (\n    PointFunc,\n    SeedSequenceSeed,\n    compile,\n    convert_observed_data,\n    gradient,\n    hessian,\n    inputvars,\n    join_nonshared_inputs,\n    rewrite_pregrad,\n)\nfrom pymc.util import (\n    UNSET,\n    VarName,\n    WithMemoization,\n    _UnsetType,\n    get_transformed_name,\n    get_value_vars_from_user_vars,\n    get_var_name,\n    treedict,\n    treelist,\n)\nfrom pymc.vartypes import continuous_types, discrete_types, typefilter\n\n__all__ = [\n    "Deterministic",\n    "Model",\n    "Point",\n    "Potential",\n    "compile_fn",\n    "modelcontext",\n    "set_data",\n]\n\n\nclass ModelManager(threading.local):\n    """Keeps track of currently active model contexts.\n\n    A global instance of this is created in this module on import.\n    Use that instance, `MODEL_MANAGER` to inspect current contexts.\n\n    It inherits from threading.local so is thread-safe, if models\n    can be entered/exited within individual threads.\n    """\n\n    def __init__(self):\n        self.active_contexts: list[Model] = []\n\n    @property\n    def current_context(self) -> Model | None:\n        """Return the innermost context of any current contexts."""\n        return self.active_contexts[-1] if self.active_contexts else None\n\n    @property\n    def parent_context(self) -> Model | None:\n        """Return the parent context to the active context, if any."""\n        return self.active_contexts[-2] if len(self.active_contexts) > 1 else None\n\n\n# MODEL_MANAGER is instantiated at import, and serves as a truth for\n# what any currently active model contexts are.\nMODEL_MANAGER = ModelManager()\n\n\ndef modelcontext(model: Model | None) -> Model:\n    """Return the given model or, if None was supplied, try to find one in the context stack."""\n    if model is None:\n        model = Model.get_context(error_if_none=False)\n\n        if model is None:\n            # TODO: This should be a ValueError, but that breaks\n            # ArviZ (and others?), so might need a deprecation.\n            raise TypeError("No model on context stack.")\n    return model\n\n\nclass ValueGradFunction:\n    """Create a PyTensor function that computes a value and its gradient.\n\n    Parameters\n    ----------\n    costs: list of PyTensor variables\n        We compute the weighted sum of the specified PyTensor values, and the gradient\n        of that sum. The weights can be specified with `ValueGradFunction.set_weights`.\n    grad_vars: list of named PyTensor variables or None\n        The arguments with respect to which the gradient is computed.\n    extra_vars_and_values: dict of PyTensor variables and their initial values\n        Other arguments of the function that are assumed constant and their\n        values. They are stored in shared variables and can be set using\n        `set_extra_values`.\n    dtype: str, default=pytensor.config.floatX\n        The dtype of the arrays.\n    casting: {\'no\', \'equiv\', \'save\', \'same_kind\', \'unsafe\'}, default=\'no\'\n        Casting rule for casting `grad_args` to the array dtype.\n        See `numpy.can_cast` for a description of the options.\n        Keep in mind that we cast the variables to the array *and*\n        back from the array dtype to the variable dtype.\n    compute_grads: bool, default=True\n        If False, return only the logp, not the gradient.\n    kwargs\n        Extra arguments are passed on to `pytensor.function`.\n\n    Attributes\n    ----------\n    profile: PyTensor profiling object or None\n        The profiling object of the PyTensor function that computes value and\n        gradient. This is None unless `profile=True` was set in the\n        kwargs.\n    """\n\n    def __init__(\n        self,\n        costs,\n        grad_vars,\n        extra_vars_and_values=None,\n        *,\n        dtype=None,\n        casting="no",\n        compute_grads=True,\n        model=None,\n        initial_point: PointType | None = None,\n        ravel_inputs: bool | None = None,\n        **kwargs,\n    ):\n        if extra_vars_and_values is None:\n            extra_vars_and_values = {}\n\n        names = [arg.name for arg in grad_vars + list(extra_vars_and_values.keys())]\n        if any(name is None for name in names):\n            raise ValueError("Arguments must be named.")\n        if len(set(names)) != len(names):\n            raise ValueError("Names of the arguments are not unique.")\n\n        self._grad_vars = grad_vars\n        self._extra_vars = list(extra_vars_and_values.keys())\n        self._extra_var_names = {var.name for var in extra_vars_and_values.keys()}\n\n        if dtype is None:\n            dtype = pytensor.config.floatX\n        self.dtype = dtype\n\n        self._n_costs = len(costs)\n        if self._n_costs == 0:\n            raise ValueError("At least one cost is required.")\n        weights = np.ones(self._n_costs - 1, dtype=self.dtype)\n        self._weights = pytensor.shared(weights, "__weights")\n\n        cost = costs[0]\n        for i, val in enumerate(costs[1:]):\n            if cost.ndim > 0 or val.ndim > 0:\n                raise ValueError("All costs must be scalar.")\n            cost = cost + self._weights[i] * val\n\n        self._extra_are_set = False\n        for var in self._grad_vars:\n            if not np.can_cast(var.dtype, self.dtype, casting):\n                raise TypeError(\n                    f"Invalid dtype for variable {var.name}. Can not "\n                    f"cast to {self.dtype} with casting rule {casting}."\n                )\n            if not np.issubdtype(var.dtype, np.floating):\n                raise TypeError(\n                    f"Invalid dtype for variable {var.name}. Must be "\n                    f"floating point but is {var.dtype}."\n                )\n\n        givens = []\n        self._extra_vars_shared = {}\n        for var, value in extra_vars_and_values.items():\n            shared = pytensor.shared(value, var.name + "_shared__", shape=value.shape)\n            self._extra_vars_shared[var.name] = shared\n            givens.append((var, shared))\n\n        cost = rewrite_pregrad(cost)\n\n        if compute_grads:\n            grads = pytensor.grad(cost, grad_vars, disconnected_inputs="ignore")\n            for grad_wrt, var in zip(grads, grad_vars):\n                grad_wrt.name = f"{var.name}_grad"\n            grads = pt.join(0, *[pt.atleast_1d(grad.ravel()) for grad in grads])\n            outputs = [cost, grads]\n        else:\n            outputs = [cost]\n\n        if ravel_inputs:\n            if initial_point is None:\n                initial_point = modelcontext(model).initial_point()\n            outputs, raveled_grad_vars = join_nonshared_inputs(\n                point=initial_point, inputs=grad_vars, outputs=outputs, make_inputs_shared=False\n            )\n            inputs = [raveled_grad_vars]\n        else:\n            if ravel_inputs is None:\n                warnings.warn(\n                    "ValueGradFunction will become a function of raveled inputs.\\n"\n                    "Specify `ravel_inputs` to suppress this warning. Note that setting `ravel_inputs=False` will be forbidden in a future release."\n                )\n            inputs = grad_vars\n\n        self._pytensor_function = compile(inputs, outputs, givens=givens, **kwargs)\n        self._raveled_inputs = ravel_inputs\n\n    def set_weights(self, values):\n        if values.shape != (self._n_costs - 1,):\n            raise ValueError("Invalid shape. Must be (n_costs - 1,).")\n        self._weights.set_value(values)\n\n    def set_extra_values(self, extra_vars):\n        self._extra_are_set = True\n        for var in self._extra_vars:\n            self._extra_vars_shared[var.name].set_value(extra_vars[var.name], borrow=True)\n\n    def get_extra_values(self):\n        if not self._extra_are_set:\n            raise ValueError("Extra values are not set.")\n\n        return {var.name: self._extra_vars_shared[var.name].get_value() for var in self._extra_vars}\n\n    def __call__(self, grad_vars, *, extra_vars=None):\n        if extra_vars is not None:\n            self.set_extra_values(extra_vars)\n        elif not self._extra_are_set:\n            raise ValueError("Extra values are not set.")\n\n        if isinstance(grad_vars, RaveledVars):\n            if self._raveled_inputs:\n                grad_vars = (grad_vars.data,)\n            else:\n                grad_vars = DictToArrayBijection.rmap(grad_vars).values()\n        elif self._raveled_inputs and not isinstance(grad_vars, Sequence):\n            grad_vars = (grad_vars,)\n\n        return self._pytensor_function(*grad_vars)\n\n    @property\n    def profile(self):\n        """Profiling information of the underlying PyTensor function."""\n        return self._pytensor_function.profile\n\n\nclass ContextMeta(type):\n    """A metaclass in order to apply a model\'s context during `Model.__init__``."""\n\n    # We want the Model\'s context to be active during __init__. In order for this\n    # to apply to subclasses of Model as well, we need to use a metaclass.\n    def __call__(cls: type[Model], *args, **kwargs):\n        instance = cls.__new__(cls, *args, **kwargs)\n        with instance:  # applies context\n            instance.__init__(*args, **kwargs)\n        return instance\n\n\nclass Model(WithMemoization, metaclass=ContextMeta):\n    """Encapsulates the variables and likelihood factors of a model.\n\n    Model class can be used for creating class based models. To create\n    a class based model you should inherit from :class:`~pymc.Model` and\n    override the `__init__` method with arbitrary definitions (do not\n    forget to call base class :meth:`pymc.Model.__init__` first).\n\n    Parameters\n    ----------\n    name : str\n        name that will be used as prefix for names of all random\n        variables defined within model\n    coords : dict\n        Xarray-like coordinate keys and values. These coordinates can be used\n        to specify the shape of random variables and to label (but not specify)\n        the shape of Determinsitic, Potential and Data objects.\n        Other than specifying the shape of random variables, coordinates have no\n        effect on the model. They can\'t be used for label-based broadcasting or indexing.\n        You must use numpy-like operations for those behaviors.\n    check_bounds : bool\n        Ensure that input parameters to distributions are in a valid\n        range. If your model is built in a way where you know your\n        parameters can only take on valid values you can set this to\n        False for increased speed. This should not be used if your model\n        contains discrete variables.\n    model : PyMC model, optional\n        A parent model that this model belongs to. If not specified and the current model\n        is created inside another model\'s context, the parent model will be set to that model.\n        If `None` the model will not have a parent.\n\n    Examples\n    --------\n    Use context manager to define model and respective variables\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            x = pm.Normal("x")\n\n\n    Use object API to define model and respective variables\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        model = pm.Model()\n        x = pm.Normal("x", model=model)\n\n\n    Use coords for defining the shape of random variables and labeling other model variables\n\n    .. code-block:: python\n\n        import pymc as pm\n        import numpy as np\n\n        coords = {\n            "feature",\n            ["A", "B", "C"],\n            "trial",\n            [1, 2, 3, 4, 5],\n        }\n\n        with pm.Model(coords=coords) as model:\n            # Variable will have default dim label `intercept__dim_0`\n            intercept = pm.Normal("intercept", shape=(3,))\n            # Variable will have shape (3,) and dim label `feature`\n            beta = pm.Normal("beta", dims=("feature",))\n\n            # Dims below are only used for labeling, they have no effect on shape\n            # Variable will have default dim label `idx__dim_0`\n            idx = pm.Data("idx", np.array([0, 1, 1, 2, 2]))\n            x = pm.Data("x", np.random.normal(size=(5, 3)), dims=("trial", "feature"))\n            # single dim can be passed as string\n            mu = pm.Deterministic("mu", intercept[idx] + beta @ x, dims="trial")\n\n            # Dims controls the shape of the variable\n            # If not specified, it would be inferred from the shape of the observations\n            y = pm.Normal("y", mu=mu, observed=[-1, 0, 0, 1, 1], dims=("trial",))\n\n\n    Define nested models, and provide name for variable name prefixing\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        with pm.Model(name="root") as root:\n            x = pm.Normal("x")  # Variable wil be named "root::x"\n\n            with pm.Model(name="first") as first:\n                # Variable will belong to root and first\n                y = pm.Normal("y", mu=x)  # Variable wil be named "root::first::y"\n\n            # Can pass parent model explicitly\n            with pm.Model(name="second", model=root) as second:\n                # Variable will belong to root and second\n                z = pm.Normal("z", mu=y)  # Variable wil be named "root::second::z"\n\n            # Set None for standalone model\n            with pm.Model(name="third", model=None) as third:\n                # Variable will belong to third only\n                w = pm.Normal("w")  # Variable wil be named "third::w"\n\n\n    Set `check_bounds` to False for models with only continuous variables and default transformers\n    PyMC will remove the bounds check from the model logp which can speed up sampling\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        with pm.Model(check_bounds=False) as model:\n            sigma = pm.HalfNormal("sigma")\n            x = pm.Normal("x", sigma=sigma)  # No bounds check will be performed on `sigma`\n\n\n    """\n\n    def __enter__(self):\n        """Enter the context manager."""\n        MODEL_MANAGER.active_contexts.append(self)\n        return self\n\n    def __exit__(self, exc_type: None, exc_val: None, exc_tb: None) -> None:\n        """Exit the context manager."""\n        _ = MODEL_MANAGER.active_contexts.pop()\n\n    def _display_(self):\n        import marimo as mo\n\n        return mo.mermaid(model_to_mermaid(self))\n\n    @staticmethod\n    def _validate_name(name):\n        if name.endswith(":"):\n            raise KeyError("name should not end with `:`")\n        return name\n\n    def __init__(\n        self,\n        name="",\n        coords=None,\n        check_bounds=True,\n        *,\n        model: _UnsetType | None | Model = UNSET,\n    ):\n        self.name = self._validate_name(name)\n        self.check_bounds = check_bounds\n        self._parent = model if not isinstance(model, _UnsetType) else MODEL_MANAGER.parent_context\n\n        if self.parent is not None:\n            self.named_vars = treedict(parent=self.parent.named_vars)\n            self.named_vars_to_dims = treedict(parent=self.parent.named_vars_to_dims)\n            self.values_to_rvs = treedict(parent=self.parent.values_to_rvs)\n            self.rvs_to_values = treedict(parent=self.parent.rvs_to_values)\n            self.rvs_to_transforms = treedict(parent=self.parent.rvs_to_transforms)\n            self.rvs_to_initial_values = treedict(parent=self.parent.rvs_to_initial_values)\n            self.free_RVs = treelist(parent=self.parent.free_RVs)\n            self.observed_RVs = treelist(parent=self.parent.observed_RVs)\n            self.deterministics = treelist(parent=self.parent.deterministics)\n            self.potentials = treelist(parent=self.parent.potentials)\n            self.data_vars = treelist(parent=self.parent.data_vars)\n            self._coords = self.parent._coords\n            self._dim_lengths = self.parent._dim_lengths\n        else:\n            self.named_vars = treedict()\n            self.named_vars_to_dims = treedict()\n            self.values_to_rvs = treedict()\n            self.rvs_to_values = treedict()\n            self.rvs_to_transforms = treedict()\n            self.rvs_to_initial_values = treedict()\n            self.free_RVs = treelist()\n            self.observed_RVs = treelist()\n            self.deterministics = treelist()\n            self.potentials = treelist()\n            self.data_vars = treelist()\n            self._coords = {}\n            self._dim_lengths = {}\n        self.add_coords(coords)\n\n        from pymc.printing import str_for_model\n\n        self.str_repr = types.MethodType(str_for_model, self)\n        self._repr_latex_ = types.MethodType(\n            functools.partial(str_for_model, formatting="latex"), self\n        )\n\n    @classmethod\n    def get_context(\n        cls, error_if_none: bool = True, allow_block_model_access: bool = False\n    ) -> Model | None:\n        model = MODEL_MANAGER.current_context\n        if isinstance(model, BlockModelAccess) and not allow_block_model_access:\n            raise BlockModelAccessError(model.error_msg_on_access)\n        if model is None and error_if_none:\n            raise TypeError("No model on context stack")\n        return model\n\n    @property\n    def parent(self):\n        return self._parent\n\n    @property\n    def root(self):\n        model = self\n        while not model.isroot:\n            model = model.parent\n        return model\n\n    @property\n    def isroot(self):\n        return self.parent is None\n\n    def logp_dlogp_function(\n        self,\n        grad_vars=None,\n        tempered=False,\n        initial_point: PointType | None = None,\n        ravel_inputs: bool | None = None,\n        **kwargs,\n    ):\n        """Compile a PyTensor function that computes logp and gradient.\n\n        Parameters\n        ----------\n        grad_vars : list of random variables, optional\n            Compute the gradient with respect to those variables. If None,\n            use all free random variables of this model.\n        tempered : bool\n            Compute the tempered logp `free_logp + alpha * observed_logp`.\n            `alpha` can be changed using `ValueGradFunction.set_weights([alpha])`.\n        """\n        if grad_vars is None:\n            grad_vars = self.continuous_value_vars\n        else:\n            grad_vars = get_value_vars_from_user_vars(grad_vars, self)\n            for i, var in enumerate(grad_vars):\n                if var.dtype not in continuous_types:\n                    raise ValueError(f"Can only compute the gradient of continuous types: {var}")\n\n        if tempered:\n            costs = [self.varlogp, self.datalogp]\n        else:\n            costs = [self.logp()]\n\n        input_vars = {i for i in graph_inputs(costs) if not isinstance(i, Constant)}\n        if initial_point is None:\n            initial_point = self.initial_point(0)\n        extra_vars_and_values = {\n            var: initial_point[var.name]\n            for var in self.value_vars\n            if var in input_vars and var not in grad_vars\n        }\n        return ValueGradFunction(\n            costs,\n            grad_vars,\n            extra_vars_and_values,\n            model=self,\n            initial_point=initial_point,\n            ravel_inputs=ravel_inputs,\n            **kwargs,\n        )\n\n    def compile_logp(\n        self,\n        vars: Variable | Sequence[Variable] | None = None,\n        jacobian: bool = True,\n        sum: bool = True,\n        **compile_kwargs,\n    ) -> PointFunc:\n        """Compiled log probability density function.\n\n        Parameters\n        ----------\n        vars : list of random variables or potential terms, optional\n            Compute the gradient with respect to those variables. If None, use all\n            free and observed random variables, as well as potential terms in model.\n        jacobian : bool\n            Whether to include jacobian terms in logprob graph. Defaults to True.\n        sum : bool\n            Whether to sum all logp terms or return elemwise logp for each variable.\n            Defaults to True.\n        """\n        return self.compile_fn(self.logp(vars=vars, jacobian=jacobian, sum=sum), **compile_kwargs)\n\n    def compile_dlogp(\n        self,\n        vars: Variable | Sequence[Variable] | None = None,\n        jacobian: bool = True,\n        **compile_kwargs,\n    ) -> PointFunc:\n        """Compiled log probability density gradient function.\n\n        Parameters\n        ----------\n        vars : list of random variables or potential terms, optional\n            Compute the gradient with respect to those variables. If None, use all\n            free and observed random variables, as well as potential terms in model.\n        jacobian : bool\n            Whether to include jacobian terms in logprob graph. Defaults to True.\n        """\n        return self.compile_fn(self.dlogp(vars=vars, jacobian=jacobian), **compile_kwargs)\n\n    def compile_d2logp(\n        self,\n        vars: Variable | Sequence[Variable] | None = None,\n        jacobian: bool = True,\n        negate_output=True,\n        **compile_kwargs,\n    ) -> PointFunc:\n        """Compiled log probability density hessian function.\n\n        Parameters\n        ----------\n        vars : list of random variables or potential terms, optional\n            Compute the gradient with respect to those variables. If None, use all\n            free and observed random variables, as well as potential terms in model.\n        jacobian : bool\n            Whether to include jacobian terms in logprob graph. Defaults to True.\n        """\n        return self.compile_fn(\n            self.d2logp(vars=vars, jacobian=jacobian, negate_output=negate_output),\n            **compile_kwargs,\n        )\n\n    def logp(\n        self,\n        vars: Variable | Sequence[Variable] | None = None,\n        jacobian: bool = True,\n        sum: bool = True,\n    ) -> Variable | list[Variable]:\n        """Elemwise log-probability of the model.\n\n        Parameters\n        ----------\n        vars : list of random variables or potential terms, optional\n            Compute the gradient with respect to those variables. If None, use all\n            free and observed random variables, as well as potential terms in model.\n        jacobian : bool\n            Whether to include jacobian terms in logprob graph. Defaults to True.\n        sum : bool\n            Whether to sum all logp terms or return elemwise logp for each variable.\n            Defaults to True.\n\n        Returns\n        -------\n        Logp graph(s)\n        """\n        varlist: list[TensorVariable]\n        if vars is None:\n            varlist = self.free_RVs + self.observed_RVs + self.potentials\n        elif not isinstance(vars, list | tuple):\n            varlist = [vars]\n        else:\n            varlist = cast(list[TensorVariable], vars)\n\n        # We need to separate random variables from potential terms, and remember their\n        # original order so that we can merge them together in the same order at the end\n        rvs = []\n        potentials = []\n        rv_order, potential_order = [], []\n        for i, var in enumerate(varlist):\n            rv = self.values_to_rvs.get(var, var)\n            if rv in self.basic_RVs:\n                rvs.append(rv)\n                rv_order.append(i)\n            else:\n                if var in self.potentials:\n                    potentials.append(var)\n                    potential_order.append(i)\n                else:\n                    raise ValueError(\n                        f"Requested variable {var} not found among the model variables"\n                    )\n\n        rv_logps: list[TensorVariable] = []\n        if rvs:\n            rv_logps = transformed_conditional_logp(\n                rvs=rvs,\n                rvs_to_values=self.rvs_to_values,\n                rvs_to_transforms=self.rvs_to_transforms,\n                jacobian=jacobian,\n            )\n            assert isinstance(rv_logps, list)\n\n        # Replace random variables by their value variables in potential terms\n        potential_logps = []\n        if potentials:\n            potential_logps = self.replace_rvs_by_values(potentials)\n\n        logp_factors = [None] * len(varlist)\n        for logp_order, logp in zip((rv_order + potential_order), (rv_logps + potential_logps)):\n            logp_factors[logp_order] = logp\n\n        if not sum:\n            return logp_factors\n\n        logp_scalar = pt.sum([pt.sum(factor) for factor in logp_factors])\n        logp_scalar_name = "__logp" if jacobian else "__logp_nojac"\n        if self.name:\n            logp_scalar_name = f"{logp_scalar_name}_{self.name}"\n        logp_scalar.name = logp_scalar_name\n        return logp_scalar\n\n    def dlogp(\n        self,\n        vars: Variable | Sequence[Variable] | None = None,\n        jacobian: bool = True,\n    ) -> Variable:\n        """Gradient of the models log-probability w.r.t. ``vars``.\n\n        Parameters\n        ----------\n        vars : list of random variables or potential terms, optional\n            Compute the gradient with respect to those variables. If None, use all\n            free and observed random variables, as well as potential terms in model.\n        jacobian : bool\n            Whether to include jacobian terms in logprob graph. Defaults to True.\n\n        Returns\n        -------\n        dlogp graph\n        """\n        if vars is None:\n            value_vars = None\n        else:\n            if not isinstance(vars, list | tuple):\n                vars = [vars]\n\n            value_vars = []\n            for i, var in enumerate(vars):\n                value_var = self.rvs_to_values.get(var)\n                if value_var is not None:\n                    value_vars.append(value_var)\n                else:\n                    raise ValueError(\n                        f"Requested variable {var} not found among the model variables"\n                    )\n\n        cost = self.logp(jacobian=jacobian)\n        cost = rewrite_pregrad(cost)\n        return gradient(cost, value_vars)\n\n    def d2logp(\n        self,\n        vars: Variable | Sequence[Variable] | None = None,\n        jacobian: bool = True,\n        negate_output=True,\n    ) -> Variable:\n        """Hessian of the models log-probability w.r.t. ``vars``.\n\n        Parameters\n        ----------\n        vars : list of random variables or potential terms, optional\n            Compute the gradient with respect to those variables. If None, use all\n            free and observed random variables, as well as potential terms in model.\n        jacobian : bool\n            Whether to include jacobian terms in logprob graph. Defaults to True.\n\n        Returns\n        -------\n        d²logp graph\n        """\n        if vars is None:\n            value_vars = None\n        else:\n            if not isinstance(vars, list | tuple):\n                vars = [vars]\n\n            value_vars = []\n            for i, var in enumerate(vars):\n                value_var = self.rvs_to_values.get(var)\n                if value_var is not None:\n                    value_vars.append(value_var)\n                else:\n                    raise ValueError(\n                        f"Requested variable {var} not found among the model variables"\n                    )\n\n        cost = self.logp(jacobian=jacobian)\n        cost = rewrite_pregrad(cost)\n        return hessian(cost, value_vars, negate_output=negate_output)\n\n    @property\n    def datalogp(self) -> Variable:\n        """PyTensor scalar of log-probability of the observed variables and potential terms."""\n        return self.observedlogp + self.potentiallogp\n\n    @property\n    def varlogp(self) -> Variable:\n        """PyTensor scalar of log-probability of the unobserved random variables (excluding deterministic)."""\n        return self.logp(vars=self.free_RVs)\n\n    @property\n    def varlogp_nojac(self) -> Variable:\n        """PyTensor scalar of log-probability of the unobserved random variables (excluding deterministic) without jacobian term."""\n        return self.logp(vars=self.free_RVs, jacobian=False)\n\n    @property\n    def observedlogp(self) -> Variable:\n        """PyTensor scalar of log-probability of the observed variables."""\n        return self.logp(vars=self.observed_RVs)\n\n    @property\n    def potentiallogp(self) -> Variable:\n        """PyTensor scalar of log-probability of the Potential terms."""\n        # Convert random variables in Potential expression into their log-likelihood\n        # inputs and apply their transforms, if any\n        potentials = self.replace_rvs_by_values(self.potentials)\n        if potentials:\n            return pt.sum([pt.sum(factor) for factor in potentials])\n        else:\n            return pt.constant(0.0)\n\n    @property\n    def value_vars(self):\n        """List of unobserved random variables used as inputs to the model\'s log-likelihood (which excludes deterministics)."""\n        return [self.rvs_to_values[v] for v in self.free_RVs]\n\n    @property\n    def unobserved_value_vars(self):\n        """List of all random variables (including untransformed projections), as well as deterministics used as inputs and outputs of the model\'s log-likelihood graph."""\n        vars = []\n        transformed_rvs = []\n        for rv in self.free_RVs:\n            value_var = self.rvs_to_values[rv]\n            transform = self.rvs_to_transforms[rv]\n            if transform is not None:\n                transformed_rvs.append(rv)\n            vars.append(value_var)\n\n        # Remove rvs from untransformed values graph\n        untransformed_vars = self.replace_rvs_by_values(transformed_rvs)\n\n        # Remove rvs from deterministics graph\n        deterministics = self.replace_rvs_by_values(self.deterministics)\n\n        return vars + untransformed_vars + deterministics\n\n    @property\n    def discrete_value_vars(self):\n        """All the discrete value variables in the model."""\n        return list(typefilter(self.value_vars, discrete_types))\n\n    @property\n    def continuous_value_vars(self):\n        """All the continuous value variables in the model."""\n        return list(typefilter(self.value_vars, continuous_types))\n\n    @property\n    def basic_RVs(self):\n        """List of random variables the model is defined in terms of.\n\n        This excludes deterministics.\n\n        These are the actual random variable terms that make up the\n        "sample-space" graph (i.e. you can sample these graphs by compiling them\n        with `pytensor.function`).  If you want the corresponding log-likelihood terms,\n        use `model.value_vars` instead.\n        """\n        return self.free_RVs + self.observed_RVs\n\n    @property\n    def unobserved_RVs(self):\n        """List of all random variables, including deterministic ones.\n\n        These are the actual random variable terms that make up the\n        "sample-space" graph (i.e. you can sample these graphs by compiling them\n        with `pytensor.function`).  If you want the corresponding log-likelihood terms,\n        use `var.unobserved_value_vars` instead.\n        """\n        return self.free_RVs + self.deterministics\n\n    @property\n    def coords(self) -> dict[str, tuple | None]:\n        """Coordinate values for model dimensions."""\n        return self._coords\n\n    @property\n    def dim_lengths(self) -> dict[str, TensorVariable]:\n        """The symbolic lengths of dimensions in the model.\n\n        The values are typically instances of ``TensorVariable`` or ``ScalarSharedVariable``.\n        """\n        return self._dim_lengths\n\n    def shape_from_dims(self, dims):\n        shape = []\n        if len(set(dims)) != len(dims):\n            raise ValueError("Can not contain the same dimension name twice.")\n        for dim in dims:\n            if dim not in self.coords:\n                raise ValueError(\n                    f"Unknown dimension name \'{dim}\'. All dimension "\n                    "names must be specified in the `coords` "\n                    "argument of the model or through a pm.Data "\n                    "variable."\n                )\n            shape.extend(np.shape(self.coords[dim]))\n        return tuple(shape)\n\n    def add_coord(\n        self,\n        name: str,\n        values: Sequence | np.ndarray | None = None,\n        *,\n        length: int | Variable | None = None,\n    ):\n        """Register a dimension coordinate with the model.\n\n        Parameters\n        ----------\n        name : str\n            Name of the dimension.\n            Forbidden: {"chain", "draw", "__sample__"}\n        values : optional, array_like\n            Coordinate values or ``None`` (for auto-numbering).\n            If ``None`` is passed, a ``length`` must be specified.\n        length : optional, scalar\n            A scalar of the dimensions length.\n            Defaults to ``pytensor.tensor.constant(len(values))``.\n        """\n        if name in {"draw", "chain", "__sample__"}:\n            raise ValueError(\n                "Dimensions can not be named `draw`, `chain` or `__sample__`, "\n                "as those are reserved for use in `InferenceData`."\n            )\n        if values is None and length is None:\n            raise ValueError(\n                f"Either `values` or `length` must be specified for the \'{name}\' dimension."\n            )\n        if values is not None:\n            # Conversion to a tuple ensures that the coordinate values are immutable.\n            # Also unlike numpy arrays the\'s tuple.index(...) which is handy to work with.\n            values = tuple(values)\n        if name in self.coords:\n            if not np.array_equal(values, self.coords[name]):\n                raise ValueError(f"Duplicate and incompatible coordinate: {name}.")\n            return\n        if length is not None and not isinstance(length, int | Variable):\n            raise ValueError(\n                f"The `length` passed for the \'{name}\' coord must be an int, PyTensor Variable or None."\n            )\n        if length is None:\n            length = len(values)\n        if not isinstance(length, Variable):\n            length = pytensor.shared(length, name=name)\n        assert length.type.ndim == 0\n        self._dim_lengths[name] = length\n        self._coords[name] = values\n\n    def add_coords(\n        self,\n        coords: dict[str, Sequence | None],\n        *,\n        lengths: dict[str, int | Variable | None] | None = None,\n    ):\n        """Vectorized version of ``Model.add_coord``."""\n        if coords is None:\n            return\n        lengths = lengths or {}\n\n        for name, values in coords.items():\n            self.add_coord(name, values, length=lengths.get(name, None))\n\n    def set_dim(self, name: str, new_length: int, coord_values: Sequence | None = None):\n        """Update a mutable dimension.\n\n        Parameters\n        ----------\n        name : str\n            Name of the dimension.\n        new_length : int\n            New length of the dimension.\n        coord_values : array_like, optional\n            Optional sequence of coordinate values.\n        """\n        if coord_values is None and self.coords.get(name, None) is not None:\n            raise ValueError(\n                f"\'{name}\' has coord values. Pass `set_dim(..., coord_values=...)` to update them."\n            )\n        if coord_values is not None:\n            len_cvals = len(coord_values)\n            if len_cvals != new_length:\n                raise ShapeError(\n                    "Length of new coordinate values does not match the new dimension length.",\n                    actual=len_cvals,\n                    expected=new_length,\n                )\n            self._coords[name] = tuple(coord_values)\n        dim_length = self.dim_lengths[name]\n        if not isinstance(dim_length, SharedVariable):\n            raise TypeError(\n                f"The dim_length of `{name}` must be a `SharedVariable` "\n                "(created through `coords` to allow updating). "\n                f"The current type is: {type(dim_length)}"\n            )\n        dim_length.set_value(new_length)\n        return\n\n    def initial_point(self, random_seed: SeedSequenceSeed = None) -> dict[str, np.ndarray]:\n        """Compute the initial point of the model.\n\n        Parameters\n        ----------\n        random_seed : SeedSequenceSeed, default None\n            Seed(s) for generating initial point from the model. Passed into :func:`pymc.pytensorf.reseed_rngs`\n\n        Returns\n        -------\n        ip : dict of {str : array_like}\n            Maps names of transformed variables to numeric initial values in the transformed space.\n        """\n        fn = make_initial_point_fn(model=self, return_transformed=True)\n        return Point(fn(random_seed), model=self)\n\n    def set_initval(self, rv_var, initval):\n        """Set an initial value (strategy) for a random variable."""\n        if initval is not None and not isinstance(initval, Variable | str):\n            # Convert scalars or array-like inputs to ndarrays\n            initval = rv_var.type.filter(initval)\n\n        self.rvs_to_initial_values[rv_var] = initval\n\n    def set_data(\n        self,\n        name: str,\n        values: Sequence | np.ndarray,\n        coords: dict[str, Sequence] | None = None,\n    ):\n        """Change the values of a data variable in the model.\n\n        In contrast to pm.Data().set_value, this method can also\n        update the corresponding coordinates.\n\n        Parameters\n        ----------\n        name : str\n            Name of a shared variable in the model.\n        values : array_like\n            New values for the shared variable.\n        coords : optional, dict\n            New coordinate values for dimensions of the shared variable.\n            Must be provided for all named dimensions that change in length\n            and already have coordinate values.\n        """\n        shared_object = self[name]\n        if not isinstance(shared_object, SharedVariable):\n            raise TypeError(\n                f"The variable `{name}` must be a `SharedVariable` "\n                "(created through `pm.Data()` to allow updating.) "\n                f"The current type is: {type(shared_object)}"\n            )\n\n        if isinstance(values, list):\n            values = np.array(values)\n        values = convert_observed_data(values)\n        dims = self.named_vars_to_dims.get(name, None) or ()\n        coords = coords or {}\n\n        if values.ndim != shared_object.ndim:\n            raise ValueError(\n                f"New values for \'{name}\' must have {shared_object.ndim} dimensions, just like the original."\n            )\n\n        for d, dname in enumerate(dims):\n            length_tensor = self.dim_lengths[dname]\n            old_length = length_tensor.eval()\n            new_length = values.shape[d]\n            original_coords = self.coords.get(dname, None)\n            new_coords = coords.get(dname, None)\n\n            length_changed = new_length != old_length\n\n            # Reject resizing if we already know that it would create shape problems.\n            # NOTE: If there are multiple pm.Data containers sharing this dim, but the user only\n            #       changes the values for one of them, they will run into shape problems nonetheless.\n            if length_changed:\n                if original_coords is not None:\n                    if new_coords is None:\n                        raise ValueError(\n                            f"The \'{name}\' variable already had {len(original_coords)} coord values defined for "\n                            f"its {dname} dimension. With the new values this dimension changes to length "\n                            f"{new_length}, so new coord values for the {dname} dimension are required."\n                        )\n                if isinstance(length_tensor, TensorConstant):\n                    # The dimension was fixed in length.\n                    # Resizing a data variable in this dimension would\n                    # definitely lead to shape problems.\n                    raise ShapeError(\n                        f"Resizing dimension \'{dname}\' is impossible, because "\n                        "a `TensorConstant` stores its length. To be able "\n                        "to change the dimension length, create data with "\n                        "pm.Data() instead."\n                    )\n                elif length_tensor.owner is not None:\n                    # The dimension was created from another variable:\n                    length_tensor_origin = length_tensor.owner.inputs[0]\n                    # Get a handle on the tensor from which this dimension length was\n                    # obtained by doing subindexing on the shape as in `.shape[i]`.\n                    if isinstance(length_tensor_origin, TensorConstant):\n                        raise ShapeError(\n                            f"Resizing dimension \'{dname}\' with values of length {new_length} would lead to incompatibilities, "\n                            f"because the dimension length is tied to a TensorConstant. "\n                            f"Check if the dimension was defined implicitly before the shared variable \'{name}\' was created, "\n                            f"for example by another model variable.",\n                            actual=new_length,\n                            expected=old_length,\n                        )\n\n                    # The shape entry this dimension is tied to is not a TensorConstant.\n                    # Whether the dimension can be resized depends on the kind of Variable the shape belongs to.\n                    # TODO: Consider checking the graph is what we are assuming it is\n                    # isinstance(length_tensor.owner.op, Subtensor)\n                    # isinstance(length_tensor.owner.inputs[0].owner.op, Shape)\n                    length_belongs_to = length_tensor_origin.owner.inputs[0]\n\n                    if length_belongs_to is shared_object:\n                        # This is the shared variable that\'s being updated!\n                        # No surprise it\'s changing.\n                        pass\n                    elif isinstance(length_belongs_to, SharedVariable):\n                        # The dimension is mutable through a SharedVariable other than the one being modified.\n                        # But the other variable was not yet re-sized! Warn the user to do that!\n                        warnings.warn(\n                            f"You are resizing a variable with dimension \'{dname}\' which was initialized "\n                            f"as a mutable dimension by another variable (\'{length_belongs_to}\')."\n                            " Remember to update that variable with the correct shape to avoid shape issues.",\n                            ShapeWarning,\n                            stacklevel=2,\n                        )\n                    else:\n                        # The dimension is immutable.\n                        raise ShapeError(\n                            f"Resizing dimension \'{dname}\' with values of length {new_length} would lead to incompatibilities, "\n                            f"because the dimension was initialized from \'{length_belongs_to}\' which is not a shared variable. "\n                            f"Check if the dimension was defined implicitly before the shared variable \'{name}\' was created, "\n                            f"for example by another model variable.",\n                            actual=new_length,\n                            expected=old_length,\n                        )\n                if isinstance(length_tensor, SharedVariable):\n                    # The dimension is mutable, but was defined without being linked\n                    # to a shared variable. This is allowed, but a little less robust.\n                    self.set_dim(dname, new_length, coord_values=new_coords)\n\n            if new_coords is not None:\n                # Update the registered coord values (also if they were None)\n                if len(new_coords) != new_length:\n                    raise ShapeError(\n                        f"Length of new coordinate values for dimension \'{dname}\' does not match the provided values.",\n                        actual=len(new_coords),\n                        expected=new_length,\n                    )\n                # store it as tuple for immutability as in add_coord\n                self._coords[dname] = tuple(new_coords)\n\n        shared_object.set_value(values)\n\n    def register_rv(\n        self,\n        rv_var: RandomVariable,\n        name: str,\n        *,\n        observed=None,\n        total_size=None,\n        dims=None,\n        default_transform=UNSET,\n        transform=UNSET,\n        initval=None,\n    ) -> TensorVariable:\n        """Register an (un)observed random variable with the model.\n\n        Parameters\n        ----------\n        rv_var : TensorVariable\n        name : str\n            Intended name for the model variable.\n        observed : array_like, optional\n            Data values for observed variables.\n        total_size : scalar\n            upscales logp of variable with ``coef = total_size/var.shape[0]``\n        dims : tuple\n            Dimension names for the variable.\n        default_transform\n            A default transform for the random variable in log-likelihood space.\n        transform\n            Additional transform which may be applied after default transform.\n        initval\n            The initial value of the random variable.\n\n        Returns\n        -------\n        TensorVariable\n        """\n        name = self.name_for(name)\n        rv_var.name = name\n\n        # Associate previously unknown dimension names with\n        # the length of the corresponding RV dimension.\n        if dims is not None:\n            for d, dname in enumerate(dims):\n                if not isinstance(dname, str):\n                    raise TypeError(f"Dims must be string. Got {dname} of type {type(dname)}")\n                if dname not in self.dim_lengths:\n                    self.add_coord(dname, values=None, length=rv_var.shape[d])\n\n        if observed is None:\n            if total_size is not None:\n                raise ValueError("total_size can only be passed to observed RVs")\n            self.free_RVs.append(rv_var)\n            self.create_value_var(rv_var, transform=transform, default_transform=default_transform)\n            self.add_named_variable(rv_var, dims)\n            self.set_initval(rv_var, initval)\n        else:\n            if total_size is None and isinstance(observed, TensorVariable):\n                for node in ancestors([observed]):\n                    if node.owner is not None and isinstance(node.owner.op, MinibatchOp):\n                        warnings.warn(\n                            f"total_size not provided for observed variable `{name}` that uses pm.Minibatch"\n                        )\n                        break\n            if not is_valid_observed(observed):\n                raise TypeError(\n                    "Variables that depend on other nodes cannot be used for observed data."\n                    f"The data variable was: {observed}"\n                )\n\n            # `rv_var` is potentially changed by `make_obs_var`,\n            # for example into a new graph for imputation of missing data.\n            rv_var = self.make_obs_var(\n                rv_var, observed, dims, default_transform, transform, total_size\n            )\n\n        return rv_var\n\n    def make_obs_var(\n        self,\n        rv_var: TensorVariable,\n        data: np.ndarray,\n        dims,\n        default_transform: Transform | None,\n        transform: Transform | None,\n        total_size: int | None,\n    ) -> TensorVariable:\n        """Create a `TensorVariable` for an observed random variable.\n\n        Parameters\n        ----------\n        rv_var : TensorVariable\n            The random variable that is observed.\n            Its dimensionality must be compatible with the data already.\n        data : array_like\n            The observed data.\n        dims : tuple\n            Dimension names for the variable.\n        default_transform\n            A transform for the random variable in log-likelihood space.\n        transform\n            Additional transform which may be applied after default transform.\n\n        Returns\n        -------\n        TensorVariable\n        """\n        name = rv_var.name\n        data = convert_observed_data(data).astype(rv_var.dtype)\n\n        if data.ndim != rv_var.ndim:\n            raise ShapeError(\n                "Dimensionality of data and RV don\'t match.", actual=data.ndim, expected=rv_var.ndim\n            )\n\n        mask = getattr(data, "mask", None)\n        if mask is not None:\n            impute_message = (\n                f"Data in {rv_var} contains missing values and"\n                " will be automatically imputed from the"\n                " sampling distribution."\n            )\n            warnings.warn(impute_message, ImputationWarning)\n\n            if total_size is not None:\n                raise ValueError("total_size is not compatible with imputed variables")\n\n            from pymc.distributions.distribution import create_partial_observed_rv\n\n            (\n                (observed_rv, observed_mask),\n                (unobserved_rv, _),\n                joined_rv,\n            ) = create_partial_observed_rv(rv_var, mask)\n            observed_data = pt.as_tensor(data.data[observed_mask])\n\n            # Register ObservedRV corresponding to observed component\n            observed_rv.name = f"{name}_observed"\n            self.create_value_var(\n                observed_rv, transform=transform, default_transform=None, value_var=observed_data\n            )\n            self.add_named_variable(observed_rv)\n            self.observed_RVs.append(observed_rv)\n\n            # Register FreeRV corresponding to unobserved components\n            self.register_rv(\n                unobserved_rv,\n                f"{name}_unobserved",\n                transform=transform,\n                default_transform=default_transform,\n            )\n\n            # Register Deterministic that combines observed and missing\n            # Note: This can widely increase memory consumption during sampling for large datasets\n            rv_var = Deterministic(name, joined_rv, self, dims)\n\n        else:\n            if sps.issparse(data):\n                data = sparse.basic.as_sparse(data, name=name)\n            else:\n                data = pt.as_tensor_variable(data, name=name)\n\n            if total_size:\n                from pymc.variational.minibatch_rv import create_minibatch_rv\n\n                rv_var = create_minibatch_rv(rv_var, total_size)\n                rv_var.name = name\n\n            rv_var.tag.observations = data\n            self.create_value_var(\n                rv_var, transform=transform, default_transform=None, value_var=data\n            )\n            self.add_named_variable(rv_var, dims)\n            self.observed_RVs.append(rv_var)\n\n        return rv_var\n\n    def create_value_var(\n        self,\n        rv_var: TensorVariable,\n        *,\n        default_transform: Transform,\n        transform: Transform,\n        value_var: Variable | None = None,\n    ) -> TensorVariable:\n        """Create a ``TensorVariable`` that will be used as the random variable\'s "value" in log-likelihood graphs.\n\n        In general, we\'ll call this type of variable the "value" variable.\n\n        In all other cases, the role of the value variable is taken by\n        observed data. That\'s why value variables are only referenced in\n        this branch of the conditional.\n\n        Parameters\n        ----------\n        rv_var : TensorVariable\n\n        default_transform: Transform\n            A transform for the random variable in log-likelihood space.\n\n        transform: Transform\n            Additional transform which may be applied after default transform.\n\n        value_var : Variable, optional\n\n        Returns\n        -------\n        TensorVariable\n        """\n        from pymc.distributions.transforms import ChainedTransform, _default_transform\n\n        # Make the value variable a transformed value variable,\n        # if there\'s an applicable transform\n        if transform is None and default_transform is UNSET:\n            default_transform = None\n            warnings.warn(\n                "To disable default transform, please use default_transform=None"\n                " instead of transform=None. Setting transform to None will"\n                " not have any effect in future.",\n                UserWarning,\n            )\n\n        if default_transform is UNSET:\n            if rv_var.owner is None:\n                default_transform = None\n            else:\n                default_transform = _default_transform(rv_var.owner.op, rv_var)\n\n        if transform is UNSET:\n            transform = default_transform\n        elif transform is not None and default_transform is not None:\n            transform = ChainedTransform([default_transform, transform])\n\n        if value_var is None:\n            if transform is None:\n                # Create value variable with the same type as the RV\n                value_var = rv_var.type()\n                value_var.name = rv_var.name\n                if pytensor.config.compute_test_value != "off":\n                    value_var.tag.test_value = rv_var.tag.test_value\n            else:\n                # Create value variable with the same type as the transformed RV\n                value_var = transform.forward(rv_var, *rv_var.owner.inputs).type()\n                value_var.name = f"{rv_var.name}_{transform.name}__"\n                value_var.tag.transform = transform\n                if pytensor.config.compute_test_value != "off":\n                    value_var.tag.test_value = transform.forward(\n                        rv_var, *rv_var.owner.inputs\n                    ).tag.test_value\n\n        self.rvs_to_transforms[rv_var] = transform\n        self.rvs_to_values[rv_var] = value_var\n        self.values_to_rvs[value_var] = rv_var\n\n        return value_var\n\n    def register_data_var(self, data, dims=None):\n        """Register a data variable with the model."""\n        self.data_vars.append(data)\n        self.add_named_variable(data, dims=dims)\n\n    def add_named_variable(self, var, dims: tuple[str | None, ...] | None = None):\n        """Add a random graph variable to the named variables of the model.\n\n        This can include several types of variables such basic_RVs, Data, Deterministics,\n        and Potentials.\n\n        Parameters\n        ----------\n        var\n\n        dims : tuple, optional\n\n        """\n        if var.name is None:\n            raise ValueError("Variable is unnamed.")\n        if self.named_vars.tree_contains(var.name):\n            raise ValueError(f"Variable name {var.name} already exists.")\n\n        if dims is not None:\n            if isinstance(dims, str):\n                dims = (dims,)\n            for dim in dims:\n                if dim not in self.coords and dim is not None:\n                    raise ValueError(f"Dimension {dim} is not specified in `coords`.")\n            if any(var.name == dim for dim in dims if dim is not None):\n                raise ValueError(f"Variable `{var.name}` has the same name as its dimension label.")\n            # This check implicitly states that only vars with .ndim attribute can have dims\n            if var.ndim != len(dims):\n                raise ValueError(\n                    f"{var} has {var.ndim} dims but {len(dims)} dim labels were provided."\n                )\n            self.named_vars_to_dims[var.name] = dims\n\n        self.named_vars[var.name] = var\n        if not hasattr(self, self.name_of(var.name)):\n            setattr(self, self.name_of(var.name), var)\n\n    @property\n    def prefix(self) -> str:\n        if self.isroot or not self.parent.prefix:\n            name = self.name\n        else:\n            name = f"{self.parent.prefix}::{self.name}"\n        return name\n\n    def name_for(self, name):\n        """Check if name has prefix and adds if needed."""\n        name = self._validate_name(name)\n        if self.prefix:\n            if not name.startswith(self.prefix + "::"):\n                return f"{self.prefix}::{name}"\n            else:\n                return name\n        else:\n            return name\n\n    def name_of(self, name):\n        """Check if name has prefix and deletes if needed."""\n        name = self._validate_name(name)\n        if not self.prefix or not name:\n            return name\n        elif name.startswith(self.prefix + "::"):\n            return name[len(self.prefix) + 2 :]\n        else:\n            return name\n\n    def __getitem__(self, key):\n        """Get the variable named `key`."""\n        try:\n            return self.named_vars[key]\n        except KeyError as e:\n            try:\n                return self.named_vars[self.name_for(key)]\n            except KeyError:\n                raise e\n\n    def __contains__(self, key):\n        """Check if the model contains a variable named `key`."""\n        return key in self.named_vars or self.name_for(key) in self.named_vars\n\n    def __copy__(self):\n        """Clone the model."""\n        return self.copy()\n\n    def __deepcopy__(self, _):\n        """Clone the model."""\n        return self.copy()\n\n    def copy(self):\n        """\n        Clone the model.\n\n        To access variables in the cloned model use `cloned_model["var_name"]`.\n\n        Examples\n        --------\n        .. code-block:: python\n\n            import pymc as pm\n            import copy\n\n            with pm.Model() as m:\n                p = pm.Beta("p", 1, 1)\n                x = pm.Bernoulli("x", p=p, shape=(3,))\n\n            clone_m = copy.copy(m)\n\n            # Access cloned variables by name\n            clone_x = clone_m["x"]\n\n            # z will be part of clone_m but not m\n            z = pm.Deterministic("z", clone_x + 1)\n        """\n        from pymc.model.fgraph import clone_model\n\n        return clone_model(self)\n\n    def replace_rvs_by_values(\n        self,\n        graphs: Sequence[TensorVariable],\n        **kwargs,\n    ) -> list[TensorVariable]:\n        """Clone and replace random variables in graphs with their value variables.\n\n        This will *not* recompute test values in the resulting graphs.\n\n        Parameters\n        ----------\n        graphs : array_like\n            The graphs in which to perform the replacements.\n\n        Returns\n        -------\n        array_like\n        """\n        return replace_rvs_by_values(\n            graphs,\n            rvs_to_values=self.rvs_to_values,\n            rvs_to_transforms=self.rvs_to_transforms,\n        )\n\n    @overload\n    def compile_fn(\n        self,\n        outs: Variable | Sequence[Variable],\n        *,\n        inputs: Sequence[Variable] | None = None,\n        mode=None,\n        point_fn: Literal[True] = True,\n        **kwargs,\n    ) -> PointFunc: ...\n\n    @overload\n    def compile_fn(\n        self,\n        outs: Variable | Sequence[Variable],\n        *,\n        inputs: Sequence[Variable] | None = None,\n        mode=None,\n        point_fn: Literal[False],\n        **kwargs,\n    ) -> Function: ...\n\n    def compile_fn(\n        self,\n        outs: Variable | Sequence[Variable],\n        *,\n        inputs: Sequence[Variable] | None = None,\n        mode=None,\n        point_fn: bool = True,\n        **kwargs,\n    ) -> PointFunc | Function:\n        """Compiles a PyTensor function.\n\n        Parameters\n        ----------\n        outs : Variable or sequence of Variables\n            PyTensor variable or iterable of PyTensor variables.\n        inputs : sequence of Variables, optional\n            PyTensor input variables, defaults to pytensorf.inputvars(outs).\n        mode\n            PyTensor compilation mode, default=None.\n        point_fn : bool\n            Whether to wrap the compiled function in a PointFunc, which takes a Point\n            dictionary with model variable names and values as input.\n        Other keyword arguments :\n            Any other keyword argument is sent to :py:func:`pymc.pytensorf.compile_pymc`.\n\n        Returns\n        -------\n        Compiled PyTensor function\n        """\n        if inputs is None:\n            inputs = inputvars(outs)\n\n        with self:\n            fn = compile(\n                inputs,\n                outs,\n                allow_input_downcast=True,\n                accept_inplace=True,\n                mode=mode,\n                **kwargs,\n            )\n\n        if point_fn:\n            return PointFunc(fn)\n        return fn\n\n    def profile(\n        self,\n        outs,\n        *,\n        n=1000,\n        point=None,\n        profile=True,\n        **compile_fn_kwargs,\n    ) -> ProfileStats:\n        """Compile and profile a PyTensor function which returns ``outs`` and takes values of model vars as a dict as an argument.\n\n        Parameters\n        ----------\n        outs : PyTensor variable or iterable of PyTensor variables\n        n : int, default 1000\n            Number of iterations to run\n        point : Point\n            Point to pass to the function\n        profile : True or ProfileStats\n        compile_fn_kwargs\n            Compilation kwargs for :func:`pymc.model.core.Model.compile_fn`\n\n        Returns\n        -------\n        pytensor.compile.profiling.ProfileStats\n            Use .summary() to print stats.\n        """\n        compile_fn_kwargs.setdefault("on_unused_input", "ignore")\n        f = self.compile_fn(\n            outs,\n            inputs=self.value_vars,\n            point_fn=False,\n            profile=profile,\n            **compile_fn_kwargs,\n        )\n        if point is None:\n            point = self.initial_point()\n\n        for _ in range(n):\n            f(**point)\n\n        return f.profile\n\n    def eval_rv_shapes(self) -> dict[str, tuple[int, ...]]:\n        """Evaluate shapes of untransformed AND transformed free variables.\n\n        Returns\n        -------\n        shapes : dict\n            Maps untransformed and transformed variable names to shape tuples.\n        """\n        names = []\n        outputs = []\n        for rv in self.free_RVs:\n            transform = self.rvs_to_transforms[rv]\n            if transform is not None:\n                names.append(get_transformed_name(rv.name, transform))\n                outputs.append(transform.forward(rv, *rv.owner.inputs).shape)\n            names.append(rv.name)\n            outputs.append(rv.shape)\n        f = pytensor.function(\n            inputs=[],\n            outputs=outputs,\n            givens=[(obs, self.rvs_to_values[obs]) for obs in self.observed_RVs],\n            mode=pytensor.compile.mode.FAST_COMPILE,\n            on_unused_input="ignore",\n        )\n        return {name: tuple(shape) for name, shape in zip(names, f())}\n\n    def check_start_vals(self, start, **kwargs):\n        r"""Check that the logp is defined and finite at the starting point.\n\n        Parameters\n        ----------\n        start : dict, or array of dict\n            Starting point in parameter space (or partial point)\n            Defaults to ``trace.point(-1))`` if there is a trace provided and\n            ``model.initial_point`` if not (defaults to empty dict). Initialization\n            methods for NUTS (see ``init`` keyword) can overwrite the default.\n        Other keyword arguments :\n            Any other keyword argument is sent to :py:meth:`~pymc.model.core.Model.point_logps`.\n\n        Raises\n        ------\n        ``KeyError`` if the parameters provided by `start` do not agree with the\n        parameters contained within the model.\n\n        ``pymc.exceptions.SamplingError`` if the evaluation of the parameters\n        in ``start`` leads to an invalid (i.e. non-finite) state\n\n        Returns\n        -------\n        None\n        """\n        start_points = [start] if isinstance(start, dict) else start\n\n        value_names_to_dtypes = {value.name: value.dtype for value in self.value_vars}\n        value_names_set = set(value_names_to_dtypes.keys())\n        for elem in start_points:\n            for k, v in elem.items():\n                elem[k] = np.asarray(v, dtype=value_names_to_dtypes[k])\n\n            if not set(elem.keys()).issubset(value_names_set):\n                extra_keys = ", ".join(set(elem.keys()) - value_names_set)\n                valid_keys = ", ".join(value_names_set)\n                raise KeyError(\n                    "Some start parameters do not appear in the model!\\n"\n                    f"Valid keys are: {valid_keys}, but {extra_keys} was supplied"\n                )\n\n            initial_eval = self.point_logps(point=elem, **kwargs)\n\n            if not all(np.isfinite(v) for v in initial_eval.values()):\n                raise SamplingError(\n                    "Initial evaluation of model at starting point failed!\\n"\n                    f"Starting values:\\n{elem}\\n\\n"\n                    f"Logp initial evaluation results:\\n{initial_eval}\\n"\n                    "You can call `model.debug()` for more details."\n                )\n\n    def point_logps(self, point=None, round_vals=2, **kwargs):\n        """Compute the log probability of `point` for all random variables in the model.\n\n        Parameters\n        ----------\n        point : Point, optional\n            Point to be evaluated.  If ``None``, then ``model.initial_point``\n            is used.\n        round_vals : int, default 2\n            Number of decimals to round log-probabilities.\n        Other keyword arguments :\n            Any other keyword argument are sent provided to :py:meth:`~pymc.model.core.Model.compile_fn`\n\n        Returns\n        -------\n        log_probability_of_point : dict\n            Log probability of `point`.\n        """\n        if point is None:\n            point = self.initial_point()\n\n        factors = self.basic_RVs + self.potentials\n        factor_logps_fn = [pt.sum(factor) for factor in self.logp(factors, sum=False)]\n        return {\n            factor.name: np.round(np.asarray(factor_logp), round_vals)\n            for factor, factor_logp in zip(\n                factors,\n                self.compile_fn(factor_logps_fn, **kwargs)(point),\n            )\n        }\n\n    def debug(\n        self,\n        point: dict[str, np.ndarray] | None = None,\n        fn: Literal["logp", "dlogp", "random"] = "logp",\n        verbose: bool = False,\n    ):\n        """Debug model function at point.\n\n        The method will evaluate the `fn` for each variable at a time.\n        When an evaluation fails or produces a non-finite value we print:\n         1. The graph of the parameters\n         2. The value of the parameters (if those can be evaluated)\n         3. The output of `fn` (if it can be evaluated)\n\n        This function should help to quickly narrow down invalid parametrizations.\n\n        Parameters\n        ----------\n        point : Point, optional\n            Point at which model function should be evaluated\n        fn : str, default "logp"\n            Function to be used for debugging. Can be one of [logp, dlogp, random].\n        verbose : bool, default False\n            Whether to show a more verbose PyTensor output when function cannot be evaluated\n        """\n        print_ = functools.partial(print, file=sys.stdout)\n\n        def first_line(exc):\n            return exc.args[0].split("\\n")[0]\n\n        def debug_parameters(rv):\n            if isinstance(rv.owner.op, RandomVariable):\n                inputs = rv.owner.op.dist_params(rv.owner)\n            else:\n                inputs = [inp for inp in rv.owner.inputs if not isinstance(inp.type, RandomType)]\n            rv_inputs = pytensor.function(\n                self.value_vars,\n                self.replace_rvs_by_values(inputs),\n                on_unused_input="ignore",\n                mode=get_mode(None).excluding("inplace", "fusion"),\n            )\n\n            print_(f"The variable {rv} has the following parameters:")\n            # done and used_ids are used to keep the same ids across distinct dprint calls\n            done = {}\n            used_ids = {}\n            for i, out in enumerate(rv_inputs.maker.fgraph.outputs):\n                print_(f"{i}: ", end="")\n                # Don\'t print useless deepcopys\n                if out.owner and isinstance(out.owner.op, DeepCopyOp):\n                    out = out.owner.inputs[0]\n                pytensor.dprint(out, print_type=True, done=done, used_ids=used_ids)\n\n            try:\n                print_("The parameters evaluate to:")\n                for i, rv_input_eval in enumerate(rv_inputs(**point)):\n                    print_(f"{i}: {rv_input_eval}")\n            except Exception as exc:\n                print_(\n                    f"The parameters of the variable {rv} cannot be evaluated: {first_line(exc)}"\n                )\n                if verbose:\n                    print_(exc, "\\n")\n\n        if fn not in ("logp", "dlogp", "random"):\n            raise ValueError(f"fn must be one of [logp, dlogp, random], got {fn}")\n\n        if point is None:\n            point = self.initial_point()\n        print_(f"point={point}\\n")\n\n        rvs_to_check = list(self.basic_RVs)\n        if fn in ("logp", "dlogp"):\n            rvs_to_check += [self.replace_rvs_by_values(p) for p in self.potentials]\n\n        found_problem = False\n        for rv in rvs_to_check:\n            if fn == "logp":\n                rv_fn = pytensor.function(\n                    self.value_vars, self.logp(vars=rv, sum=False)[0], on_unused_input="ignore"\n                )\n            elif fn == "dlogp":\n                rv_fn = pytensor.function(\n                    self.value_vars, self.dlogp(vars=rv), on_unused_input="ignore"\n                )\n            else:\n                [rv_inputs_replaced] = replace_rvs_by_values(\n                    [rv],\n                    # Don\'t include itself, or the function will just the the value variable\n                    rvs_to_values={\n                        rv_key: value\n                        for rv_key, value in self.rvs_to_values.items()\n                        if rv_key is not rv\n                    },\n                    rvs_to_transforms=self.rvs_to_transforms,\n                )\n                rv_fn = pytensor.function(\n                    self.value_vars, rv_inputs_replaced, on_unused_input="ignore"\n                )\n\n            try:\n                rv_fn_eval = rv_fn(**point)\n            except ParameterValueError as exc:\n                found_problem = True\n                debug_parameters(rv)\n                print_(\n                    f"This does not respect one of the following constraints: {first_line(exc)}\\n"\n                )\n                if verbose:\n                    print_(exc)\n            except Exception as exc:\n                found_problem = True\n                debug_parameters(rv)\n                print_(\n                    f"The variable {rv} {fn} method raised the following exception: {first_line(exc)}\\n"\n                )\n                if verbose:\n                    print_(exc)\n            else:\n                if not np.all(np.isfinite(rv_fn_eval)):\n                    found_problem = True\n                    debug_parameters(rv)\n                    if fn == "random" or rv is self.potentials:\n                        print_("This combination seems able to generate non-finite values")\n                    else:\n                        # Find which values are associated with non-finite evaluation\n                        values = self.rvs_to_values[rv]\n                        if rv in self.observed_RVs:\n                            values = values.eval()\n                        else:\n                            values = point[values.name]\n\n                        observed = " observed " if rv in self.observed_RVs else " "\n                        print_(\n                            f"Some of the{observed}values of variable {rv} are associated with a non-finite {fn}:"\n                        )\n                        mask = ~np.isfinite(rv_fn_eval)\n                        for value, fn_eval in zip(values[mask], rv_fn_eval[mask]):\n                            print_(f" value = {value} -> {fn} = {fn_eval}")\n                        print_()\n\n        if not found_problem:\n            print_("No problems found")\n        elif not verbose:\n            print_("You can set `verbose=True` for more details")\n\n    def to_graphviz(\n        self,\n        *,\n        var_names: Iterable[VarName] | None = None,\n        formatting: str = "plain",\n        save: str | None = None,\n        figsize: tuple[int, int] | None = None,\n        dpi: int = 300,\n    ):\n        """Produce a graphviz Digraph from a PyMC model.\n\n        Requires graphviz, which may be installed most easily with\n            conda install -c conda-forge python-graphviz\n\n        Alternatively, you may install the `graphviz` binaries yourself,\n        and then `pip install graphviz` to get the python bindings.  See\n        http://graphviz.readthedocs.io/en/stable/manual.html\n        for more information.\n\n        Parameters\n        ----------\n        var_names : iterable of variable names, optional\n            Subset of variables to be plotted that identify a subgraph with respect to the entire model graph\n        formatting : str, optional\n            one of { "plain" }\n        save : str, optional\n            If provided, an image of the graph will be saved to this location. The format is inferred from\n            the file extension.\n        figsize : tuple[int, int], optional\n            Width and height of the figure in inches. If not provided, uses the default figure size. It only affect\n            the size of the saved figure.\n        dpi : int, optional\n            Dots per inch. It only affects the resolution of the saved figure. The default is 300.\n\n        Examples\n        --------\n        How to plot the graph of the model.\n\n        .. code-block:: python\n\n            import numpy as np\n            from pymc import HalfCauchy, Model, Normal\n\n            J = 8\n            y = np.array([28, 8, -3, 7, -1, 1, 18, 12])\n            sigma = np.array([15, 10, 16, 11, 9, 11, 10, 18])\n\n            with Model() as schools:\n                eta = Normal("eta", 0, 1, shape=J)\n                mu = Normal("mu", 0, sigma=1e6)\n                tau = HalfCauchy("tau", 25)\n\n                theta = mu + tau * eta\n\n                obs = Normal("obs", theta, sigma=sigma, observed=y)\n\n            schools.to_graphviz()\n\n        Note that this code automatically plots the graph if executed in a Jupyter notebook.\n        If executed non-interactively, such as in a script or python console, the graph\n        needs to be rendered explicitly:\n\n        .. code-block:: python\n\n            # creates the file `schools.pdf`\n            schools.to_graphviz().render("schools")\n        """\n        return model_to_graphviz(\n            model=self,\n            var_names=var_names,\n            formatting=formatting,\n            save=save,\n            figsize=figsize,\n            dpi=dpi,\n        )\n\n\nclass BlockModelAccess(Model):\n    """Can be used to prevent user access to Model contexts."""\n\n    def __init__(self, *args, error_msg_on_access="Model access is blocked", **kwargs):\n        self.error_msg_on_access = error_msg_on_access\n\n\ndef new_or_existing_block_model_access(*args, **kwargs):\n    """Return a BlockModelAccess in the stack or create a new one if none is found."""\n    model = Model.get_context(error_if_none=False, allow_block_model_access=True)\n    if isinstance(model, BlockModelAccess):\n        return model\n    return BlockModelAccess(*args, **kwargs)\n\n\ndef set_data(new_data, model=None, *, coords=None):\n    """Set the value of one or more data container variables.\n\n    Note that the shape is also dynamic, it is updated when the value is\n    changed.  See the examples below for two common use-cases that take\n    advantage of this behavior.\n\n    Parameters\n    ----------\n    new_data: dict\n        New values for the data containers. The keys of the dictionary are\n        the variables\' names in the model and the values are the objects\n        with which to update.\n    model: Model (optional if in `with` context)\n\n    Examples\n    --------\n    This example shows how to change the shape of the likelihood to correspond automatically with\n    `x`, the predictor in a regression model.\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            x = pm.Data("x", [1.0, 2.0, 3.0])\n            y = pm.Data("y", [1.0, 2.0, 3.0])\n            beta = pm.Normal("beta", 0, 1)\n            obs = pm.Normal("obs", x * beta, 1, observed=y, shape=x.shape)\n            idata = pm.sample()\n\n    Then change the value of `x` to predict on new data.\n\n    .. code-block:: python\n\n        with model:\n            pm.set_data({\'x\': [5., 6., 9., 12., 15.]})\n            y_test = pm.sample_posterior_predictive(idata)\n\n        print(y_test.posterior_predictive[\'obs\'].mean((\'chain\', \'draw\')))\n\n        >>> array([4.6088569 , 5.54128318, 8.32953844, 11.14044852, 13.94178173])\n\n    This example shows how to reuse the same model without recompiling on a new data set.  The\n    shape of the likelihood, `obs`, automatically tracks the shape of the observed data, `y`.\n\n    .. code-block:: python\n\n        import numpy as np\n        import pymc as pm\n\n        rng = np.random.default_rng()\n        data = rng.normal(loc=1.0, scale=2.0, size=100)\n\n        with pm.Model() as model:\n            y = pm.Data("y", data)\n            theta = pm.Normal("theta", mu=0.0, sigma=10.0)\n            obs = pm.Normal("obs", theta, 2.0, observed=y, shape=y.shape)\n            idata = pm.sample()\n\n    Now update the model with a new data set.\n\n    .. code-block:: python\n\n        with model:\n            pm.set_data({"y": rng.normal(loc=1.0, scale=2.0, size=200)})\n            idata = pm.sample()\n    """\n    model = modelcontext(model)\n\n    for variable_name, new_value in new_data.items():\n        model.set_data(variable_name, new_value, coords=coords)\n\n\ndef compile_fn(\n    outs: Variable | Sequence[Variable],\n    *,\n    inputs: Sequence[Variable] | None = None,\n    mode=None,\n    point_fn: bool = True,\n    model: Model | None = None,\n    **kwargs,\n) -> PointFunc | Function:\n    """Compiles a PyTensor function.\n\n    Parameters\n    ----------\n    outs\n        PyTensor variable or iterable of PyTensor variables.\n    inputs\n        PyTensor input variables, defaults to pytensorf.inputvars(outs).\n    mode\n        PyTensor compilation mode, default=None.\n    point_fn : bool\n        Whether to wrap the compiled function in a PointFunc, which takes a Point\n        dictionary with model variable names and values as input.\n    model : Model, optional\n        Current model on stack.\n\n    Returns\n    -------\n    Compiled PyTensor function\n    """\n    model = modelcontext(model)\n    return model.compile_fn(\n        outs,\n        inputs=inputs,\n        mode=mode,\n        point_fn=point_fn,\n        **kwargs,\n    )\n\n\ndef Point(*args, filter_model_vars=False, **kwargs) -> dict[VarName, np.ndarray]:\n    """Build a point.\n\n    Uses same args as dict() does.\n    Filters out variables not in the model. All keys are strings.\n\n    Parameters\n    ----------\n    args, kwargs\n        arguments to build a dict\n    filter_model_vars : bool\n        If `True`, only model variables are included in the result.\n    """\n    model = modelcontext(kwargs.pop("model", None))\n    args = list(args)\n    try:\n        d = dict(*args, **kwargs)\n    except Exception as e:\n        raise TypeError(f"can\'t turn {args} and {kwargs} into a dict. {e}")\n    return {\n        get_var_name(k): np.array(v)\n        for k, v in d.items()\n        if not filter_model_vars or (get_var_name(k) in map(get_var_name, model.value_vars))\n    }\n\n\ndef Deterministic(name, var, model=None, dims=None):\n    """Create a named deterministic variable.\n\n    Deterministic nodes are only deterministic given all of their inputs, i.e.\n    they don\'t add randomness to the model.  They are generally used to record\n    an intermediary result.\n\n    Parameters\n    ----------\n    name : str\n        Name of the deterministic variable to be registered in the model.\n    var : tensor_like\n        Expression for the calculation of the variable.\n    model : Model, optional\n        The model object to which the Deterministic variable is added.\n        If ``None`` is provided, the current model in the context stack is used.\n    dims : str or tuple of str, optional\n        Dimension names for the variable.\n\n    Returns\n    -------\n    var : tensor_like\n        The registered, named variable wrapped in Deterministic.\n\n    Examples\n    --------\n    Indeed, PyMC allows for arbitrary combinations of random variables, for\n    example in the case of a logistic regression\n\n    .. code:: python\n\n        with pm.Model():\n            alpha = pm.Normal("alpha", 0, 1)\n            intercept = pm.Normal("intercept", 0, 1)\n            p = pm.math.invlogit(alpha * x + intercept)\n            outcome = pm.Bernoulli("outcome", p, observed=outcomes)\n\n\n    but doesn\'t memorize the fact that the expression ``pm.math.invlogit(alpha *\n    x + intercept)`` has been affected to the variable ``p``.  If the quantity\n    ``p`` is important and one would like to track its value in the sampling\n    trace, then one can use a deterministic node:\n\n    .. code:: python\n\n        with pm.Model():\n            alpha = pm.Normal("alpha", 0, 1)\n            intercept = pm.Normal("intercept", 0, 1)\n            p = pm.Deterministic("p", pm.math.invlogit(alpha * x + intercept))\n            outcome = pm.Bernoulli("outcome", p, observed=outcomes)\n\n    These two models are strictly equivalent from a mathematical point of view.\n    However, in the first case, the inference data will only contain values for\n    the variables ``alpha``, ``intercept`` and ``outcome``.  In the second, it\n    will also contain sampled values of ``p`` for each of the observed points.\n\n    Notes\n    -----\n    Even though adding a Deterministic node forces PyMC to compute this\n    expression, which could have been optimized away otherwise, this doesn\'t come\n    with a performance cost.  Indeed, Deterministic nodes are computed outside\n    the main computation graph, which can be optimized as though there was no\n    Deterministic nodes.  Whereas the optimized graph can be evaluated thousands\n    of times during a NUTS step, the Deterministic quantities are just\n    computeed once at the end of the step, with the final values of the other\n    random variables.\n    """\n    model = modelcontext(model)\n    var = var.copy(model.name_for(name))\n    model.deterministics.append(var)\n    model.add_named_variable(var, dims)\n\n    from pymc.printing import str_for_potential_or_deterministic\n\n    var.str_repr = types.MethodType(\n        functools.partial(str_for_potential_or_deterministic, dist_name="Deterministic"), var\n    )\n    var._repr_latex_ = types.MethodType(\n        functools.partial(\n            str_for_potential_or_deterministic, dist_name="Deterministic", formatting="latex"\n        ),\n        var,\n    )\n\n    return var\n\n\ndef Potential(name, var: TensorVariable, model=None, dims=None) -> TensorVariable:\n    """Add an arbitrary term to the model log-probability.\n\n    Warnings\n    --------\n    Potential terms only influence probability-based sampling, such as ``pm.sample``, but not forward sampling like\n    ``pm.sample_prior_predictive`` or ``pm.sample_posterior_predictive``. A warning is raised when doing forward\n    sampling with models containing Potential terms.\n\n    Parameters\n    ----------\n    name : str\n        Name of the potential variable to be registered in the model.\n    var : tensor_like\n        Expression to be added to the model joint logp.\n    model : Model, optional\n        The model object to which the potential function is added.\n        If ``None`` is provided, the current model in the context stack is used.\n    dims : str or tuple of str, optional\n        Dimension names for the variable.\n\n    Returns\n    -------\n    var : tensor_like\n        The registered, named model variable.\n\n    Examples\n    --------\n    In this example, we define a constraint on ``x`` to be greater or equal to 0.\n    The statement ``pm.math.log(pm.math.switch(constraint, 0, 1))`` adds either 0 or -inf to the model logp,\n    depending on whether the constraint is met. During sampling, any proposals where ``x`` is negative will be rejected.\n\n    .. code:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            x = pm.Normal("x", mu=0, sigma=1)\n\n            constraint = x >= 0\n            potential = pm.Potential("x_constraint", pm.math.log(pm.math.switch(constraint, 1, 0)))\n\n\n    Instead, with a soft constraint like ``pm.math.log(pm.math.switch(constraint, 1, 0.5))``,\n    the sampler will be less likely, but not forbidden, from accepting negative values for `x`.\n\n    .. code:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            x = pm.Normal("x", mu=0, sigma=1)\n\n            constraint = x >= 0\n            potential = pm.Potential("x_constraint", pm.math.log(pm.math.switch(constraint, 1.0, 0.5)))\n\n    A Potential term can depend on multiple variables.\n    In the following example, the ``soft_sum_constraint`` potential encourages ``x`` and ``y`` to have a small sum.\n    The more the sum deviates from zero, the more negative the penalty value of ``(-((x + y)**2))``.\n\n    .. code:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            x = pm.Normal("x", mu=0, sigma=10)\n            y = pm.Normal("y", mu=0, sigma=10)\n            soft_sum_constraint = pm.Potential("soft_sum_constraint", -((x + y)**2))\n\n    A Potential can be used to define a specific prior term.\n    The following example imposes a power law prior on `max_items`, under the form ``log(1/max_items)``,\n    which penalizes very large values of `max_items`.\n\n    .. code:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            # p(max_items) = 1 / max_items\n            max_items = pm.Uniform("max_items", lower=1, upper=100)\n            pm.Potential("power_prior", pm.math.log(1/max_items))\n\n            n_items = pm.Uniform("n_items", lower=1, upper=max_items, observed=60)\n\n    A Potential can be used to define a specific likelihood term.\n    In the following example, a normal likelihood term is added to fixed data.\n    The same result would be obtained by using an observed `Normal` variable.\n\n    .. code:: python\n\n        import pymc as pm\n\n        def normal_logp(value, mu, sigma):\n            return -0.5 * ((value - mu) / sigma) ** 2 - pm.math.log(sigma)\n\n        with pm.Model() as model:\n            mu = pm.Normal("x")\n            sigma = pm.HalfNormal("sigma")\n\n            data = [0.1, 0.5, 0.9]\n            llike = pm.Potential("llike", normal_logp(data, mu, sigma))\n\n\n    """\n    model = modelcontext(model)\n    var.name = model.name_for(name)\n    model.potentials.append(var)\n    model.add_named_variable(var, dims)\n\n    from pymc.printing import str_for_potential_or_deterministic\n\n    var.str_repr = types.MethodType(\n        functools.partial(str_for_potential_or_deterministic, dist_name="Potential"), var\n    )\n    var._repr_latex_ = types.MethodType(\n        functools.partial(\n            str_for_potential_or_deterministic, dist_name="Potential", formatting="latex"\n        ),\n        var,\n    )\n\n    return var\n',
            'pymc/model_graph.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport warnings\n\nfrom collections import defaultdict\nfrom collections.abc import Callable, Iterable\nfrom dataclasses import dataclass\nfrom enum import Enum\nfrom os import path\nfrom typing import Any, cast\n\nfrom pytensor import function\nfrom pytensor.graph import Apply\nfrom pytensor.graph.basic import ancestors, walk\nfrom pytensor.scalar.basic import Cast\nfrom pytensor.tensor.elemwise import Elemwise\nfrom pytensor.tensor.random.op import RandomVariable\nfrom pytensor.tensor.shape import Shape\nfrom pytensor.tensor.variable import TensorVariable\n\nimport pymc as pm\n\nfrom pymc.util import VarName, get_default_varnames, get_var_name\n\n__all__ = (\n    "ModelGraph",\n    "model_to_graphviz",\n    "model_to_networkx",\n)\n\n\n@dataclass\nclass DimInfo:\n    names: tuple[str | None, ...]\n    lengths: tuple[int, ...]\n\n    def __post_init__(self) -> None:\n        if len(self.names) != len(self.lengths):\n            raise ValueError("The number of names and lengths must be equal.")\n\n    def __hash__(self):\n        return hash((self.names, self.lengths))\n\n    def __bool__(self) -> bool:\n        return len(self.lengths) > 0 or len(self.names) > 0\n\n\nPlateLabelFunc = Callable[[DimInfo], str]\n\n\ndef create_plate_label_without_dim_length(\n    dim_info: DimInfo,\n) -> str:\n    return " x ".join(\n        f"{dname}" if dname else f"{dlen}"\n        for (dname, dlen) in zip(dim_info.names, dim_info.lengths)\n    )\n\n\ndef create_plate_label_with_dim_length(\n    dim_info: DimInfo,\n) -> str:\n    return " x ".join(\n        f"{dname} ({dlen})" if dname else f"{dlen}"\n        for (dname, dlen) in zip(dim_info.names, dim_info.lengths)\n    )\n\n\ndef fast_eval(var):\n    return function([], var, mode="FAST_COMPILE")()\n\n\nclass NodeType(str, Enum):\n    """Enum for the types of nodes in the graph."""\n\n    POTENTIAL = "Potential"\n    FREE_RV = "Free Random Variable"\n    OBSERVED_RV = "Observed Random Variable"\n    DETERMINISTIC = "Deterministic"\n    DATA = "Data"\n\n\n@dataclass\nclass NodeInfo:\n    var: TensorVariable\n    node_type: NodeType\n\n    def __hash__(self):\n        return hash(self.var.name)\n\n\n@dataclass\nclass Plate:\n    dim_info: DimInfo\n    variables: list[NodeInfo]\n\n    def __eq__(self, other) -> bool:\n        if not isinstance(other, Plate):\n            return False\n\n        return self.dim_info == other.dim_info and set(self.variables) == set(other.variables)\n\n\nGraphvizNodeKwargs = dict[str, Any]\nNodeFormatter = Callable[[TensorVariable], GraphvizNodeKwargs]\n\n\ndef default_potential(var: TensorVariable) -> GraphvizNodeKwargs:\n    """Return default data for potential in the graph."""\n    return {\n        "shape": "octagon",\n        "style": "filled",\n        "label": f"{var.name}\\n~\\nPotential",\n    }\n\n\ndef random_variable_symbol(var: TensorVariable) -> str:\n    """Get the symbol of the random variable."""\n    symbol = var.owner.op.__class__.__name__\n\n    if symbol.endswith("RV"):\n        symbol = symbol[:-2]\n\n    return symbol\n\n\ndef default_free_rv(var: TensorVariable) -> GraphvizNodeKwargs:\n    """Return default data for free RV in the graph."""\n    symbol = random_variable_symbol(var)\n\n    return {\n        "shape": "ellipse",\n        "style": None,\n        "label": f"{var.name}\\n~\\n{symbol}",\n    }\n\n\ndef default_observed_rv(var: TensorVariable) -> GraphvizNodeKwargs:\n    """Return default data for observed RV in the graph."""\n    symbol = random_variable_symbol(var)\n\n    return {\n        "shape": "ellipse",\n        "style": "filled",\n        "label": f"{var.name}\\n~\\n{symbol}",\n    }\n\n\ndef default_deterministic(var: TensorVariable) -> GraphvizNodeKwargs:\n    """Return default data for the deterministic in the graph."""\n    return {\n        "shape": "box",\n        "style": None,\n        "label": f"{var.name}\\n~\\nDeterministic",\n    }\n\n\ndef default_data(var: TensorVariable) -> GraphvizNodeKwargs:\n    """Return default data for the data in the graph."""\n    return {\n        "shape": "box",\n        "style": "rounded, filled",\n        "label": f"{var.name}\\n~\\nData",\n    }\n\n\ndef get_node_type(var_name: VarName, model) -> NodeType:\n    """Return the node type of the variable in the model."""\n    v = model[var_name]\n\n    if v in model.deterministics:\n        return NodeType.DETERMINISTIC\n    elif v in model.free_RVs:\n        return NodeType.FREE_RV\n    elif v in model.observed_RVs:\n        return NodeType.OBSERVED_RV\n    elif v in model.data_vars:\n        return NodeType.DATA\n    else:\n        return NodeType.POTENTIAL\n\n\nNodeTypeFormatterMapping = dict[NodeType, NodeFormatter]\n\nDEFAULT_NODE_FORMATTERS: NodeTypeFormatterMapping = {\n    NodeType.POTENTIAL: default_potential,\n    NodeType.FREE_RV: default_free_rv,\n    NodeType.OBSERVED_RV: default_observed_rv,\n    NodeType.DETERMINISTIC: default_deterministic,\n    NodeType.DATA: default_data,\n}\n\n\ndef update_node_formatters(node_formatters: NodeTypeFormatterMapping) -> NodeTypeFormatterMapping:\n    node_formatters = {**DEFAULT_NODE_FORMATTERS, **node_formatters}\n\n    unknown_keys = set(node_formatters.keys()) - set(NodeType)\n    if unknown_keys:\n        raise ValueError(\n            f"Node formatters must be of type NodeType. Found: {list(unknown_keys)}."\n            f" Please use one of {[node_type.value for node_type in NodeType]}."\n        )\n\n    return node_formatters\n\n\nAddNode = Callable[[str, GraphvizNodeKwargs], None]\n\n\ndef _make_node(\n    node: NodeInfo,\n    *,\n    node_formatters: NodeTypeFormatterMapping,\n    add_node: AddNode,\n    cluster: str | None = None,\n    formatting: str = "plain",\n):\n    """Attaches the given variable to a graphviz or networkx Digraph."""\n    node_formatter = node_formatters[node.node_type]\n    kwargs = node_formatter(node.var)\n\n    if cluster is not None:\n        kwargs["cluster"] = cluster\n\n    var_name: str = cast(str, node.var.name)\n    add_node(var_name.replace(":", "&"), **kwargs)  # type: ignore[call-arg]\n\n\nclass ModelGraph:\n    def __init__(self, model):\n        self.model = model\n        self._all_var_names = get_default_varnames(self.model.named_vars, include_transformed=False)\n        self.var_list = self.model.named_vars.values()\n\n    def get_parent_names(self, var: TensorVariable) -> set[VarName]:\n        if var.owner is None or var.owner.inputs is None:\n            return set()\n\n        def _filter_non_parameter_inputs(var):\n            node = var.owner\n            if isinstance(node.op, Shape):\n                # Don\'t show shape-related dependencies\n                return []\n            if isinstance(node.op, RandomVariable):\n                # Filter out rng and size parameters or RandomVariable nodes\n                return node.op.dist_params(node)\n            else:\n                # Otherwise return all inputs\n                return node.inputs\n\n        blockers = set(self.model.named_vars)\n\n        def _expand(x):\n            nonlocal blockers\n            if x.name in blockers:\n                return [x]\n            if isinstance(x.owner, Apply):\n                return reversed(_filter_non_parameter_inputs(x))\n            return []\n\n        parents = set()\n        for x in walk(nodes=_filter_non_parameter_inputs(var), expand=_expand):\n            # Only consider nodes that are in the named model variables.\n            vname = getattr(x, "name", None)\n            if isinstance(vname, str) and vname in self._all_var_names:\n                parents.add(VarName(vname))\n\n        return parents\n\n    def vars_to_plot(self, var_names: Iterable[VarName] | None = None) -> list[VarName]:\n        if var_names is None:\n            return self._all_var_names\n\n        selected_names = set(var_names)\n\n        # .copy() because sets cannot change in size during iteration\n        for var_name in selected_names.copy():\n            if var_name not in self._all_var_names:\n                raise ValueError(f"{var_name} is not in this model.")\n\n            for model_var in self.var_list:\n                if model_var in self.model.observed_RVs:\n                    if self.model.rvs_to_values[model_var] == self.model[var_name]:\n                        selected_names.add(model_var.name)\n\n        selected_ancestors = set(\n            filter(\n                lambda rv: rv.name in self._all_var_names,\n                list(ancestors([self.model[var_name] for var_name in selected_names])),\n            )\n        )\n\n        for var in selected_ancestors.copy():\n            if var in self.model.observed_RVs:\n                selected_ancestors.add(self.model.rvs_to_values[var])\n\n        # ordering of self._all_var_names is important\n        return [get_var_name(var) for var in selected_ancestors]\n\n    def make_compute_graph(\n        self, var_names: Iterable[VarName] | None = None\n    ) -> dict[VarName, set[VarName]]:\n        """Get map of var_name -> set(input var names) for the model."""\n        input_map: dict[VarName, set[VarName]] = defaultdict(set)\n\n        for var_name in self.vars_to_plot(var_names):\n            var = self.model[var_name]\n            parent_name = self.get_parent_names(var)\n            input_map[var_name] = input_map[var_name].union(parent_name)\n\n            if var in self.model.observed_RVs:\n                obs_node = self.model.rvs_to_values[var]\n\n                # loop created so that the elif block can go through this again\n                # and remove any intermediate ops, notably dtype casting, to observations\n                while True:\n                    obs_name = obs_node.name\n                    if obs_name and obs_name != var_name:\n                        input_map[var_name] = input_map[var_name].difference({obs_name})\n                        input_map[obs_name] = input_map[obs_name].union({var_name})\n                        break\n                    elif (\n                        # for cases where observations are cast to a certain dtype\n                        # see issue 5795: https://github.com/pymc-devs/pymc/issues/5795\n                        obs_node.owner\n                        and isinstance(obs_node.owner.op, Elemwise)\n                        and isinstance(obs_node.owner.op.scalar_op, Cast)\n                    ):\n                        # we can retrieve the observation node by going up the graph\n                        obs_node = obs_node.owner.inputs[0]\n                    else:\n                        break\n\n        return input_map\n\n    def get_plates(\n        self,\n        var_names: Iterable[VarName] | None = None,\n    ) -> list[Plate]:\n        """Rough but surprisingly accurate plate detection.\n\n        Just groups by the shape of the underlying distribution.  Will be wrong\n        if there are two plates with the same shape.\n\n        Returns\n        -------\n        dict\n            Maps plate labels to the set of ``VarName``s inside the plate.\n        """\n        plates = defaultdict(set)\n\n        # TODO: Evaluate all RV shapes at once\n        #       This should help find discrepencies, and\n        #       avoids unnecessary function compiles for determining labels.\n        dim_lengths: dict[str, int] = {\n            dim_name: fast_eval(value).item() for dim_name, value in self.model.dim_lengths.items()\n        }\n        var_shapes: dict[str, tuple[int, ...]] = {\n            var_name: tuple(fast_eval(self.model[var_name].shape))\n            for var_name in self.vars_to_plot(var_names)\n        }\n\n        for var_name in self.vars_to_plot(var_names):\n            shape: tuple[int, ...] = var_shapes[var_name]\n            if var_name in self.model.named_vars_to_dims:\n                # The RV is associated with `dims` information.\n                names = []\n                lengths = []\n                for d, dname in enumerate(self.model.named_vars_to_dims[var_name]):\n                    names.append(dname)\n                    lengths.append(dim_lengths.get(dname, shape[d]))\n\n                dim_info = DimInfo(\n                    names=tuple(names),\n                    lengths=tuple(lengths),\n                )\n            else:\n                # The RV has no `dims` information.\n                dim_size = len(shape)\n                dim_info = DimInfo(\n                    names=tuple([None] * dim_size),\n                    lengths=tuple(shape),\n                )\n\n            v = self.model[var_name]\n            node_type = get_node_type(var_name, self.model)\n            var = NodeInfo(var=v, node_type=node_type)\n            plates[dim_info].add(var)\n\n        return [\n            Plate(\n                dim_info=dim_info,\n                variables=list(variables),\n            )\n            for dim_info, variables in plates.items()\n        ]\n\n    def edges(\n        self,\n        var_names: Iterable[VarName] | None = None,\n    ) -> list[tuple[VarName, VarName]]:\n        """Get edges between the variables in the model.\n\n        Parameters\n        ----------\n        var_names : iterable of str, optional\n            Subset of variables to be plotted that identify a subgraph with respect to the entire model graph\n\n        Returns\n        -------\n        list of tuple\n            List of edges between the variables in the model.\n\n        """\n        return [\n            (VarName(child.replace(":", "&")), VarName(parent.replace(":", "&")))\n            for child, parents in self.make_compute_graph(var_names=var_names).items()\n            for parent in parents\n        ]\n\n    def nodes(self, plates: list[Plate] | None = None) -> list[NodeInfo]:\n        """Get all nodes in the model graph."""\n        plates = plates or self.get_plates()\n        nodes = []\n        for plate in plates:\n            nodes.extend(plate.variables)\n        return nodes\n\n\ndef make_graph(\n    name: str,\n    plates: list[Plate],\n    edges: list[tuple[VarName, VarName]],\n    formatting: str = "plain",\n    save=None,\n    figsize=None,\n    dpi=300,\n    node_formatters: NodeTypeFormatterMapping | None = None,\n    graph_attr: dict[str, Any] | None = None,\n    create_plate_label: PlateLabelFunc = create_plate_label_with_dim_length,\n):\n    """Make graphviz Digraph of PyMC model.\n\n    Returns\n    -------\n    graphviz.Digraph\n    """\n    try:\n        import graphviz\n    except ImportError:\n        raise ImportError(\n            "This function requires the python library graphviz, along with binaries. "\n            "The easiest way to install all of this is by running\\n\\n"\n            "\\tconda install -c conda-forge python-graphviz"\n        )\n\n    node_formatters = node_formatters or {}\n    node_formatters = update_node_formatters(node_formatters)\n\n    graph = graphviz.Digraph(name, graph_attr=graph_attr)\n    for plate in plates:\n        if plate.dim_info:\n            # must be preceded by \'cluster\' to get a box around it\n            plate_label = create_plate_label(plate.dim_info)\n            plate_name = f"cluster{plate_label}"\n\n            with graph.subgraph(name=plate_name) as sub:\n                for var in plate.variables:\n                    _make_node(\n                        node=var,\n                        formatting=formatting,\n                        node_formatters=node_formatters,\n                        add_node=sub.node,\n                    )\n                # plate label goes bottom right\n                sub.attr(label=plate_label, labeljust="r", labelloc="b", style="rounded")\n        else:\n            for var in plate.variables:\n                _make_node(\n                    node=var,\n                    formatting=formatting,\n                    node_formatters=node_formatters,\n                    add_node=graph.node,\n                )\n\n    for child, parent in edges:\n        graph.edge(parent, child)\n\n    if save is not None:\n        width, height = (None, None) if figsize is None else figsize\n        base, ext = path.splitext(save)\n        if ext:\n            ext = ext.replace(".", "")\n        else:\n            ext = "png"\n        graph_c = graph.copy()\n        graph_c.graph_attr.update(size=f"{width},{height}!")\n        graph_c.graph_attr.update(dpi=str(dpi))\n        graph_c.render(filename=base, format=ext, cleanup=True)\n\n    return graph\n\n\ndef make_networkx(\n    name: str,\n    plates: list[Plate],\n    edges: list[tuple[VarName, VarName]],\n    formatting: str = "plain",\n    node_formatters: NodeTypeFormatterMapping | None = None,\n    create_plate_label: PlateLabelFunc = create_plate_label_with_dim_length,\n):\n    """Make networkx Digraph of PyMC model.\n\n    Returns\n    -------\n    networkx.Digraph\n    """\n    try:\n        import networkx\n    except ImportError:\n        raise ImportError(\n            "This function requires the python library networkx, along with binaries. "\n            "The easiest way to install all of this is by running\\n\\n"\n            "\\tconda install networkx"\n        )\n\n    node_formatters = node_formatters or {}\n    node_formatters = update_node_formatters(node_formatters)\n\n    graphnetwork = networkx.DiGraph(name=name)\n    for plate in plates:\n        if plate.dim_info:\n            # # must be preceded by \'cluster\' to get a box around it\n\n            plate_label = create_plate_label(plate.dim_info)\n            plate_name = f"cluster{plate_label}"\n            subgraphnetwork = networkx.DiGraph(name=plate_name, label=plate_label)\n\n            for var in plate.variables:\n                _make_node(\n                    node=var,\n                    node_formatters=node_formatters,\n                    cluster=plate_name,\n                    formatting=formatting,\n                    add_node=subgraphnetwork.add_node,\n                )\n            for sgn in subgraphnetwork.nodes:\n                networkx.set_node_attributes(\n                    subgraphnetwork,\n                    {sgn: {"labeljust": "r", "labelloc": "b", "style": "rounded"}},\n                )\n            node_data = {\n                e[0]: e[1] for e in graphnetwork.nodes(data=True) & subgraphnetwork.nodes(data=True)\n            }\n\n            graphnetwork = networkx.compose(graphnetwork, subgraphnetwork)\n            networkx.set_node_attributes(graphnetwork, node_data)\n            graphnetwork.graph["name"] = name\n        else:\n            for var in plate.variables:\n                _make_node(\n                    node=var,\n                    formatting=formatting,\n                    node_formatters=node_formatters,\n                    add_node=graphnetwork.add_node,\n                )\n\n    for child, parents in edges:\n        graphnetwork.add_edge(parents, child)\n\n    return graphnetwork\n\n\ndef model_to_networkx(\n    model=None,\n    *,\n    var_names: Iterable[VarName] | None = None,\n    formatting: str = "plain",\n    node_formatters: NodeTypeFormatterMapping | None = None,\n    include_dim_lengths: bool = True,\n):\n    """Produce a networkx Digraph from a PyMC model.\n\n    Requires networkx, which may be installed most easily with::\n\n        conda install networkx\n\n    Alternatively, you may install using pip with::\n\n        pip install networkx\n\n    See https://networkx.org/documentation/stable/ for more information.\n\n    Parameters\n    ----------\n    model : Model\n        The model to plot. Not required when called from inside a modelcontext.\n    var_names : iterable of str, optional\n        Subset of variables to be plotted that identify a subgraph with respect to the entire model graph\n    formatting : str, optional\n        one of { "plain" }\n    node_formatters : dict, optional\n        A dictionary mapping node types to functions that return a dictionary of node attributes.\n        Check out the networkx documentation for more information\n        how attributes are added to nodes: https://networkx.org/documentation/stable/reference/classes/generated/networkx.Graph.add_node.html\n    include_dim_lengths : bool\n        Include the dim length in the plate label. Default is True.\n\n    Examples\n    --------\n    How to plot the graph of the model.\n\n    .. code-block:: python\n\n        import numpy as np\n        from pymc import HalfCauchy, Model, Normal, model_to_networkx\n\n        J = 8\n        y = np.array([28, 8, -3, 7, -1, 1, 18, 12])\n        sigma = np.array([15, 10, 16, 11, 9, 11, 10, 18])\n\n        with Model() as schools:\n            eta = Normal("eta", 0, 1, shape=J)\n            mu = Normal("mu", 0, sigma=1e6)\n            tau = HalfCauchy("tau", 25)\n\n            theta = mu + tau * eta\n\n            obs = Normal("obs", theta, sigma=sigma, observed=y)\n\n        model_to_networkx(schools)\n\n    Add custom attributes to Free Random Variables and Observed Random Variables nodes.\n\n    .. code-block:: python\n\n        node_formatters = {\n            "Free Random Variable": lambda var: {"shape": "circle", "label": var.name},\n            "Observed Random Variable": lambda var: {"shape": "square", "label": var.name},\n        }\n        model_to_networkx(schools, node_formatters=node_formatters)\n\n    """\n    if "plain" not in formatting:\n        raise ValueError(f"Unsupported formatting for graph nodes: \'{formatting}\'. See docstring.")\n\n    if formatting != "plain":\n        warnings.warn(\n            "Formattings other than \'plain\' are currently not supported.",\n            UserWarning,\n            stacklevel=2,\n        )\n\n    model = pm.modelcontext(model)\n    graph = ModelGraph(model)\n    return make_networkx(\n        name=model.name,\n        plates=graph.get_plates(var_names=var_names),\n        edges=graph.edges(var_names=var_names),\n        formatting=formatting,\n        node_formatters=node_formatters,\n        create_plate_label=create_plate_label_with_dim_length\n        if include_dim_lengths\n        else create_plate_label_without_dim_length,\n    )\n\n\ndef model_to_graphviz(\n    model=None,\n    *,\n    var_names: Iterable[VarName] | None = None,\n    formatting: str = "plain",\n    save: str | None = None,\n    figsize: tuple[int, int] | None = None,\n    dpi: int = 300,\n    node_formatters: NodeTypeFormatterMapping | None = None,\n    graph_attr: dict[str, Any] | None = None,\n    include_dim_lengths: bool = True,\n):\n    """Produce a graphviz Digraph from a PyMC model.\n\n    Requires graphviz, which may be installed most easily with\n        conda install -c conda-forge python-graphviz\n\n    Alternatively, you may install the `graphviz` binaries yourself,\n    and then `pip install graphviz` to get the python bindings.  See\n    http://graphviz.readthedocs.io/en/stable/manual.html\n    for more information.\n\n    Parameters\n    ----------\n    model : pm.Model\n        The model to plot. Not required when called from inside a modelcontext.\n    var_names : iterable of variable names, optional\n        Subset of variables to be plotted that identify a subgraph with respect to the entire model graph\n    formatting : str, optional\n        one of { "plain" }\n    save : str, optional\n        If provided, an image of the graph will be saved to this location. The format is inferred from\n        the file extension.\n    figsize : tuple[int, int], optional\n        Width and height of the figure in inches. If not provided, uses the default figure size. It only affect\n        the size of the saved figure.\n    dpi : int, optional\n        Dots per inch. It only affects the resolution of the saved figure. The default is 300.\n    graph_attr : dict, optional\n        A dictionary of top-level layout attributes for graphviz\n        Check out graphviz documentation for more information on available attributes\n        https://graphviz.org/doc/info/attrs.html\n    node_formatters : dict, optional\n        A dictionary mapping node types to functions that return a dictionary of node attributes.\n        Check out graphviz documentation for more information on available\n        attributes. https://graphviz.org/docs/nodes/\n    include_dim_lengths : bool\n        Include the dim lengths in the plate label. Default is True.\n\n    Examples\n    --------\n    How to plot the graph of the model.\n\n    .. code-block:: python\n\n        import numpy as np\n        from pymc import HalfCauchy, Model, Normal, model_to_graphviz\n\n        J = 8\n        y = np.array([28, 8, -3, 7, -1, 1, 18, 12])\n        sigma = np.array([15, 10, 16, 11, 9, 11, 10, 18])\n\n        with Model() as schools:\n            eta = Normal("eta", 0, 1, shape=J)\n            mu = Normal("mu", 0, sigma=1e6)\n            tau = HalfCauchy("tau", 25)\n\n            theta = mu + tau * eta\n\n            obs = Normal("obs", theta, sigma=sigma, observed=y)\n\n        model_to_graphviz(schools)\n\n    Note that this code automatically plots the graph if executed in a Jupyter notebook.\n    If executed non-interactively, such as in a script or python console, the graph\n    needs to be rendered explicitly:\n\n    .. code-block:: python\n\n        # creates the file `schools.pdf`\n        model_to_graphviz(schools).render("schools")\n\n    Display Free Random Variables and Observed Random Variables nodes with custom formatting.\n\n    .. code-block:: python\n\n        node_formatters = {\n            "Free Random Variable": lambda var: {"shape": "circle", "label": var.name},\n            "Observed Random Variable": lambda var: {"shape": "square", "label": var.name},\n        }\n        model_to_graphviz(schools, node_formatters=node_formatters)\n    """\n    if "plain" not in formatting:\n        raise ValueError(f"Unsupported formatting for graph nodes: \'{formatting}\'. See docstring.")\n    if formatting != "plain":\n        warnings.warn(\n            "Formattings other than \'plain\' are currently not supported.",\n            UserWarning,\n            stacklevel=2,\n        )\n\n    model = pm.modelcontext(model)\n    graph = ModelGraph(model)\n    return make_graph(\n        model.name,\n        plates=graph.get_plates(var_names=var_names),\n        edges=graph.edges(var_names=var_names),\n        formatting=formatting,\n        save=save,\n        figsize=figsize,\n        dpi=dpi,\n        graph_attr=graph_attr,\n        node_formatters=node_formatters,\n        create_plate_label=create_plate_label_with_dim_length\n        if include_dim_lengths\n        else create_plate_label_without_dim_length,\n    )\n\n\ndef _create_mermaid_node_name(name: str) -> str:\n    return name.replace(":", "_").replace(" ", "_")\n\n\ndef _build_mermaid_node(node: NodeInfo) -> list[str]:\n    var = node.var\n    node_type = node.node_type\n    name = cast(str, var.name)\n    node_name = _create_mermaid_node_name(name)\n    if node_type == NodeType.DATA:\n        return [\n            f"{node_name}[{var.name} ~ Data]",\n            f"{node_name}@{{ shape: db }}",\n        ]\n    elif node_type == NodeType.OBSERVED_RV:\n        return [\n            f"{node_name}([{name} ~ {random_variable_symbol(var)}])",\n            f"{node_name}@{{ shape: rounded }}",\n            f"style {node_name} fill:#757575",\n        ]\n\n    elif node_type == NodeType.FREE_RV:\n        return [\n            f"{node_name}([{name} ~ {random_variable_symbol(var)}])",\n            f"{node_name}@{{ shape: rounded }}",\n        ]\n    elif node_type == NodeType.DETERMINISTIC:\n        return [\n            f"{node_name}([{name} ~ Deterministic])",\n            f"{node_name}@{{ shape: rect }}",\n        ]\n    elif node_type == NodeType.POTENTIAL:\n        return [\n            f"{node_name}([{name} ~ Potential])",\n            f"{node_name}@{{ shape: diam }}",\n            f"style {node_name} fill:#f0f0f0",\n        ]\n\n    return []\n\n\ndef _build_mermaid_nodes(nodes) -> list[str]:\n    node_lines = []\n    for node in nodes:\n        node_lines.extend(_build_mermaid_node(node))\n\n    return node_lines\n\n\ndef _build_mermaid_edges(edges) -> list[str]:\n    """Return a list of Mermaid edge definitions."""\n    edge_lines = []\n    for child, parent in edges:\n        child_id = _create_mermaid_node_name(child)\n        parent_id = _create_mermaid_node_name(parent)\n        edge_lines.append(f"{parent_id} --> {child_id}")\n    return edge_lines\n\n\ndef _build_mermaid_plates(plates, include_dim_lengths) -> list[str]:\n    plate_lines = []\n    for plate in plates:\n        if not plate.dim_info:\n            continue\n\n        plate_label_func = (\n            create_plate_label_with_dim_length\n            if include_dim_lengths\n            else create_plate_label_without_dim_length\n        )\n        plate_label = plate_label_func(plate.dim_info)\n        plate_name = f\'subgraph "{plate_label}"\'\n        plate_lines.append(plate_name)\n        for var in plate.variables:\n            plate_lines.append(f"    {var.var.name}")\n        plate_lines.append("end")\n\n    return plate_lines\n\n\ndef model_to_mermaid(model=None, *, var_names=None, include_dim_lengths: bool = True) -> str:\n    """Produce a Mermaid diagram string from a PyMC model.\n\n    Parameters\n    ----------\n    model : pm.Model\n        The model to plot. Not required when called from inside a modelcontext.\n    var_names : iterable of variable names, optional\n        Subset of variables to be plotted that identify a subgraph with respect to the entire model graph\n    include_dim_lengths : bool\n        Include the dim lengths in the plate label. Default is True.\n\n    Returns\n    -------\n    str\n        Mermaid diagram string representing the model graph.\n\n    Examples\n    --------\n    Visualize a simple PyMC model\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            mu = pm.Normal("mu", mu=0, sigma=1)\n            sigma = pm.HalfNormal("sigma", sigma=1)\n\n            pm.Normal("obs", mu=mu, sigma=sigma, observed=[1, 2, 3])\n\n        print(pm.model_to_mermaid(model))\n\n\n    """\n    model = pm.modelcontext(model)\n    graph = ModelGraph(model)\n    plates = sorted(graph.get_plates(var_names=var_names), key=lambda plate: hash(plate.dim_info))\n    edges = sorted(graph.edges(var_names=var_names))\n    nodes = sorted(graph.nodes(plates=plates), key=lambda node: cast(str, node.var.name))\n\n    return "\\n".join(\n        [\n            "graph TD",\n            "%% Nodes:",\n            *_build_mermaid_nodes(nodes),\n            "\\n%% Edges:",\n            *_build_mermaid_edges(edges),\n            "\\n%% Plates:",\n            *_build_mermaid_plates(plates, include_dim_lengths=include_dim_lengths),\n        ]\n    )\n',
            'scripts/run_mypy.py': '#!/usr/bin/env python\n"""\nInvoke mypy and compare the reults with files in /pymc.\n\nExcludes tests and a list of files that are known to fail.\n\nExit code 0 indicates that there are no unexpected results.\n\nUsage\n-----\npython scripts/run_mypy.py [--verbose]\n"""\n\nimport argparse\nimport importlib\nimport os\nimport pathlib\nimport subprocess\nimport sys\n\nfrom collections.abc import Iterator\n\nimport pandas\n\nDP_ROOT = pathlib.Path(__file__).absolute().parent.parent\nFAILING = """\npymc/distributions/continuous.py\npymc/distributions/dist_math.py\npymc/distributions/distribution.py\npymc/distributions/custom.py\npymc/distributions/multivariate.py\npymc/distributions/timeseries.py\npymc/distributions/truncated.py\npymc/initial_point.py\npymc/logprob/basic.py\npymc/logprob/mixture.py\npymc/logprob/rewriting.py\npymc/logprob/scan.py\npymc/logprob/transform_value.py\npymc/logprob/transforms.py\npymc/logprob/utils.py\npymc/model/core.py\npymc/model/fgraph.py\npymc/model/transform/conditioning.py\npymc/pytensorf.py\npymc/sampling/jax.py\npymc/sampling/mcmc.py\n"""\n\n\ndef enforce_pep561(module_name):\n    try:\n        module = importlib.import_module(module_name)\n        fp = pathlib.Path(module.__path__[0], "py.typed")\n        if not fp.exists():\n            fp.touch()\n    except ModuleNotFoundError:\n        print(f"Can\'t enforce PEP 561 for {module_name} because it is not installed.")\n    return\n\n\ndef mypy_to_pandas(input_lines: Iterator[str]) -> pandas.DataFrame:\n    """Reformats mypy output with error codes to a DataFrame.\n\n    Adapted from: https://gist.github.com/michaelosthege/24d0703e5f37850c9e5679f69598930a\n    """\n    current_section = None\n    data = {\n        "file": [],\n        "line": [],\n        "type": [],\n        "errorcode": [],\n        "message": [],\n    }\n    for line in input_lines:\n        line = line.strip()\n        elems = line.split(":")\n        if len(elems) < 3:\n            continue\n        try:\n            file, lineno, message_type, *_ = elems[0:3]\n            message_type = message_type.strip()\n            if message_type == "error":\n                current_section = line.split("  [")[-1][:-1]\n            message = line.replace(f"{file}:{lineno}: {message_type}: ", "").replace(\n                f"  [{current_section}]", ""\n            )\n            data["file"].append(file)\n            data["line"].append(lineno)\n            data["type"].append(message_type)\n            data["errorcode"].append(current_section)\n            data["message"].append(message)\n        except Exception as ex:\n            print(elems)\n            print(ex)\n    return pandas.DataFrame(data=data).set_index(["file", "line"])\n\n\ndef check_no_unexpected_results(mypy_lines: Iterator[str]):\n    """Compare mypy results with list of known FAILING files.\n\n    Exits the process with non-zero exit code upon unexpected results.\n    """\n    df = mypy_to_pandas(mypy_lines)\n    all_files = {\n        str(fp).replace(str(DP_ROOT), "").strip(os.sep).replace(os.sep, "/")\n        for fp in DP_ROOT.glob("pymc/**/*.py")\n        if "tests" not in str(fp)\n    }\n    failing = set(df.reset_index().file.str.replace(os.sep, "/", regex=False))\n    if not failing.issubset(all_files):\n        raise Exception(\n            "Mypy should have ignored these files:\\n"\n            + "\\n".join(sorted(map(str, failing - all_files)))\n        )\n    passing = all_files - failing\n    expected_failing = set(FAILING.strip().split("\\n")) - {""}\n    unexpected_failing = failing - expected_failing\n    unexpected_passing = passing.intersection(expected_failing)\n\n    if not unexpected_failing:\n        print(f"{len(passing)}/{len(all_files)} files pass as expected.")\n    else:\n        print("!!!!!!!!!")\n        print(f"{len(unexpected_failing)} files unexpectedly failed.")\n        print("\\n".join(sorted(map(str, unexpected_failing))))\n        print(\n            "These files did not fail before, so please check the above output"\n            f" for errors in {unexpected_failing} and fix them."\n        )\n        print("You can run `python scripts/run_mypy.py --verbose` to reproduce this test locally.")\n        sys.exit(1)\n\n    if unexpected_passing:\n        print("!!!!!!!!!")\n        print(f"{len(unexpected_passing)} files unexpectedly passed the type checks:")\n        print("\\n".join(sorted(map(str, unexpected_passing))))\n        print(\n            "This is good news! Go to scripts/run_mypy.py and remove them from the `FAILING` list."\n        )\n        if all_files.issubset(passing):\n            print("WOW! All files are passing the mypy type checks!")\n            print("scripts\\\\run_mypy.py may no longer be needed.")\n        print("!!!!!!!!!")\n        sys.exit(1)\n    return\n\n\nif __name__ == "__main__":\n    parser = argparse.ArgumentParser(description="Run mypy type checks on PyMC codebase.")\n    parser.add_argument(\n        "--verbose", action="count", default=0, help="Pass this to print mypy output."\n    )\n    parser.add_argument(\n        "--groupby",\n        default="file",\n        help="How to group verbose output. One of {file|errorcode|message}.",\n    )\n    args, _ = parser.parse_known_args()\n\n    cp = subprocess.run(\n        ["mypy", "--show-error-codes", "--exclude", "tests", "pymc"],\n        capture_output=True,\n    )\n    output = cp.stdout.decode()\n    if args.verbose:\n        df = mypy_to_pandas(output.split("\\n"))\n        for section, sdf in df.reset_index().groupby(args.groupby):\n            print(f"\\n\\n[{section}]")\n            for row in sdf.itertuples():\n                print(f"{row.file}:{row.line}: {row.type}: {row.message}")\n        print()\n    else:\n        print(\n            "Mypy output hidden."\n            " Run `python run_mypy.py --verbose` to see the full output,"\n            " or `python run_mypy.py --help` for other options."\n        )\n\n    check_no_unexpected_results(output.split("\\n"))\n    sys.exit(0)\n',
            'tests/model/test_core.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport copy\nimport pickle\nimport threading\nimport traceback\nimport warnings\n\nfrom unittest.mock import patch\n\nimport arviz as az\nimport cloudpickle\nimport numpy as np\nimport numpy.ma as ma\nimport numpy.testing as npt\nimport pytensor\nimport pytensor.sparse as sparse\nimport pytensor.tensor as pt\nimport pytest\nimport scipy\nimport scipy.sparse as sps\nimport scipy.stats as st\n\nfrom pytensor.graph import graph_inputs\nfrom pytensor.graph.basic import get_var_by_name\nfrom pytensor.raise_op import Assert\nfrom pytensor.tensor.random.op import RandomVariable\nfrom pytensor.tensor.variable import TensorConstant\n\nimport pymc as pm\n\nfrom pymc import Deterministic, Model, MvNormal, Potential\nfrom pymc.blocking import DictToArrayBijection, RaveledVars\nfrom pymc.distributions import Normal, transforms\nfrom pymc.distributions.distribution import PartialObservedRV\nfrom pymc.distributions.transforms import (\n    ChainedTransform,\n    Interval,\n    LogTransform,\n    log,\n    ordered,\n    simplex,\n)\nfrom pymc.exceptions import ImputationWarning, ShapeError, ShapeWarning\nfrom pymc.logprob.basic import transformed_conditional_logp\nfrom pymc.logprob.transforms import IntervalTransform\nfrom pymc.model import Point, ValueGradFunction, modelcontext\nfrom pymc.variational.minibatch_rv import MinibatchRandomVariable\nfrom tests.models import simple_model\n\n\nclass NewModel(pm.Model):\n    def __init__(self, name="", model=None):\n        super().__init__(name, model)\n        assert pm.modelcontext(None) is self\n        # 1) init variables with Var method\n        self.register_rv(pm.Normal.dist(), "v1")\n        self.v2 = pm.Normal("v2", mu=0, sigma=1)\n        # 2) Potentials and Deterministic variables with method too\n        # be sure that names will not overlap with other same models\n        pm.Deterministic("d", pt.constant(1))\n        pm.Potential("p", pt.constant(1))\n\n\nclass DocstringModel(pm.Model):\n    def __init__(self, mean=0, sigma=1, name="", model=None):\n        super().__init__(name, model)\n        self.register_rv(Normal.dist(mu=mean, sigma=sigma), "v1")\n        Normal("v2", mu=mean, sigma=sigma)\n        Normal("v3", mu=mean, sigma=Normal("sigma", mu=10, sigma=1, initval=1.0))\n        Deterministic("v3_sq", self.v3**2)\n        Potential("p1", pt.constant(1))\n\n\nclass TestBaseModel:\n    def test_setattr_properly_works(self):\n        with pm.Model() as model:\n            pm.Normal("v1")\n            assert len(model.value_vars) == 1\n            with pm.Model("sub") as submodel:\n                submodel.register_rv(pm.Normal.dist(), "v1")\n                assert hasattr(submodel, "v1")\n                assert len(submodel.value_vars) == 1\n            assert len(model.value_vars) == 2\n            with submodel:\n                submodel.register_rv(pm.Normal.dist(), "v2")\n                assert hasattr(submodel, "v2")\n                assert len(submodel.value_vars) == 2\n            assert len(model.value_vars) == 3\n\n    def test_context_passes_vars_to_parent_model(self):\n        with pm.Model() as model:\n            assert pm.model.modelcontext(None) == model\n            assert pm.Model.get_context() == model\n            # a set of variables is created\n            nm = NewModel()\n            assert pm.Model.get_context() == model\n            # another set of variables are created but with prefix \'another\'\n            usermodel2 = NewModel(name="another")\n            assert pm.Model.get_context() == model\n            assert usermodel2._parent == model\n            # you can enter in a context with submodel\n            with usermodel2:\n                usermodel2.register_rv(pm.Normal.dist(), "v3")\n                pm.Normal("v4")\n                # this variable is created in parent model too\n        assert "another::v2" in model.named_vars\n        assert "another::v3" in model.named_vars\n        assert "another::v3" in usermodel2.named_vars\n        assert "another::v4" in model.named_vars\n        assert "another::v4" in usermodel2.named_vars\n        assert hasattr(usermodel2, "v3")\n        assert hasattr(usermodel2, "v2")\n        assert hasattr(usermodel2, "v4")\n        # When you create a class based model you should follow some rules\n        with model:\n            m = NewModel("one_more")\n        assert m.d is model["one_more::d"]\n        assert m["d"] is model["one_more::d"]\n        assert m["one_more::d"] is model["one_more::d"]\n\n    def test_docstring_example(self):\n        with pm.Model(name="root") as root:\n            x = pm.Normal("x")  # Variable wil be named "root::x"\n\n            with pm.Model(name="first") as first:\n                # Variable will belong to root and first\n                y = pm.Normal("y", mu=x)  # Variable wil be named "root::first::y"\n\n            # Can pass parent model explicitly\n            with pm.Model(name="second", model=root) as second:\n                # Variable will belong to root and second\n                z = pm.Normal("z", mu=y)  # Variable wil be named "root::second::z"\n\n            # Set None for standalone model\n            with pm.Model(name="third", model=None) as third:\n                # Variable will belong to third only\n                w = pm.Normal("w")  # Variable wil be named "third::w"\n\n        assert x.name == "root::x"\n        assert y.name == "root::first::y"\n        assert z.name == "root::second::z"\n        assert w.name == "third::w"\n\n        assert set(root.basic_RVs) == {x, y, z}\n        assert set(first.basic_RVs) == {y}\n        assert set(second.basic_RVs) == {z}\n        assert set(third.basic_RVs) == {w}\n\n\nclass TestNested:\n    def test_nest_context_works(self):\n        with pm.Model() as m:\n            new = NewModel()\n            with new:\n                assert pm.modelcontext(None) is new\n            assert pm.modelcontext(None) is m\n        assert "v1" in m.named_vars\n        assert "v2" in m.named_vars\n\n    def test_named_context(self):\n        with pm.Model() as m:\n            NewModel(name="new")\n        assert "new::v1" in m.named_vars\n        assert "new::v2" in m.named_vars\n\n    def test_docstring_example1(self):\n        usage1 = DocstringModel()\n        assert "v1" in usage1.named_vars\n        assert "v2" in usage1.named_vars\n        assert "v3" in usage1.named_vars\n        assert "v3_sq" in usage1.named_vars\n        assert len(usage1.potentials), "1"\n\n    def test_docstring_example2(self):\n        with pm.Model() as model:\n            DocstringModel(name="prefix")\n        assert "prefix::v1" in model.named_vars\n        assert "prefix::v2" in model.named_vars\n        assert "prefix::v3" in model.named_vars\n        assert "prefix::v3_sq" in model.named_vars\n        assert len(model.potentials), "1"\n\n    def test_duplicates_detection(self):\n        with pm.Model():\n            DocstringModel(name="prefix")\n            with pytest.raises(ValueError):\n                DocstringModel(name="prefix")\n\n    def test_model_root(self):\n        with pm.Model() as model:\n            assert model is model.root\n            with pm.Model() as sub:\n                assert model is sub.root\n\n    def test_prefix_add_uses_separator(self):\n        with pm.Model("foo"):\n            foobar = pm.Normal("foobar")\n            assert foobar.name == "foo::foobar"\n\n    def test_nested_named_model_repeated(self):\n        with pm.Model("sub") as model:\n            b = pm.Normal("var")\n            with pm.Model("sub"):\n                b = pm.Normal("var")\n        assert {"sub::var", "sub::sub::var"} == set(model.named_vars.keys())\n\n    def test_nested_named_model(self):\n        with pm.Model("sub1") as model:\n            b = pm.Normal("var")\n            with pm.Model("sub2"):\n                b = pm.Normal("var")\n        assert {"sub1::var", "sub1::sub2::var"} == set(model.named_vars.keys())\n\n    def test_nested_model_to_netcdf(self, tmp_path):\n        with pm.Model("scope") as model:\n            b = pm.Normal("var")\n            trace = pm.sample(100, tune=0)\n        az.to_netcdf(trace, tmp_path / "trace.nc")\n        trace1 = az.from_netcdf(tmp_path / "trace.nc")\n        assert "scope::var" in trace1.posterior\n\n    def test_bad_name(self):\n        with pm.Model() as model:\n            with pytest.raises(KeyError):\n                b = pm.Normal("var::")\n        with pytest.raises(KeyError):\n            with pm.Model("scope::") as model:\n                b = pm.Normal("v")\n\n\nclass TestObserved:\n    def test_observed_rv_fail(self):\n        with pytest.raises(TypeError):\n            with pm.Model():\n                x = Normal("x")\n                Normal("n", observed=x)\n\n    def test_observed_type(self):\n        X_ = pm.floatX(np.random.randn(100, 5))\n        X = pm.floatX(pytensor.shared(X_))\n        with pm.Model():\n            x1 = pm.Normal("x1", observed=X_)\n            x2 = pm.Normal("x2", observed=X)\n\n        assert x1.type.dtype == X.type.dtype\n        assert x2.type.dtype == X.type.dtype\n\n    @pytensor.config.change_flags(compute_test_value="raise")\n    def test_observed_compute_test_value(self):\n        data = np.zeros(100)\n        with pm.Model():\n            obs = pm.Normal("obs", mu=pt.zeros_like(data), sigma=1, observed=data)\n        assert obs.tag.test_value.shape == data.shape\n        assert obs.tag.test_value.dtype == data.dtype\n\n\ndef test_duplicate_vars():\n    with pytest.raises(ValueError) as err:\n        with pm.Model():\n            pm.Normal("a")\n            pm.Normal("a")\n    err.match("already exists")\n\n    with pytest.raises(ValueError) as err:\n        with pm.Model():\n            pm.Normal("a")\n            pm.Normal("a", transform=transforms.log)\n    err.match("already exists")\n\n    with pytest.raises(ValueError) as err:\n        with pm.Model():\n            a = pm.Normal("a")\n            pm.Potential("a", a**2)\n    err.match("already exists")\n\n    with pytest.raises(ValueError) as err:\n        with pm.Model():\n            pm.Binomial("a", 10, 0.5)\n            pm.Normal("a", transform=transforms.log)\n    err.match("already exists")\n\n\ndef test_empty_observed():\n    pd = pytest.importorskip("pandas")\n    data = pd.DataFrame(np.ones((2, 3)) / 3)\n    data.values[:] = np.nan\n    with pm.Model():\n        a = pm.Normal("a", observed=data)\n        assert not hasattr(a.tag, "observations")\n\n\nclass TestValueGradFunction:\n    def test_no_extra(self):\n        a = pt.vector("a")\n        a_ = np.zeros(3, dtype=a.dtype)\n        f_grad = ValueGradFunction(\n            [a.sum()], [a], {}, ravel_inputs=True, initial_point={"a": a_}, mode="FAST_COMPILE"\n        )\n        assert f_grad._extra_vars == []\n\n    def test_invalid_type(self):\n        a = pt.ivector("a")\n        a_ = np.zeros(3, dtype=a.dtype)\n        a.dshape = (3,)\n        a.dsize = 3\n        with pytest.raises(TypeError, match="Invalid dtype"):\n            ValueGradFunction(\n                [a.sum()], [a], {}, ravel_inputs=True, initial_point={"a": a_}, mode="FAST_COMPILE"\n            )\n\n    def setup_method(self, test_method):\n        extra1 = pt.iscalar("extra1")\n        extra1_ = np.array(0, dtype=extra1.dtype)\n        extra1.dshape = ()\n        extra1.dsize = 1\n\n        val1 = pt.vector("val1")\n        val1_ = np.zeros(3, dtype=val1.dtype)\n        val1.dshape = (3,)\n        val1.dsize = 3\n\n        val2 = pt.matrix("val2")\n        val2_ = np.zeros((2, 3), dtype=val2.dtype)\n        val2.dshape = (2, 3)\n        val2.dsize = 6\n\n        self.val1, self.val1_ = val1, val1_\n        self.val2, self.val2_ = val2, val2_\n        self.extra1, self.extra1_ = extra1, extra1_\n\n        self.cost = extra1 * val1.sum() + val2.sum()\n\n        self.initial_point = {\n            "extra1": extra1_,\n            "val1": val1_,\n            "val2": val2_,\n        }\n\n        with pytest.warns(\n            UserWarning, match="ValueGradFunction will become a function of raveled inputs"\n        ):\n            self.f_grad = ValueGradFunction(\n                [self.cost],\n                [val1, val2],\n                {extra1: extra1_},\n                mode="FAST_COMPILE",\n            )\n\n        self.f_grad_raveled_inputs = ValueGradFunction(\n            [self.cost],\n            [val1, val2],\n            {extra1: extra1_},\n            initial_point=self.initial_point,\n            mode="FAST_COMPILE",\n            ravel_inputs=True,\n        )\n        self.f_grad_raveled_inputs.trust_input = True\n\n    @pytest.mark.parametrize("raveled_fn", (False, True))\n    def test_extra_not_set(self, raveled_fn):\n        f_grad = self.f_grad_raveled_inputs if raveled_fn else self.f_grad\n        with pytest.raises(ValueError) as err:\n            f_grad.get_extra_values()\n        err.match("Extra values are not set")\n\n        with pytest.raises(ValueError) as err:\n            size = self.val1_.size + self.val2_.size\n            f_grad(np.zeros(size, dtype=self.f_grad.dtype))\n        err.match("Extra values are not set")\n\n    @pytest.mark.parametrize("raveled_fn", (False, True))\n    def test_grad(self, raveled_fn):\n        f_grad = self.f_grad_raveled_inputs if raveled_fn else self.f_grad\n        f_grad.set_extra_values({"extra1": 5})\n\n        size = self.val1_.size + self.val2_.size\n        array = RaveledVars(\n            np.ones(size, dtype=self.f_grad.dtype),\n            (\n                ("val1", self.val1_.shape, self.val1_.size, self.val1_.dtype),\n                ("val2", self.val2_.shape, self.val2_.size, self.val2_.dtype),\n            ),\n        )\n\n        val, grad = f_grad(array)\n        assert val == 21\n        npt.assert_allclose(grad, [5, 5, 5, 1, 1, 1, 1, 1, 1])\n\n    def test_edge_case(self):\n        # Edge case discovered in #2948\n        ndim = 3\n        with pm.Model() as m:\n            pm.LogNormal(\n                "sigma", mu=np.zeros(ndim), tau=np.ones(ndim), initval=np.ones(ndim), shape=ndim\n            )  # variance for the correlation matrix\n            pm.HalfCauchy("nu", beta=10)\n            step = pm.NUTS()\n\n        func = step._logp_dlogp_func\n        initial_point = m.initial_point()\n        func.set_extra_values(initial_point)\n        q = DictToArrayBijection.map(initial_point)\n        logp, dlogp = func(q)\n        assert logp.size == 1\n        assert dlogp.size == 4\n        npt.assert_allclose(dlogp, 0.0, atol=1e-5)\n\n    def test_missing_data(self):\n        # Originally from a case described in #3122\n        X = np.random.binomial(1, 0.5, 10)\n        X[0] = -1  # masked a single value\n        X = np.ma.masked_values(X, value=-1)\n        with pm.Model() as m:\n            x1 = pm.Uniform("x1", 0.0, 1.0)\n            with pytest.warns(ImputationWarning):\n                x2 = pm.Bernoulli("x2", x1, observed=X)\n\n        gf = m.logp_dlogp_function(ravel_inputs=True)\n        gf._extra_are_set = True\n\n        assert m["x2_unobserved"].type == gf._extra_vars_shared["x2_unobserved"].type\n\n        # The dtype of the merged observed/missing deterministic should match the RV dtype\n        assert m.deterministics[0].type.dtype == x2.type.dtype\n\n        point = m.initial_point(random_seed=None).copy()\n        del point["x2_unobserved"]\n\n        res = [gf(DictToArrayBijection.map(Point(point, model=m))) for i in range(5)]\n\n        # Assert that all the elements of res are equal\n        assert res[1:] == res[:-1]\n\n\nclass TestPytensorRelatedLogpBugs:\n    def test_pytensor_switch_broadcast_edge_cases_1(self):\n        # Tests against two subtle issues related to a previous bug in Theano\n        # where `tt.switch` would not always broadcast tensors with single\n        # values https://github.com/pymc-devs/pytensor/issues/270\n\n        # Known issue 1: https://github.com/pymc-devs/pymc/issues/4389\n        data = pm.floatX(np.zeros(10))\n        with pm.Model() as m:\n            p = pm.Beta("p", 1, 1)\n            obs = pm.Bernoulli("obs", p=p, observed=data)\n\n        npt.assert_allclose(\n            m.compile_logp(obs)({"p_logodds__": pm.floatX(np.array(0.0))}),\n            np.log(0.5) * 10,\n        )\n\n    def test_pytensor_switch_broadcast_edge_cases_2(self):\n        # Known issue 2: https://github.com/pymc-devs/pymc/issues/4417\n        # fmt: off\n        data = np.array([\n            1.35202174, -0.83690274, 1.11175166, 1.29000367, 0.21282749,\n            0.84430966, 0.24841369, 0.81803141, 0.20550244, -0.45016253,\n        ])\n        # fmt: on\n        with pm.Model() as m:\n            mu = pm.Normal("mu", 0, 5)\n            obs = pm.TruncatedNormal("obs", mu=mu, sigma=1, lower=-1, upper=2, observed=data)\n\n        npt.assert_allclose(m.compile_dlogp(mu)({"mu": 0}), 2.499424682024436, rtol=1e-5)\n\n\ndef test_multiple_observed_rv():\n    "Test previously buggy multi-observed RV comparison code."\n    y1_data = np.random.randn(10)\n    y2_data = np.random.randn(100)\n    with pm.Model() as model:\n        mu = pm.Normal("mu")\n        x = pm.CustomDist(\n            "x", mu, logp=lambda value, mu: pm.Normal.logp(value, mu, 1.0), observed=0.1\n        )\n    assert not model["x"] == model["mu"]\n    assert model["x"] == model["x"]\n    assert model["x"] in model.observed_RVs\n    assert model["x"] not in model.value_vars\n\n\n@pytest.mark.parametrize("ravel_inputs", (False, True))\ndef test_tempered_logp_dlogp(ravel_inputs):\n    with pm.Model() as model:\n        pm.Normal("x")\n        pm.Normal("y", observed=1)\n        pm.Potential("z", pt.constant(-1.0, dtype=pytensor.config.floatX))\n\n    func = model.logp_dlogp_function(ravel_inputs=ravel_inputs)\n    func.set_extra_values({})\n\n    func_temp = model.logp_dlogp_function(tempered=True, ravel_inputs=ravel_inputs)\n    func_temp.set_extra_values({})\n\n    func_nograd = model.logp_dlogp_function(compute_grads=False, ravel_inputs=ravel_inputs)\n    func_nograd.set_extra_values({})\n\n    func_temp_nograd = model.logp_dlogp_function(\n        tempered=True, compute_grads=False, ravel_inputs=ravel_inputs\n    )\n    func_temp_nograd.set_extra_values({})\n\n    x = np.ones((1,), dtype=func.dtype)\n    npt.assert_allclose(func(x)[0], func_temp(x)[0])\n    npt.assert_allclose(func(x)[1], func_temp(x)[1])\n\n    npt.assert_allclose(func_nograd(x), func(x)[0])\n    npt.assert_allclose(func_temp_nograd(x), func(x)[0])\n\n    func_temp.set_weights(np.array([0.0], dtype=func.dtype))\n    func_temp_nograd.set_weights(np.array([0.0], dtype=func.dtype))\n    npt.assert_allclose(func(x)[0], 2 * func_temp(x)[0] - 1)\n    npt.assert_allclose(func(x)[1], func_temp(x)[1])\n\n    npt.assert_allclose(func_nograd(x), func(x)[0])\n    npt.assert_allclose(func_temp_nograd(x), func_temp(x)[0])\n\n    func_temp.set_weights(np.array([0.5], dtype=func.dtype))\n    func_temp_nograd.set_weights(np.array([0.5], dtype=func.dtype))\n    npt.assert_allclose(func(x)[0], 4 / 3 * (func_temp(x)[0] - 1 / 4))\n    npt.assert_allclose(func(x)[1], func_temp(x)[1])\n\n    npt.assert_allclose(func_nograd(x), func(x)[0])\n    npt.assert_allclose(func_temp_nograd(x), func_temp(x)[0])\n\n\nclass TestPickling:\n    def test_model_pickle(self, tmpdir):\n        """Tests that PyMC models are pickleable"""\n        with pm.Model() as model:\n            x = pm.Normal("x")\n            pm.Normal("y", observed=1)\n\n        cloudpickle.loads(cloudpickle.dumps(model))\n\n    def test_model_pickle_deterministic(self, tmpdir):\n        """Tests that PyMC models are pickleable"""\n        with pm.Model() as model:\n            x = pm.Normal("x")\n            z = pm.Normal("z")\n            pm.Deterministic("w", x / z)\n            pm.Normal("y", observed=1)\n\n        cloudpickle.loads(cloudpickle.dumps(model))\n\n    def setup_method(self):\n        _, self.model, _ = simple_model()\n\n    def test_model_roundtrip(self):\n        m = self.model\n        for proto in range(pickle.HIGHEST_PROTOCOL + 1):\n            try:\n                s = cloudpickle.dumps(m, proto)\n                cloudpickle.loads(s)\n            except Exception:\n                raise AssertionError(\n                    f"Exception while trying roundtrip with pickle protocol {proto}:\\n"\n                    + "".join(traceback.format_exc())\n                )\n\n\ndef test_model_value_vars():\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        pm.Normal("x", a)\n\n    value_vars = model.value_vars\n    assert len(value_vars) == 2\n    assert set(value_vars) == set(pm.inputvars(model.logp()))\n\n\ndef test_model_var_maps():\n    with pm.Model() as model:\n        a = pm.Uniform("a")\n        x = pm.Normal("x", a)\n\n    assert set(model.rvs_to_values.keys()) == {a, x}\n    a_value = model.rvs_to_values[a]\n    x_value = model.rvs_to_values[x]\n    assert a_value.owner is None\n    assert x_value.owner is None\n    assert model.values_to_rvs == {a_value: a, x_value: x}\n\n    assert set(model.rvs_to_transforms.keys()) == {a, x}\n    assert isinstance(model.rvs_to_transforms[a], IntervalTransform)\n    assert model.rvs_to_transforms[x] is None\n\n\nclass TestTransformArgs:\n    def test_transform_warning(self):\n        with pm.Model():\n            with pytest.warns(\n                UserWarning,\n                match="To disable default transform,"\n                " please use default_transform=None"\n                " instead of transform=None. Setting transform to"\n                " None will not have any effect in future.",\n            ):\n                a = pm.Normal("a", transform=None)\n\n    def test_transform_order(self):\n        with pm.Model() as model:\n            x = pm.Normal("x", transform=Interval(0, 1), default_transform=log)\n        transform = model.rvs_to_transforms[x]\n        assert isinstance(transform, ChainedTransform)\n        assert isinstance(transform.transform_list[0], LogTransform)\n        assert isinstance(transform.transform_list[1], Interval)\n\n    def test_default_transform_is_applied(self):\n        with pm.Model() as model1:\n            x1 = pm.LogNormal("x1", [0, 0], [1, 1], transform=ordered, default_transform=None)\n        with pm.Model() as model2:\n            x2 = pm.LogNormal("x2", [0, 0], [1, 1], transform=ordered)\n        assert np.isinf(model1.compile_logp()({"x1_ordered__": (-1, -1)}))\n        assert np.isfinite(model2.compile_logp()({"x2_chain__": (-1, -1)}))\n\n\ndef test_make_obs_var():\n    """\n    Check returned values for `data` given known inputs to `as_tensor()`.\n\n    Note that ndarrays should return a TensorConstant and sparse inputs\n    should return a Sparse PyTensor object.\n    """\n    # Create the various inputs to the function\n    input_name = "testing_inputs"\n    sparse_input = sps.csr_matrix(np.eye(3))\n    dense_input = np.arange(9).reshape((3, 3))\n    masked_array_input = ma.array(dense_input, mask=(np.mod(dense_input, 2) == 0))\n\n    # Create a fake model and fake distribution to be used for the test\n    fake_model = pm.Model()\n    with fake_model:\n        fake_distribution = pm.Normal.dist(mu=0, sigma=1, size=(3, 3))\n        # Create the testval attribute simply for the sake of model testing\n        fake_distribution.name = input_name\n\n    # The function requires data and RV dimensionality to be compatible\n    with pytest.raises(ShapeError, match="Dimensionality of data and RV don\'t match."):\n        fake_model.make_obs_var(fake_distribution, np.ones((3, 3, 1)), None, None, None, None)\n\n    # Check function behavior using the various inputs\n    # dense, sparse: Ensure that the missing values are appropriately set to None\n    # masked: a deterministic variable is returned\n\n    dense_output = fake_model.make_obs_var(fake_distribution, dense_input, None, None, None, None)\n    assert dense_output == fake_distribution\n    assert isinstance(fake_model.rvs_to_values[dense_output], TensorConstant)\n    del fake_model.named_vars[fake_distribution.name]\n\n    sparse_output = fake_model.make_obs_var(fake_distribution, sparse_input, None, None, None, None)\n    assert sparse_output == fake_distribution\n    assert sparse.basic._is_sparse_variable(fake_model.rvs_to_values[sparse_output])\n    del fake_model.named_vars[fake_distribution.name]\n\n    # Here the RandomVariable is split into observed/imputed and a Deterministic is returned\n    with pytest.warns(ImputationWarning):\n        masked_output = fake_model.make_obs_var(\n            fake_distribution, masked_array_input, None, None, None, None\n        )\n    assert masked_output != fake_distribution\n    assert not isinstance(masked_output, RandomVariable)\n    # Ensure it has missing values\n    assert {"testing_inputs_unobserved"} == {v.name for v in fake_model.value_vars}\n    assert {"testing_inputs", "testing_inputs_observed"} == {\n        v.name for v in fake_model.observed_RVs\n    }\n    del fake_model.named_vars[fake_distribution.name]\n\n    # Test that setting total_size returns a MinibatchRandomVariable\n    scaled_outputs = fake_model.make_obs_var(\n        fake_distribution, dense_input, None, None, None, total_size=100\n    )\n    assert scaled_outputs != fake_distribution\n    assert isinstance(scaled_outputs.owner.op, MinibatchRandomVariable)\n    del fake_model.named_vars[fake_distribution.name]\n\n\ndef test_initial_point():\n    with pm.Model() as model:\n        a = pm.Uniform("a")\n        x = pm.Normal("x", a)\n\n    b_initval = np.array(0.3, dtype=pytensor.config.floatX)\n\n    with model:\n        b = pm.Uniform("b", initval=b_initval)\n\n    b_initval_trans = model.rvs_to_transforms[b].forward(b_initval, *b.owner.inputs).eval()\n\n    y_initval = np.array(-2.4, dtype=pytensor.config.floatX)\n\n    with model:\n        y = pm.Normal("y", initval=y_initval)\n\n    assert a in model.rvs_to_initial_values\n    assert x in model.rvs_to_initial_values\n    assert model.rvs_to_initial_values[b] == b_initval\n    assert model.initial_point(0)["b_interval__"] == b_initval_trans\n    assert model.rvs_to_initial_values[y] == y_initval\n\n\ndef test_point_logps():\n    with pm.Model() as model:\n        a = pm.Uniform("a")\n        pm.Normal("x", a)\n\n    logp_vals = model.point_logps()\n\n    assert "x" in logp_vals.keys()\n    assert "a" in logp_vals.keys()\n\n\ndef test_point_logps_potential():\n    with pm.Model() as model:\n        x = pm.Flat("x", initval=1)\n        y = pm.Potential("y", x * 2)\n\n    logps = model.point_logps()\n    assert np.isclose(logps["y"], 2)\n\n\nclass TestShapeEvaluation:\n    def test_eval_rv_shapes(self):\n        with pm.Model(\n            coords={\n                "city": ["Sydney", "Las Vegas", "Düsseldorf"],\n            }\n        ) as pmodel:\n            pm.Data("budget", [1, 2, 3, 4], dims="year")\n            pm.Normal("untransformed", size=(1, 2))\n            pm.Uniform("transformed", size=(7,))\n            obs = pm.Uniform("observed", size=(3,), observed=[0.1, 0.2, 0.3])\n            pm.LogNormal("lognorm", mu=pt.log(obs))\n            pm.Normal("from_dims", dims=("city", "year"))\n        shapes = pmodel.eval_rv_shapes()\n        assert shapes["untransformed"] == (1, 2)\n        assert shapes["transformed"] == (7,)\n        assert shapes["transformed_interval__"] == (7,)\n        assert shapes["lognorm"] == (3,)\n        assert shapes["lognorm_log__"] == (3,)\n        assert shapes["from_dims"] == (3, 4)\n\n\nclass TestCheckStartVals:\n    def test_valid_start_point(self):\n        with pm.Model() as model:\n            a = pm.Uniform("a", lower=0.0, upper=1.0)\n            b = pm.Uniform("b", lower=2.0, upper=3.0)\n\n        start = {\n            "a_interval__": model.rvs_to_transforms[a].forward(0.3, *a.owner.inputs).eval(),\n            "b_interval__": model.rvs_to_transforms[b].forward(2.1, *b.owner.inputs).eval(),\n        }\n        model.check_start_vals(start)\n\n    def test_invalid_start_point(self):\n        with pm.Model() as model:\n            a = pm.Uniform("a", lower=0.0, upper=1.0)\n            b = pm.Uniform("b", lower=2.0, upper=3.0)\n\n        start = {\n            "a_interval__": np.nan,\n            "b_interval__": model.rvs_to_transforms[b].forward(2.1, *b.owner.inputs).eval(),\n        }\n        with pytest.raises(pm.exceptions.SamplingError):\n            model.check_start_vals(start)\n\n    def test_invalid_variable_name(self):\n        with pm.Model() as model:\n            a = pm.Uniform("a", lower=0.0, upper=1.0)\n            b = pm.Uniform("b", lower=2.0, upper=3.0)\n\n        start = {\n            "a_interval__": model.rvs_to_transforms[a].forward(0.3, *a.owner.inputs).eval(),\n            "b_interval__": model.rvs_to_transforms[b].forward(2.1, *b.owner.inputs).eval(),\n            "c": 1.0,\n        }\n        with pytest.raises(KeyError):\n            model.check_start_vals(start)\n\n    @pytest.mark.parametrize("mode", [None, "JAX", "NUMBA"])\n    def test_mode(self, mode):\n        with pm.Model() as model:\n            a = pm.Uniform("a", lower=0.0, upper=1.0)\n            b = pm.Uniform("b", lower=2.0, upper=3.0)\n        start = {\n            "a_interval__": model.rvs_to_transforms[a].forward(0.3, *a.owner.inputs).eval(),\n            "b_interval__": model.rvs_to_transforms[b].forward(2.1, *b.owner.inputs).eval(),\n        }\n        with patch("pymc.model.core.compile") as patched_compile:\n            model.check_start_vals(start, mode=mode)\n        patched_compile.assert_called_once()\n        assert patched_compile.call_args.kwargs["mode"] == mode\n\n\ndef test_set_initval():\n    # Make sure the dependencies between variables are maintained when\n    # generating initial values\n    rng = np.random.RandomState(392)\n\n    with pm.Model() as model:\n        eta = pm.Uniform("eta", 1.0, 2.0, size=(1, 1))\n        mu = pm.Normal("mu", sigma=eta, initval=[[100]])\n        alpha = pm.HalfNormal("alpha", initval=100)\n        value = pm.NegativeBinomial("value", mu=mu, alpha=alpha)\n\n    assert np.array_equal(model.rvs_to_initial_values[mu], np.array([[100.0]]))\n    np.testing.assert_array_equal(model.rvs_to_initial_values[alpha], np.array(100))\n    assert model.rvs_to_initial_values[value] is None\n\n    # `Flat` cannot be sampled, so let\'s make sure that doesn\'t break initial\n    # value computations\n    with pm.Model() as model:\n        x = pm.Flat("x")\n        y = pm.Normal("y", x, 1)\n\n    assert y in model.rvs_to_initial_values\n\n\ndef test_datalogp_multiple_shapes():\n    with pm.Model() as m:\n        x = pm.Normal("x", 0, 1)\n        z1 = pm.Potential("z1", x)\n        z2 = pm.Potential("z2", pt.full((1, 3), x))\n        y1 = pm.Normal("y1", x, 1, observed=np.array([1]))\n        y2 = pm.Normal("y2", x, 1, observed=np.array([1, 2]))\n        y3 = pm.Normal("y3", x, 1, observed=np.array([1, 2, 3]))\n\n    # This would raise a TypeError, see #4803 and #4804\n    x_val = m.rvs_to_values[x]\n    m.datalogp.eval({x_val: 0})\n\n\ndef test_nested_model_coords():\n    with pm.Model(name="m1", coords={"dim1": range(2)}) as m1:\n        a = pm.Normal("a", dims="dim1")\n        with pm.Model(name="m2", coords={"dim2": range(4)}) as m2:\n            b = pm.Normal("b", dims="dim1")\n            m1.add_coord("dim3", range(4))\n            c = pm.HalfNormal("c", dims="dim3")\n            d = pm.Normal("d", b, c, dims="dim2")\n        e = pm.Normal("e", a[None] + d[:, None], dims=("dim2", "dim1"))\n    assert m1.coords is m2.coords\n    assert m1.dim_lengths is m2.dim_lengths\n    assert set(m2.named_vars_to_dims) < set(m1.named_vars_to_dims)\n\n\ndef test_multiple_add_coords_with_same_name():\n    coord = {"dim1": ["a", "b", "c"]}\n    with pm.Model(coords=coord) as m:\n        a = pm.Normal("a", dims="dim1")\n        with pm.Model(coords=coord) as nested_m:\n            b = pm.Normal("b", dims="dim1")\n        m.add_coords(coord)\n        c = pm.Normal("c", dims="dim1")\n        d = pm.Deterministic("d", a + b + c)\n    variables = get_var_by_name([d], "dim1")\n    assert len(variables) == 1 and variables[0] is m.dim_lengths["dim1"]\n\n\nclass TestSetUpdateCoords:\n    def test_shapeerror_from_set_data_dimensionality(self):\n        with pm.Model() as pmodel:\n            pm.Data("m", np.ones((3,)), dims="one")\n            with pytest.raises(ValueError, match="must have 1 dimensions"):\n                pmodel.set_data("m", np.ones((3, 4)))\n\n    def test_resize_from_set_data_dim_with_coords(self):\n        with pm.Model(coords={"dim_with_coords": [1, 2]}) as pmodel:\n            pm.Data("m", [1, 2], dims=("dim_with_coords",))\n            # Does not resize dim\n            pmodel.set_data("m", [3, 4])\n            # Resizes, but also passes new coords\n            pmodel.set_data("m", [1, 2, 3], coords={"dim_with_coords": [1, 2, 3]})\n\n            # Resizes, but does not pass new coords\n            with pytest.raises(ValueError, match="\'m\' variable already had 3"):\n                pm.set_data({"m": [1, 2, 3, 4]})\n\n    def test_resize_from_set_data_dim_without_coords(self):\n        with pm.Model() as pmodel:\n            # TODO: Either support dims without coords everywhere or don\'t. Why is it okay for Data but not RVs?\n            pm.Data("m", [1, 2], dims=("dim_without_coords",))\n            pmodel.set_data("m", [3, 4])\n            pmodel.set_data("m", [1, 2, 3])\n\n    def test_resize_from_set_dim(self):\n        """Test the conscious re-sizing of dims created through add_coord() with coord value."""\n        with pm.Model(coords={"mdim": ["A", "B"]}) as pmodel:\n            a = pm.Normal("a", dims="mdim")\n        assert pmodel.coords["mdim"] == ("A", "B")\n\n        with pytest.raises(ValueError, match="has coord values"):\n            pmodel.set_dim("mdim", new_length=3)\n\n        with pytest.raises(ShapeError, match="does not match"):\n            pmodel.set_dim("mdim", new_length=3, coord_values=["A", "B"])\n\n        pmodel.set_dim("mdim", 3, ["A", "B", "C"])\n        assert pmodel.coords["mdim"] == ("A", "B", "C")\n        with pytensor.config.change_flags(cxx=""):\n            assert a.eval().shape == (3,)\n\n    def test_resize_from_set_data_and_set_dim(self):\n        with pm.Model(coords={"group": ["A", "B"]}) as m:\n            x = pm.Data("x", [0], dims="feature")\n            y = pm.Normal("y", x, 1, dims=("group", "feature"))\n\n        with pytensor.config.change_flags(cxx=""):\n            assert x.eval().shape == (1,)\n            assert y.eval().shape == (2, 1)\n\n        m.set_data("x", [0, 1])\n        m.set_dim("group", new_length=3, coord_values=["A", "B", "C"])\n        with pytensor.config.change_flags(cxx=""):\n            assert x.eval().shape == (2,)\n            assert y.eval().shape == (3, 2)\n\n    def test_add_named_variable_checks_dim_name(self):\n        with pm.Model() as pmodel:\n            rv = pm.Normal.dist(mu=[1, 2])\n\n            # Checks that vars are named\n            with pytest.raises(ValueError, match="is unnamed"):\n                pmodel.add_named_variable(rv)\n            rv.name = "nomnom"\n\n            # Coords must be available already\n            with pytest.raises(ValueError, match="not specified in `coords`"):\n                pmodel.add_named_variable(rv, dims="nomnom")\n            pmodel.add_coord("nomnom", [1, 2])\n\n            # No name collisions\n            with pytest.raises(ValueError, match="same name as"):\n                pmodel.add_named_variable(rv, dims="nomnom")\n\n            # This should work (regression test against #6335)\n            rv2 = rv[:, None]\n            rv2.name = "yumyum"\n            pmodel.add_named_variable(rv2, dims=("nomnom", None))\n\n    def test_add_named_variable_checks_number_of_dims(self):\n        match = "dim labels were provided"\n        with pm.Model(coords={"bad": range(6)}) as m:\n            with pytest.raises(ValueError, match=match):\n                m.add_named_variable(pt.random.normal(size=(6, 6, 6), name="a"), dims=("bad",))\n\n            # "bad" is an iterable with 3 elements, but we treat strings as a single dim, so it\'s still invalid\n            with pytest.raises(ValueError, match=match):\n                m.add_named_variable(pt.random.normal(size=(6, 6, 6), name="b"), dims="bad")\n\n    def test_rv_dims_type_check(self):\n        with pm.Model(coords={"a": range(5)}) as m:\n            with pytest.raises(TypeError, match="Dims must be string"):\n                x = pm.Normal("x", shape=(10, 5), dims=(None, "a"))\n\n    def test_none_coords_autonumbering(self):\n        # TODO: Either allow dims without coords everywhere or nowhere\n        with pm.Model() as m:\n            m.add_coord(name="a", values=None, length=3)\n            m.add_coord(name="b", values=range(-5, 0))\n            m.add_coord(name="c", values=None, length=7)\n            x = pm.Normal("x", dims=("a", "b", "c"))\n            prior = pm.sample_prior_predictive(draws=2).prior\n        assert prior["x"].shape == (1, 2, 3, 5, 7)\n        assert list(prior.coords["a"].values) == list(range(3))\n        assert list(prior.coords["b"].values) == list(range(-5, 0))\n        assert list(prior.coords["c"].values) == list(range(7))\n\n    def test_set_data_indirect_resize_without_coords(self):\n        with pm.Model() as pmodel:\n            pmodel.add_coord("mdim", length=2)\n            pm.Data("mdata", [1, 2], dims="mdim")\n\n        assert pmodel.dim_lengths["mdim"].get_value() == 2\n        assert pmodel.coords["mdim"] is None\n\n        # First resize the dimension.\n        pmodel.dim_lengths["mdim"].set_value(3)\n        # Then change the data.\n        with warnings.catch_warnings():\n            warnings.simplefilter("error")\n            pmodel.set_data("mdata", [1, 2, 3])\n\n        # Now the other way around.\n        with warnings.catch_warnings():\n            warnings.simplefilter("error")\n            pmodel.set_data("mdata", [1, 2, 3, 4])\n\n    def test_set_data_indirect_resize_with_coords(self):\n        with pm.Model() as pmodel:\n            pmodel.add_coord("mdim", ["A", "B"], length=2)\n            pm.Data("mdata", [1, 2], dims="mdim")\n\n        assert pmodel.coords["mdim"] == ("A", "B")\n\n        # First resize the dimension.\n        pmodel.set_dim("mdim", 3, ["A", "B", "C"])\n        assert pmodel.coords["mdim"] == ("A", "B", "C")\n        # Then change the data.\n        with warnings.catch_warnings():\n            warnings.simplefilter("error")\n            pmodel.set_data("mdata", [1, 2, 3])\n\n        # Now the other way around.\n        with warnings.catch_warnings():\n            warnings.simplefilter("error")\n            pmodel.set_data("mdata", [1, 2, 3, 4], coords={"mdim": ["A", "B", "C", "D"]})\n        assert pmodel.coords["mdim"] == ("A", "B", "C", "D")\n\n        # This time with incorrectly sized coord values\n        with pytest.raises(ShapeError, match="new coordinate values"):\n            pmodel.set_data("mdata", [1, 2], coords={"mdim": [1, 2, 3]})\n\n    def test_set_data_warns_on_resize_of_dims_defined_by_other_data(self):\n        with pm.Model() as pmodel:\n            pm.Data("m1", [1, 2], dims="mutable")\n            pm.Data("m2", [3, 4], dims="mutable")\n\n            # Resizing the non-defining variable first gives a warning\n            with pytest.warns(ShapeWarning, match="by another variable"):\n                pmodel.set_data("m2", [4, 5, 6])\n                pmodel.set_data("m1", [1, 2, 3])\n\n            # Resizing the defining variable first is silent\n            with warnings.catch_warnings():\n                warnings.simplefilter("error")\n                pmodel.set_data("m1", [1, 2])\n                pmodel.set_data("m2", [3, 4])\n\n    def test_set_data_constant_shape_error(self):\n        # TODO: Why allow such a complex scenario?\n        with pm.Model() as pmodel:\n            x = pm.Normal("x", size=7)\n            pmodel.add_coord("weekday", length=x.shape[0])\n            pm.Data("y", np.arange(7), dims="weekday")\n\n        msg = "because the dimension was initialized from \'x\'"\n        with pytest.raises(ShapeError, match=msg):\n            pmodel.set_data("y", np.arange(10))\n\n\n@pytest.mark.parametrize("jacobian", [True, False])\ndef test_model_logp(jacobian):\n    with pm.Model() as m:\n        x = pm.Normal("x", 0, 1, size=2)\n        y = pm.LogNormal("y", 0, 1, size=2)\n\n    test_vals = np.array([0.0, 1.0])\n\n    expected_x_logp = st.norm().logpdf(test_vals)\n    expected_y_logp = expected_x_logp.copy()\n    if not jacobian:\n        expected_y_logp -= np.array([0.0, 1.0])\n\n    x_logp, y_logp = m.compile_logp(sum=False, jacobian=jacobian)(\n        {"x": test_vals, "y_log__": test_vals}\n    )\n    assert np.all(np.isclose(x_logp, expected_x_logp))\n    assert np.all(np.isclose(y_logp, expected_y_logp))\n\n    x_logp2 = m.compile_logp(vars=[x], sum=False, jacobian=jacobian)({"x": test_vals})\n    assert np.all(np.isclose(x_logp2, expected_x_logp))\n\n    y_logp2 = m.compile_logp(vars=[y], sum=False, jacobian=jacobian)({"y_log__": test_vals})\n    assert np.all(np.isclose(y_logp2, expected_y_logp))\n\n    logp_sum = m.compile_logp(sum=True, jacobian=jacobian)({"x": test_vals, "y_log__": test_vals})\n    assert np.isclose(logp_sum, expected_x_logp.sum() + expected_y_logp.sum())\n\n\n@pytest.mark.parametrize("jacobian", [True, False])\ndef test_model_dlogp(jacobian):\n    with pm.Model() as m:\n        x = pm.Normal("x", 0, 1, size=2)\n        y = pm.LogNormal("y", 0, 1, size=2)\n\n    test_vals = np.array([0.0, -1.0])\n    state = {"x": test_vals, "y_log__": test_vals}\n\n    expected_x_dlogp = expected_y_dlogp = np.array([0.0, 1.0])\n    if not jacobian:\n        expected_y_dlogp = np.array([-1.0, 0.0])\n\n    dlogps = m.compile_dlogp(jacobian=jacobian)(state)\n    assert np.all(np.isclose(dlogps[:2], expected_x_dlogp))\n    assert np.all(np.isclose(dlogps[2:], expected_y_dlogp))\n\n    x_dlogp2 = m.compile_dlogp(vars=[x], jacobian=jacobian)(state)\n    assert np.all(np.isclose(x_dlogp2, expected_x_dlogp))\n\n    y_dlogp2 = m.compile_dlogp(vars=[y], jacobian=jacobian)(state)\n    assert np.all(np.isclose(y_dlogp2, expected_y_dlogp))\n\n\n@pytest.mark.parametrize("jacobian", [True, False])\ndef test_model_d2logp(jacobian):\n    with pm.Model() as m:\n        x = pm.Normal("x", 0, 1, size=2)\n        y = pm.LogNormal("y", 0, 1, size=2)\n\n    test_vals = np.array([0.0, -1.0])\n    state = {"x": test_vals, "y_log__": test_vals}\n\n    expected_x_d2logp = expected_y_d2logp = -np.eye(2)\n\n    dlogps = m.compile_d2logp(jacobian=jacobian, negate_output=False)(state)\n    assert np.all(np.isclose(dlogps[:2, :2], expected_x_d2logp))\n    assert np.all(np.isclose(dlogps[2:, 2:], expected_y_d2logp))\n\n    x_dlogp2 = m.compile_d2logp(vars=[x], jacobian=jacobian, negate_output=False)(state)\n    assert np.all(np.isclose(x_dlogp2, expected_x_d2logp))\n\n    y_dlogp2 = m.compile_d2logp(vars=[y], jacobian=jacobian, negate_output=False)(state)\n    assert np.all(np.isclose(y_dlogp2, expected_y_d2logp))\n\n\ndef test_deterministic():\n    with pm.Model() as model:\n        x = pm.Normal("x", 0, 1)\n        y = pm.Deterministic("y", x**2)\n\n    assert model.y == y\n    assert model["y"] == y\n\n\ndef test_determinsitic_with_dims():\n    """\n    Test to check the passing of dims to the potential\n    """\n    with pm.Model(coords={"observed": range(10)}) as model:\n        x = pm.Normal("x", 0, 1, shape=(10,))\n        y = pm.Deterministic("y", x**2, dims=("observed",))\n    assert model.named_vars_to_dims == {"y": ("observed",)}\n\n\ndef test_potential_with_dims():\n    """\n    Test to check the passing of dims to the potential\n    """\n    with pm.Model(coords={"observed": range(10)}) as model:\n        x = pm.Normal("x", 0, 1, shape=(10,))\n        y = pm.Potential("y", x**2, dims=("observed",))\n    assert model.named_vars_to_dims == {"y": ("observed",)}\n\n\ndef test_empty_model_representation():\n    assert pm.Model().str_repr() == ""\n\n\ndef test_compile_fn():\n    with pm.Model() as m:\n        x = pm.Normal("x", 0, 1, size=2)\n        y = pm.LogNormal("y", 0, 1, size=2)\n\n    test_vals = np.array([0.0, -1.0])\n    state = {"x": test_vals, "y": test_vals}\n\n    with m:\n        func = pm.compile_fn(x + y, inputs=[x, y])\n        result_compute = func(state)\n\n    func = m.compile_fn(x + y, inputs=[x, y])\n    result_expect = func(state)\n\n    np.testing.assert_allclose(result_compute, result_expect)\n\n\ndef test_model_parent_set_programmatically():\n    with pm.Model() as model:\n        x = pm.Normal("x")\n\n    with pm.Model(model=model):\n        y = pm.Normal("y")\n\n    with model:\n        # Default inherits from model\n        with pm.Model():\n            z_in = pm.Normal("z_in")\n\n        # Explict None opts out of model context\n        with pm.Model(model=None):\n            z_out = pm.Normal("z_out")\n\n    assert "y" in model.named_vars\n    assert "z_in" in model.named_vars\n    assert "z_out" not in model.named_vars\n\n\nclass TestModelContext:\n    def test_thread_safety(self):\n        """Regression test for issue #1552: Thread safety of model context manager\n\n        This test creates two threads that attempt to construct two\n        unrelated models at the same time.\n        For repeatable testing, the two threads are synchronised such\n        that thread A enters the context manager first, then B,\n        then A attempts to declare a variable while B is still in the context manager.\n        """\n        aInCtxt, bInCtxt, aDone = (threading.Event() for _ in range(3))\n        modelA = pm.Model()\n        modelB = pm.Model()\n\n        def make_model_a():\n            with modelA:\n                aInCtxt.set()\n                bInCtxt.wait()\n                Normal("a", 0, 1)\n            aDone.set()\n\n        def make_model_b():\n            aInCtxt.wait()\n            with modelB:\n                bInCtxt.set()\n                aDone.wait()\n                Normal("b", 0, 1)\n\n        threadA = threading.Thread(target=make_model_a)\n        threadB = threading.Thread(target=make_model_b)\n        threadA.start()\n        threadB.start()\n        threadA.join()\n        threadB.join()\n        # now let\'s see which model got which variable\n        # previous to #1555, the variables would be swapped:\n        # - B enters it\'s model context after A, but before a is declared -> a goes into B\n        # - A leaves it\'s model context before B attempts to declare b. A\'s context manager\n        #   takes B from the stack, such that b ends up in model A\n        assert (\n            list(modelA.named_vars),\n            list(modelB.named_vars),\n        ) == (["a"], ["b"])\n\n\ndef test_mixed_contexts():\n    modelA = pm.Model()\n    modelB = pm.Model()\n    with pytest.raises((ValueError, TypeError)):\n        modelcontext(None)\n    with modelA:\n        with modelB:\n            assert pm.Model.get_context() == modelB\n            assert modelcontext(None) == modelB\n        assert pm.Model.get_context() == modelA\n        assert modelcontext(None) == modelA\n    assert pm.Model.get_context(error_if_none=False) is None\n    with pytest.raises(TypeError):\n        pm.Model.get_context(error_if_none=True)\n    with pytest.raises((ValueError, TypeError)):\n        modelcontext(None)\n\n\nclass TestProfile:\n    def setup_method(self):\n        _, self.model, _ = simple_model()\n\n    def test_profile_model(self):\n        assert self.model.profile(self.model.logp(), n=3000).fct_call_time > 0\n\n    def test_profile_variable(self):\n        rv = self.model.basic_RVs[0]\n        assert self.model.profile(self.model.logp(vars=[rv], sum=False), n=3000).fct_call_time > 0\n\n    def test_profile_count(self):\n        count = 1005\n        assert self.model.profile(self.model.logp(), n=count).fct_callcount == count\n\n\n@pytest.fixture(params=["masked", "pandas"])\ndef missing_data(request):\n    if request.param == "masked":\n        return np.ma.masked_values([1, 2, -1, 4, -1], value=-1)\n    else:\n        # request.param == "pandas"\n        pd = pytest.importorskip("pandas")\n        return pd.DataFrame([1, 2, np.nan, 4, np.nan])\n\n\nclass TestImputationMissingData:\n    "Test for Missing Data imputation"\n\n    def test_missing_basic(self, missing_data):\n        with pm.Model() as model:\n            x = pm.Normal("x", 1, 1)\n            with pytest.warns(ImputationWarning):\n                _ = pm.Normal("y", x, 1, observed=missing_data)\n\n        assert "y_unobserved" in model.named_vars\n\n        test_point = model.initial_point()\n        assert not np.isnan(model.compile_logp()(test_point))\n\n        with model:\n            ipr = pm.sample_prior_predictive()\n        assert {"x", "y"} <= set(ipr.prior.keys())\n\n    def test_missing_with_predictors(self):\n        predictors = np.array([0.5, 1, 0.5, 2, 0.3])\n        data = np.ma.masked_values([1, 2, -1, 4, -1], value=-1)\n        with pm.Model() as model:\n            x = pm.Normal("x", 1, 1)\n            with pytest.warns(ImputationWarning):\n                y = pm.Normal("y", x * predictors, 1, observed=data)\n\n        assert "y_unobserved" in model.named_vars\n\n        test_point = model.initial_point()\n        assert not np.isnan(model.compile_logp()(test_point))\n\n        with model:\n            ipr = pm.sample_prior_predictive()\n        assert {"x", "y"} <= set(ipr.prior.keys())\n\n    def test_missing_dual_observations(self):\n        with pm.Model() as model:\n            obs1 = np.ma.masked_values([1, 2, -1, 4, -1], value=-1)\n            obs2 = np.ma.masked_values([-1, -1, 6, -1, 8], value=-1)\n            beta1 = pm.Normal("beta1", 1, 1)\n            beta2 = pm.Normal("beta2", 2, 1)\n            latent = pm.Normal("theta", size=5)\n            with pytest.warns(ImputationWarning):\n                ovar1 = pm.Normal("o1", mu=beta1 * latent, observed=obs1)\n            with pytest.warns(ImputationWarning):\n                ovar2 = pm.Normal("o2", mu=beta2 * latent, observed=obs2)\n\n            prior_trace = pm.sample_prior_predictive(return_inferencedata=False)\n            assert {"beta1", "beta2", "theta", "o1", "o2"} <= set(prior_trace.keys())\n            # TODO: Assert something\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                trace = pm.sample(chains=1, tune=5, draws=50)\n\n    def test_interval_missing_observations(self):\n        rng = np.random.default_rng(1198)\n\n        with pm.Model() as model:\n            obs1 = np.ma.masked_values([1, 2, -1, 4, -1], value=-1)\n            obs2 = np.ma.masked_values([-1, -1, 6, -1, 8], value=-1)\n\n            with pytest.warns(ImputationWarning):\n                theta1 = pm.Uniform("theta1", 0, 5, observed=obs1)\n            with pytest.warns(ImputationWarning):\n                theta2 = pm.Normal("theta2", mu=theta1, observed=obs2)\n\n            assert isinstance(\n                model.rvs_to_transforms[model["theta1_unobserved"]], IntervalTransform\n            )\n            assert model.rvs_to_transforms[model["theta1_observed"]] is None\n\n            prior_trace = pm.sample_prior_predictive(random_seed=rng, return_inferencedata=False)\n            assert set(prior_trace.keys()) == {\n                "theta1",\n                "theta1_observed",\n                "theta1_unobserved",\n                "theta2",\n                "theta2_observed",\n                "theta2_unobserved",\n            }\n\n            # Make sure the observed + missing combined deterministics have the\n            # same shape as the original observations vectors\n            assert prior_trace["theta1"].shape[-1] == obs1.shape[0]\n            assert prior_trace["theta2"].shape[-1] == obs2.shape[0]\n\n            # Make sure that the observed values are newly generated samples\n            assert np.all(np.var(prior_trace["theta1_observed"], 0) > 0.0)\n            assert np.all(np.var(prior_trace["theta2_observed"], 0) > 0.0)\n\n            # Make sure the missing parts of the combined deterministic matches the\n            # sampled missing and observed variable values\n            assert (\n                np.mean(prior_trace["theta1"][:, obs1.mask] - prior_trace["theta1_unobserved"])\n                == 0.0\n            )\n            assert (\n                np.mean(prior_trace["theta1"][:, ~obs1.mask] - prior_trace["theta1_observed"])\n                == 0.0\n            )\n            assert (\n                np.mean(prior_trace["theta2"][:, obs2.mask] - prior_trace["theta2_unobserved"])\n                == 0.0\n            )\n            assert (\n                np.mean(prior_trace["theta2"][:, ~obs2.mask] - prior_trace["theta2_observed"])\n                == 0.0\n            )\n\n            trace = pm.sample(\n                chains=1,\n                draws=50,\n                compute_convergence_checks=False,\n                return_inferencedata=False,\n                random_seed=rng,\n            )\n            assert set(trace.varnames) == {\n                "theta1",\n                "theta1_unobserved",\n                "theta1_unobserved_interval__",\n                "theta2",\n                "theta2_unobserved",\n            }\n\n            # Make sure that the missing values are newly generated samples and that\n            # the observed and deterministic match\n            assert np.all(0 < trace["theta1_unobserved"].mean(0))\n            assert np.all(0 < trace["theta2_unobserved"].mean(0))\n            assert np.isclose(\n                np.mean(trace["theta1"][:, obs1.mask] - trace["theta1_unobserved"]), 0\n            )\n            assert np.isclose(\n                np.mean(trace["theta2"][:, obs2.mask] - trace["theta2_unobserved"]), 0\n            )\n\n            # Make sure that the observed values are unchanged\n            assert np.allclose(np.var(trace["theta1"][:, ~obs1.mask], 0), 0.0)\n            assert np.allclose(np.var(trace["theta2"][:, ~obs2.mask], 0), 0.0)\n            np.testing.assert_array_equal(trace["theta1"][0][~obs1.mask], obs1[~obs1.mask])\n            np.testing.assert_array_equal(trace["theta2"][0][~obs2.mask], obs1[~obs2.mask])\n\n            pp_idata = pm.sample_posterior_predictive(trace, random_seed=rng)\n            pp_trace = pp_idata.posterior_predictive.stack(sample=["chain", "draw"]).transpose(\n                "sample", ...\n            )\n            assert set(pp_trace.keys()) == {\n                "theta1",\n                "theta1_observed",\n                "theta2",\n                "theta2_observed",\n            }\n\n            # Make sure that the observed values are newly generated samples and that\n            # the observed and deterministic match\n            assert np.all(np.var(pp_trace["theta1"], 0) > 0.0)\n            assert np.all(np.var(pp_trace["theta2"], 0) > 0.0)\n            assert np.isclose(\n                np.mean(pp_trace["theta1"][:, ~obs1.mask] - pp_trace["theta1_observed"]), 0\n            )\n            assert np.isclose(\n                np.mean(pp_trace["theta2"][:, ~obs2.mask] - pp_trace["theta2_observed"]), 0\n            )\n\n    def test_missing_logp1(self):\n        with pm.Model(check_bounds=False) as m1:\n            x = pm.Gamma("x", 1, 1, size=4)\n\n        logp_val = m1.compile_logp()({"x_log__": np.array([0, 0, 0, 0])})\n        assert logp_val == -4.0\n\n        with pm.Model(check_bounds=False) as m2:\n            with pytest.warns(ImputationWarning):\n                x = pm.Gamma("x", 1, 1, observed=[1, 1, 1, np.nan])\n\n        logp_val = m2.compile_logp()({"x_unobserved_log__": np.array([0])})\n        assert logp_val == -4.0\n\n    def test_missing_logp2(self):\n        with pm.Model() as m:\n            theta1 = pm.Normal("theta1", 0, 5, observed=[0, 1, 2, 3, 4])\n            theta2 = pm.Normal("theta2", mu=theta1, observed=[0, 1, 2, 3, 4])\n        m_logp = m.compile_logp()({})\n\n        with pm.Model() as m_missing:\n            with pytest.warns(ImputationWarning):\n                theta1 = pm.Normal("theta1", 0, 5, observed=np.array([0, 1, np.nan, 3, np.nan]))\n                theta2 = pm.Normal(\n                    "theta2", mu=theta1, observed=np.array([np.nan, np.nan, 2, np.nan, 4])\n                )\n        m_missing_logp = m_missing.compile_logp()(\n            {"theta1_unobserved": [2, 4], "theta2_unobserved": [0, 1, 3]}\n        )\n\n        assert m_logp == m_missing_logp\n\n    def test_missing_multivariate_separable(self):\n        with pm.Model() as m_miss:\n            with pytest.warns(ImputationWarning):\n                x = pm.Dirichlet(\n                    "x",\n                    a=[1, 2, 3],\n                    observed=np.array([[0.3, 0.3, 0.4], [np.nan, np.nan, np.nan]]),\n                )\n        assert isinstance(m_miss["x_unobserved"].owner.op, pm.Dirichlet)\n        assert isinstance(m_miss["x_observed"].owner.op, pm.Dirichlet)\n\n        with pm.Model() as m_unobs:\n            x = pm.Dirichlet("x", a=[1, 2, 3], shape=(1, 3))\n\n        inp_vals = simplex.forward(np.array([[0.3, 0.3, 0.4]])).eval()\n        np.testing.assert_allclose(\n            m_miss.compile_logp(jacobian=False)({"x_unobserved_simplex__": inp_vals}),\n            m_unobs.compile_logp(jacobian=False)({"x_simplex__": inp_vals}) * 2,\n        )\n\n    def test_missing_multivariate_unseparable(self):\n        with pm.Model() as m_miss:\n            with pytest.warns(ImputationWarning):\n                x = pm.Dirichlet(\n                    "x",\n                    a=[1, 2, 3],\n                    observed=np.array([[0.3, 0.3, np.nan], [np.nan, np.nan, 0.4]]),\n                )\n\n        assert isinstance(m_miss["x_unobserved"].owner.op, PartialObservedRV)\n        assert isinstance(m_miss["x_observed"].owner.op, PartialObservedRV)\n\n        inp_values = np.array([0.3, 0.3, 0.4])\n        np.testing.assert_allclose(\n            m_miss.compile_logp()({"x_unobserved": [0.4, 0.3, 0.3]}),\n            st.dirichlet.logpdf(inp_values, [1, 2, 3]) * 2,\n        )\n\n    def test_missing_vector_parameter(self):\n        with pm.Model() as m:\n            with pytest.warns(ImputationWarning):\n                x = pm.Normal(\n                    "x",\n                    np.array([-10, 10]),\n                    0.1,\n                    observed=np.array([[np.nan, 10], [-10, np.nan], [np.nan, np.nan]]),\n                )\n        x_draws = x.eval()\n        assert x_draws.shape == (3, 2)\n        assert np.all(x_draws[:, 0] < 0)\n        assert np.all(x_draws[:, 1] > 0)\n        assert np.isclose(\n            m.compile_logp()({"x_unobserved": np.array([-10, 10, -10, 10])}),\n            st.norm(scale=0.1).logpdf(0) * 6,\n        )\n\n    def test_missing_symmetric(self):\n        """Check that logp works when partially observed variable have equal observed and\n        unobserved dimensions.\n\n        This would fail in a previous implementation because the two variables would be\n        equivalent and one of them would be discarded during MergeOptimization while\n        building the logp graph\n        """\n        with pm.Model() as m:\n            with pytest.warns(ImputationWarning):\n                x = pm.Gamma("x", alpha=3, beta=10, observed=np.array([1, np.nan]))\n\n        x_obs_rv = m["x_observed"]\n        x_obs_vv = m.rvs_to_values[x_obs_rv]\n\n        x_unobs_rv = m["x_unobserved"]\n        x_unobs_vv = m.rvs_to_values[x_unobs_rv]\n\n        logp = transformed_conditional_logp(\n            [x_obs_rv, x_unobs_rv],\n            rvs_to_values={x_obs_rv: x_obs_vv, x_unobs_rv: x_unobs_vv},\n            rvs_to_transforms={},\n        )\n        logp_inputs = list(graph_inputs(logp))\n        assert x_obs_vv in logp_inputs\n        assert x_unobs_vv in logp_inputs\n\n    def test_dims(self):\n        """Test that we don\'t propagate dims to the subcomponents of a partially\n        observed RV\n\n        See https://github.com/pymc-devs/pymc/issues/6177\n        """\n        data = np.array([np.nan] * 3 + [0] * 7)\n        with pm.Model(coords={"observed": range(10)}) as model:\n            with pytest.warns(ImputationWarning):\n                x = pm.Normal("x", observed=data, dims=("observed",))\n        assert model.named_vars_to_dims == {"x": ("observed",)}\n\n    def test_symbolic_random_variable(self):\n        data = np.array([np.nan] * 3 + [0] * 7)\n        with pm.Model() as model:\n            with pytest.warns(ImputationWarning):\n                x = pm.Censored(\n                    "x",\n                    pm.Normal.dist(),\n                    lower=0,\n                    upper=10,\n                    observed=data,\n                )\n        np.testing.assert_almost_equal(\n            model.compile_logp()({"x_unobserved": [0] * 3}),\n            st.norm.logcdf(0) * 10,\n        )\n\n    def test_truncated_normal(self):\n        """Test transform of unobserved TruncatedNormal leads to finite logp.\n\n        Regression test for #6999\n        """\n        with Model() as m:\n            mu = pm.TruncatedNormal("mu", mu=1, sigma=2, lower=0)\n            with pytest.warns(ImputationWarning):\n                x = pm.TruncatedNormal(\n                    "x",\n                    mu=mu,\n                    sigma=0.5,\n                    lower=0,\n                    observed=np.array([0.1, 0.2, 0.5, np.nan, np.nan]),\n                )\n        m.check_start_vals(m.initial_point())\n\n    def test_coordinates(self):\n        # Regression test for https://github.com/pymc-devs/pymc/issues/7304\n\n        coords = {"trial": range(30), "feature": range(2)}\n        observed = np.zeros((30, 2))\n        observed[0, 0] = np.nan\n\n        with Model(coords=coords) as model:\n            with pytest.warns(ImputationWarning):\n                MvNormal(\n                    "y",\n                    mu=np.zeros(2),\n                    cov=np.eye(2),\n                    observed=observed,\n                    dims=("trial", "feature"),\n                )\n\n        logp_fn = model.compile_logp()\n        np.testing.assert_allclose(\n            logp_fn({"y_unobserved": [0]}),\n            scipy.stats.multivariate_normal.logpdf([0, 0], cov=np.eye(2)) * 30,\n        )\n\n\nclass TestShared:\n    def test_deterministic(self):\n        with pm.Model() as model:\n            data_values = np.array([0.5, 0.4, 5, 2])\n            X = pytensor.shared(np.asarray(data_values, dtype=pytensor.config.floatX), borrow=True)\n            pm.Normal("y", 0, 1, observed=X)\n            assert np.all(\n                np.isclose(model.compile_logp(sum=False)({}), st.norm().logpdf(data_values))\n            )\n\n\nclass TestModelDebug:\n    @pytest.mark.parametrize("fn", ("logp", "dlogp", "random"))\n    def test_no_problems(self, fn, capfd):\n        with pm.Model() as m:\n            x = pm.Normal("x", [1, -1, 1])\n        m.debug(fn=fn)\n\n        out, _ = capfd.readouterr()\n        assert out == "point={\'x\': array([ 1., -1.,  1.])}\\n\\nNo problems found\\n"\n\n    @pytest.mark.parametrize("fn", ("logp", "dlogp", "random"))\n    def test_invalid_parameter(self, fn, capfd):\n        with pm.Model() as m:\n            x = pm.Normal("x", [1, -1, 1])\n            y = pm.HalfNormal("y", tau=x)\n        m.debug(fn=fn)\n\n        out, _ = capfd.readouterr()\n        if fn == "dlogp":\n            # var dlogp is 0 or 1 without a likelihood\n            assert "No problems found" in out\n        else:\n            assert "The parameters evaluate to:\\n0: [0.]\\n1: [ 1. -1.  1.]" in out\n            if fn == "logp":\n                assert "This does not respect one of the following constraints: sigma > 0" in out\n            else:\n                assert (\n                    "The variable y random method raised the following exception: Domain error in arguments."\n                    in out\n                )\n\n    @pytest.mark.parametrize("verbose", (True, False))\n    @pytest.mark.parametrize("fn", ("logp", "dlogp", "random"))\n    def test_invalid_parameter_cant_be_evaluated(self, fn, verbose, capfd):\n        with pm.Model() as m:\n            x = pm.Normal("x", [1, 1, 1])\n            sigma = Assert(msg="x > 0")(pm.math.abs(x), (x > 0).all())\n            y = pm.HalfNormal("y", sigma=sigma)\n        m.debug(point={"x": [-1, -1, -1], "y_log__": [0, 0, 0]}, fn=fn, verbose=verbose)\n\n        out, _ = capfd.readouterr()\n        assert "{\'x\': [-1, -1, -1], \'y_log__\': [0, 0, 0]}" in out\n        assert "The parameters of the variable y cannot be evaluated: x > 0" in out\n        verbose_str = "Apply node that caused the error:" in out\n        assert verbose_str if verbose else not verbose_str\n\n    def test_invalid_value(self, capfd):\n        with pm.Model() as m:\n            x = pm.Normal("x", [1, -1, 1])\n            y = pm.HalfNormal("y", tau=pm.math.abs(x), initval=[-1, 1, -1], default_transform=None)\n        m.debug()\n\n        out, _ = capfd.readouterr()\n        assert "The parameters of the variable y evaluate to:\\n0: array(0., dtype=float32)\\n1: array([1., 1., 1.])]"\n        assert "Some of the values of variable y are associated with a non-finite logp" in out\n        assert "value = -1.0 -> logp = -inf" in out\n\n    def test_invalid_observed_value(self, capfd):\n        with pm.Model() as m:\n            theta = pm.Uniform("theta", lower=0, upper=1)\n            y = pm.Uniform("y", lower=0, upper=theta, observed=[0.49, 0.27, 0.53, 0.19])\n        m.debug()\n\n        out, _ = capfd.readouterr()\n        assert "The parameters of the variable y evaluate to:\\n0: 0.0\\n1: 0.5"\n        assert (\n            "Some of the observed values of variable y are associated with a non-finite logp" in out\n        )\n        assert "value = 0.53 -> logp = -inf" in out\n\n\ndef test_model_logp_fast_compile():\n    # Issue #5618\n    with pm.Model() as m:\n        pm.Dirichlet("a", np.ones(3))\n\n    with pytensor.config.change_flags(mode="FAST_COMPILE"):\n        assert m.point_logps() == {"a": -1.5}\n\n\nclass TestModelGraphs:\n    @staticmethod\n    def school_model(J: int) -> pm.Model:\n        y = np.array([28, 8, -3, 7, -1, 1, 18, 12])\n        sigma = np.array([15, 10, 16, 11, 9, 11, 10, 18])\n        with pm.Model(coords={"school": np.arange(J)}) as schools:\n            eta = pm.Normal("eta", 0, 1, dims="school")\n            mu = pm.Normal("mu", 0, sigma=1e6)\n            tau = pm.HalfCauchy("tau", 25)\n            theta = mu + tau * eta\n            pm.Normal("obs", theta, sigma=sigma, observed=y, dims="school")\n        return schools\n\n    @pytest.mark.parametrize(\n        argnames="var_names", argvalues=[None, ["mu", "tau"]], ids=["all", "subset"]\n    )\n    @pytest.mark.parametrize(\n        argnames="filenames",\n        argvalues=["model.png", "model"],\n        ids=["ext", "no_ext"],\n    )\n    def test_graphviz_call_function(self, var_names, filenames) -> None:\n        model = self.school_model(J=8)\n        with patch("pymc.model.core.model_to_graphviz") as mock_model_to_graphviz:\n            model.to_graphviz(var_names=var_names, save=filenames)\n            mock_model_to_graphviz.assert_called_once_with(\n                model=model,\n                var_names=var_names,\n                formatting="plain",\n                save=filenames,\n                figsize=None,\n                dpi=300,\n            )\n\n\nclass TestModelCopy:\n    @pytest.mark.parametrize("copy_method", (copy.copy, copy.deepcopy))\n    def test_copy_model(self, copy_method) -> None:\n        with pm.Model() as simple_model:\n            pm.Normal("y")\n\n        copy_simple_model = copy_method(simple_model)\n\n        with simple_model:\n            simple_model_prior_predictive = pm.sample_prior_predictive(samples=1, random_seed=42)\n\n        with copy_simple_model:\n            z = pm.Deterministic("z", copy_simple_model["y"] + 1)\n            copy_simple_model_prior_predictive = pm.sample_prior_predictive(\n                samples=1, random_seed=42\n            )\n\n        assert (\n            simple_model_prior_predictive["prior"]["y"].values\n            == copy_simple_model_prior_predictive["prior"]["y"].values\n        )\n\n        assert "z" in copy_simple_model.named_vars\n        assert "z" not in simple_model.named_vars\n        assert (\n            copy_simple_model_prior_predictive["prior"]["z"].values\n            == 1 + simple_model_prior_predictive["prior"]["y"].values\n        )\n\n    @pytest.mark.parametrize("copy_method", (copy.copy, copy.deepcopy))\n    def test_guassian_process_copy_failure(self, copy_method) -> None:\n        with pm.Model() as gaussian_process_model:\n            ell = pm.Gamma("ell", alpha=2, beta=1)\n            cov = 2 * pm.gp.cov.ExpQuad(1, ell)\n            gp = pm.gp.Latent(cov_func=cov)\n            f = gp.prior("f", X=np.arange(10)[:, None])\n            pm.Normal("y", f * 2)\n\n        with pytest.warns(\n            UserWarning,\n            match="Detected variables likely created by GP objects. Further use of these old GP objects should be avoided as it may reintroduce variables from the old model. See issue: https://github.com/pymc-devs/pymc/issues/6883",\n        ):\n            copy_method(gaussian_process_model)\n',
            'tests/test_model_graph.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport warnings\n\nfrom textwrap import dedent\n\nimport numpy as np\nimport pytensor\nimport pytensor.tensor as pt\nimport pytest\n\nfrom pytensor.compile.sharedvalue import SharedVariable\nfrom pytensor.tensor.variable import TensorConstant\n\nimport pymc as pm\n\nfrom pymc.exceptions import ImputationWarning\nfrom pymc.model_graph import (\n    DimInfo,\n    ModelGraph,\n    NodeInfo,\n    NodeType,\n    Plate,\n    model_to_graphviz,\n    model_to_mermaid,\n    model_to_networkx,\n)\n\n\ndef sort_plates(plates: list[Plate]) -> list[Plate]:\n    return sorted(plates, key=lambda x: x.dim_info.lengths)\n\n\ndef school_model():\n    """\n    Schools model to use in testing model_to_networkx function\n    """\n    J = 8\n    y = np.array([28, 8, -3, 7, -1, 1, 18, 12])\n    sigma = np.array([15, 10, 16, 11, 9, 11, 10, 18])\n    with pm.Model() as schools:\n        eta = pm.Normal("eta", 0, 1, shape=J)\n        mu = pm.Normal("mu", 0, sigma=1e6)\n        tau = pm.HalfCauchy("tau", 25)\n        theta = mu + tau * eta\n        obs = pm.Normal("obs", theta, sigma=sigma, observed=y)\n    return schools\n\n\nclass BaseModelNXTest:\n    network_model = {\n        "graph_attr_dict_factory": dict,\n        "node_dict_factory": dict,\n        "node_attr_dict_factory": dict,\n        "adjlist_outer_dict_factory": dict,\n        "adjlist_inner_dict_factory": dict,\n        "edge_attr_dict_factory": dict,\n        "graph": {"name": "", "label": "8"},\n        "_node": {\n            "eta": {\n                "shape": "ellipse",\n                "style": "rounded",\n                "label": "eta\\n~\\nNormal",\n                "cluster": "cluster8",\n                "labeljust": "r",\n                "labelloc": "b",\n            },\n            "obs": {\n                "shape": "ellipse",\n                "style": "rounded",\n                "label": "obs\\n~\\nNormal",\n                "cluster": "cluster8",\n                "labeljust": "r",\n                "labelloc": "b",\n            },\n            "tau": {"shape": "ellipse", "style": None, "label": "tau\\n~\\nHalfCauchy"},\n            "mu": {"shape": "ellipse", "style": None, "label": "mu\\n~\\nNormal"},\n        },\n        "_adj": {"eta": {"obs": {}}, "obs": {}, "tau": {"obs": {}}, "mu": {"obs": {}}},\n        "_pred": {"eta": {}, "obs": {"tau": {}, "eta": {}, "mu": {}}, "tau": {}, "mu": {}},\n        "_succ": {"eta": {"obs": {}}, "obs": {}, "tau": {"obs": {}}, "mu": {"obs": {}}},\n    }\n\n    def test_networkx(self):\n        assert self.network_model == model_to_networkx(school_model()).__dict__\n\n\ndef radon_model():\n    """Similar in shape to the Radon model"""\n    n_homes = 919\n    counties = 85\n    uranium = np.random.normal(-0.1, 0.4, size=n_homes)\n    xbar = np.random.normal(1, 0.1, size=n_homes)\n    floor_measure = np.random.randint(0, 2, size=n_homes)\n\n    d, r = divmod(919, 85)\n    county = np.hstack((np.tile(np.arange(counties, dtype=int), d), np.arange(r)))\n    with pm.Model() as model:\n        sigma_a = pm.HalfCauchy("sigma_a", 5)\n        gamma = pm.Normal("gamma", mu=0.0, sigma=1e5, shape=3)\n        mu_a = pm.Deterministic("mu_a", gamma[0] + gamma[1] * uranium + gamma[2] * xbar)\n        eps_a = pm.Normal("eps_a", mu=0, sigma=sigma_a, shape=counties)\n        a = pm.Deterministic("a", mu_a + eps_a[county])\n        b = pm.Normal("b", mu=0.0, sigma=1e15)\n        sigma_y = pm.Uniform("sigma_y", lower=0, upper=100)\n\n        # Anonymous SharedVariables don\'t show up\n        floor_measure = pytensor.shared(floor_measure)\n        floor_measure_offset = pm.Data("floor_measure_offset", 1)\n        y_hat = a + b * floor_measure + floor_measure_offset\n        log_radon = pm.Data("log_radon", np.random.normal(1, 1, size=n_homes))\n        y_like = pm.Normal("y_like", mu=y_hat, sigma=sigma_y, observed=log_radon)\n\n    compute_graph = {\n        # variable_name : set of named parents in the graph\n        "sigma_a": set(),\n        "gamma": set(),\n        "mu_a": {"gamma"},\n        "eps_a": {"sigma_a"},\n        "a": {"mu_a", "eps_a"},\n        "b": set(),\n        "sigma_y": set(),\n        "y_like": {"a", "b", "sigma_y", "floor_measure_offset"},\n        "floor_measure_offset": set(),\n        # observed data don\'t have parents in the model graph, but are shown as descendants\n        # of the model variables that the observations belong to:\n        "log_radon": {"y_like"},\n    }\n    plates = [\n        Plate(\n            dim_info=DimInfo(names=(), lengths=()),\n            variables=[\n                NodeInfo(var=model["b"], node_type=NodeType.FREE_RV),\n                NodeInfo(var=model["sigma_a"], node_type=NodeType.FREE_RV),\n                NodeInfo(var=model["sigma_y"], node_type=NodeType.FREE_RV),\n                NodeInfo(var=model["floor_measure_offset"], node_type=NodeType.DATA),\n            ],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(3,)),\n            variables=[NodeInfo(var=model["gamma"], node_type=NodeType.FREE_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(85,)),\n            variables=[NodeInfo(var=model["eps_a"], node_type=NodeType.FREE_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(919,)),\n            variables=[\n                NodeInfo(var=model["a"], node_type=NodeType.DETERMINISTIC),\n                NodeInfo(var=model["mu_a"], node_type=NodeType.DETERMINISTIC),\n                NodeInfo(var=model["y_like"], node_type=NodeType.OBSERVED_RV),\n                NodeInfo(var=model["log_radon"], node_type=NodeType.DATA),\n            ],\n        ),\n    ]\n\n    return model, compute_graph, sort_plates(plates)\n\n\ndef model_with_imputations():\n    """The example from https://github.com/pymc-devs/pymc/issues/4043"""\n    x = np.random.randn(10) + 10.0\n    x = np.concatenate([x, [np.nan], [np.nan]])\n    x = np.ma.masked_array(x, np.isnan(x))\n\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        with pytest.warns(ImputationWarning):\n            pm.Normal("L", a, 1.0, observed=x)\n\n    compute_graph = {\n        "a": set(),\n        "L_unobserved": {"a"},\n        "L_observed": {"a"},\n        "L": {"L_unobserved", "L_observed"},\n    }\n    plates = [\n        Plate(\n            dim_info=DimInfo(names=(), lengths=()),\n            variables=[NodeInfo(var=model["a"], node_type=NodeType.FREE_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(2,)),\n            variables=[NodeInfo(var=model["L_unobserved"], node_type=NodeType.FREE_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(10,)),\n            variables=[NodeInfo(var=model["L_observed"], node_type=NodeType.OBSERVED_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(12,)),\n            variables=[NodeInfo(var=model["L"], node_type=NodeType.DETERMINISTIC)],\n        ),\n    ]\n    return model, compute_graph, sort_plates(plates)\n\n\ndef model_with_dims():\n    with pm.Model(coords={"city": ["Aachen", "Maastricht", "London", "Bergheim"]}) as pmodel:\n        economics = pm.Uniform("economics", lower=-1, upper=1, shape=(1,))\n\n        population = pm.HalfNormal("population", sigma=5, dims=("city"))\n\n        time = pm.Data("time", [2014, 2015, 2016], dims="year")\n\n        n = pm.Deterministic(\n            "tax revenue", economics * population[None, :] * time[:, None], dims=("year", "city")\n        )\n\n        yobs = pm.Data("observed", np.ones((3, 4)))\n        L = pm.Normal("L", n, observed=yobs)\n\n    compute_graph = {\n        "economics": set(),\n        "population": set(),\n        "time": set(),\n        "tax revenue": {"economics", "population", "time"},\n        "L": {"tax revenue"},\n        "observed": {"L"},\n    }\n    plates = [\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(1,)),\n            variables=[NodeInfo(var=pmodel["economics"], node_type=NodeType.FREE_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=("city",), lengths=(4,)),\n            variables=[NodeInfo(var=pmodel["population"], node_type=NodeType.FREE_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=("year",), lengths=(3,)),\n            variables=[NodeInfo(var=pmodel["time"], node_type=NodeType.DATA)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=("year", "city"), lengths=(3, 4)),\n            variables=[NodeInfo(var=pmodel["tax revenue"], node_type=NodeType.DETERMINISTIC)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None, None), lengths=(3, 4)),\n            variables=[\n                NodeInfo(var=pmodel["L"], node_type=NodeType.OBSERVED_RV),\n                NodeInfo(var=pmodel["observed"], node_type=NodeType.DATA),\n            ],\n        ),\n    ]\n\n    return pmodel, compute_graph, sort_plates(plates)\n\n\ndef model_unnamed_observed_node():\n    """\n    Model at the source of the following issue: https://github.com/pymc-devs/pymc/issues/5892\n    """\n    data = [-1, 0, 0.5, 1]\n\n    with pm.Model() as model:\n        mu = pm.Normal(name="mu", mu=0.0, sigma=5.0)\n        y = pm.Normal(name="y", mu=mu, sigma=3.0, observed=data)\n\n    compute_graph = {\n        "mu": set(),\n        "y": {"mu"},\n    }\n    plates = [\n        Plate(\n            dim_info=DimInfo(\n                names=(),\n                lengths=(),\n            ),\n            variables=[NodeInfo(var=model["mu"], node_type=NodeType.FREE_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(\n                names=(None,),\n                lengths=(4,),\n            ),\n            variables=[NodeInfo(var=model["y"], node_type=NodeType.OBSERVED_RV)],\n        ),\n    ]\n\n    return model, compute_graph, sort_plates(plates)\n\n\ndef model_observation_dtype_casting():\n    """\n    Model at the source of the following issue: https://github.com/pymc-devs/pymc/issues/5795\n    """\n    with pm.Model() as model:\n        data = pm.Data("data", np.array([0, 0, 1, 1], dtype=int))\n        p = pm.Beta("p", 1, 1)\n        bern = pm.Bernoulli("response", p, observed=data)\n\n    compute_graph = {\n        "p": set(),\n        "response": {"p"},\n        "data": {"response"},\n    }\n    plates = [\n        Plate(\n            dim_info=DimInfo(names=(), lengths=()),\n            variables=[NodeInfo(var=model["p"], node_type=NodeType.FREE_RV)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(4,)),\n            variables=[\n                NodeInfo(var=model["data"], node_type=NodeType.DATA),\n                NodeInfo(var=model["response"], node_type=NodeType.OBSERVED_RV),\n            ],\n        ),\n    ]\n\n    return model, compute_graph, sort_plates(plates)\n\n\ndef model_non_random_variable_rvs():\n    """Test that node types are not inferred based on the variable Op type, but\n    model properties\n\n    See https://github.com/pymc-devs/pymc/issues/5766\n    """\n    with pm.Model() as model:\n        mu = pm.Normal(name="mu", mu=0.0, sigma=5.0)\n\n        y_raw = pm.Normal.dist(mu)\n        y = pm.math.clip(y_raw, -3, 3)\n        model.register_rv(y, name="y")\n\n        z_raw = pm.Normal.dist(y, shape=(5,))\n        z = pm.math.clip(z_raw, -1, 1)\n        model.register_rv(z, name="z", observed=[0] * 5)\n\n    compute_graph = {\n        "mu": set(),\n        "y": {"mu"},\n        "z": {"y"},\n    }\n    plates = [\n        Plate(\n            dim_info=DimInfo(names=(), lengths=()),\n            variables=[\n                NodeInfo(var=model["mu"], node_type=NodeType.FREE_RV),\n                NodeInfo(var=model["y"], node_type=NodeType.FREE_RV),\n            ],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(5,)),\n            variables=[NodeInfo(var=model["z"], node_type=NodeType.OBSERVED_RV)],\n        ),\n    ]\n\n    return model, compute_graph, sort_plates(plates)\n\n\nclass BaseModelGraphTest:\n    model_func = None\n\n    @classmethod\n    def setup_class(cls):\n        cls.model, cls.compute_graph, cls.plates = cls.model_func()\n        cls.model_graph = ModelGraph(cls.model)\n\n    def test_inputs(self):\n        for child, parents_in_plot in self.compute_graph.items():\n            var = self.model[child]\n            parents_in_graph = self.model_graph.get_parent_names(var)\n            if isinstance(var, SharedVariable | TensorConstant):\n                # observed data also doesn\'t have parents in the compute graph!\n                # But for the visualization we like them to become descendants of the\n                # RVs that these observations belong to.\n                assert not parents_in_graph\n            else:\n                assert parents_in_plot == parents_in_graph\n\n    def test_compute_graph(self):\n        expected = self.compute_graph\n        actual = self.model_graph.make_compute_graph()\n        assert actual == expected\n\n    def test_plates(self):\n        assert self.plates == sort_plates(self.model_graph.get_plates())\n\n    def test_graphviz(self):\n        # just make sure everything runs without error\n\n        g = model_to_graphviz(self.model)\n        for key in self.compute_graph:\n            assert key in g.source\n\n\nclass TestRadonModel(BaseModelGraphTest):\n    model_func = radon_model\n\n    def test_checks_formatting(self):\n        with warnings.catch_warnings():\n            warnings.simplefilter("error")\n            model_to_graphviz(self.model, formatting="plain")\n        with pytest.raises(ValueError, match="Unsupported formatting"):\n            model_to_graphviz(self.model, formatting="latex")\n        with pytest.warns(UserWarning, match="currently not supported"):\n            model_to_graphviz(self.model, formatting="plain_with_params")\n\n\ndef model_with_different_descendants():\n    """\n    Model proposed by Michael to test variable selection functionality\n    From here: https://github.com/pymc-devs/pymc/pull/5634#pullrequestreview-916297509\n    """\n    with pm.Model() as pmodel2:\n        a = pm.Normal("a")\n        b = pm.Normal("b")\n        pm.Normal("c", a * b)\n        intermediate = pm.Deterministic("intermediate", a + b)\n        pred = pm.Deterministic("pred", intermediate * 3)\n\n        obs = pm.Data("obs", 1.75)\n\n        L = pm.Normal("L", mu=1 + 0.5 * pred, observed=obs)\n\n    return pmodel2\n\n\nclass TestImputationModel(BaseModelGraphTest):\n    model_func = model_with_imputations\n\n\nclass TestModelWithDims(BaseModelGraphTest):\n    model_func = model_with_dims\n\n    def test_issue_6335_dims_containing_none(self):\n        with pm.Model(coords={"time": np.arange(5)}) as pmodel:\n            data = pt.as_tensor(np.ones((3, 5)))\n            pm.Deterministic("n", data, dims=(None, "time"))\n\n        mg = ModelGraph(pmodel)\n        plates_actual = sort_plates(mg.get_plates())\n        plates_expected = sort_plates(\n            [\n                Plate(\n                    dim_info=DimInfo(names=(None, "time"), lengths=(3, 5)),\n                    variables=[NodeInfo(var=pmodel["n"], node_type=NodeType.DETERMINISTIC)],\n                ),\n            ]\n        )\n        assert plates_actual == plates_expected\n\n\nclass TestUnnamedObservedNodes(BaseModelGraphTest):\n    model_func = model_unnamed_observed_node\n\n\nclass TestObservationDtypeCasting(BaseModelGraphTest):\n    model_func = model_observation_dtype_casting\n\n\nclass TestVariableSelection:\n    @pytest.mark.parametrize(\n        "var_names, vars_to_plot, compute_graph",\n        [\n            (["c"], ["a", "b", "c"], {"c": {"a", "b"}, "a": set(), "b": set()}),\n            (\n                ["L"],\n                ["pred", "obs", "L", "intermediate", "a", "b"],\n                {\n                    "pred": {"intermediate"},\n                    "obs": {"L"},\n                    "L": {"pred"},\n                    "intermediate": {"a", "b"},\n                    "a": set(),\n                    "b": set(),\n                },\n            ),\n            (\n                ["obs"],\n                ["pred", "obs", "L", "intermediate", "a", "b"],\n                {\n                    "pred": {"intermediate"},\n                    "obs": {"L"},\n                    "L": {"pred"},\n                    "intermediate": {"a", "b"},\n                    "a": set(),\n                    "b": set(),\n                },\n            ),\n            # selecting ["c", "L"] is akin to selecting the entire graph\n            (\n                ["c", "L"],\n                ModelGraph(model_with_different_descendants()).vars_to_plot(),\n                ModelGraph(model_with_different_descendants()).make_compute_graph(),\n            ),\n        ],\n    )\n    def test_subgraph(self, var_names, vars_to_plot, compute_graph):\n        mg = ModelGraph(model_with_different_descendants())\n        assert set(mg.vars_to_plot(var_names=var_names)) == set(vars_to_plot)\n        assert mg.make_compute_graph(var_names=var_names) == compute_graph\n\n\nclass TestModelNonRandomVariableRVs(BaseModelGraphTest):\n    model_func = model_non_random_variable_rvs\n\n\ndef test_model_graph_with_intermediate_named_variables():\n    # Issue 6421\n    with pm.Model() as m1:\n        a = pm.Normal("a", 0, 1, shape=3)\n        pm.Normal("b", a.mean(axis=-1), 1)\n    assert dict(ModelGraph(m1).make_compute_graph()) == {"a": set(), "b": {"a"}}\n\n    with pm.Model() as m2:\n        a = pm.Normal("a", 0, 1)\n        b = a + 1\n        b.name = "b"\n        pm.Normal("c", b, 1)\n    assert dict(ModelGraph(m2).make_compute_graph()) == {"a": set(), "c": {"a"}}\n\n\n@pytest.fixture\ndef simple_model() -> pm.Model:\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        b = pm.Normal("b", mu=a)\n        c = pm.Normal("c", mu=b)\n\n    return model\n\n\ndef test_unknown_node_type(simple_model):\n    with pytest.raises(ValueError, match="Node formatters must be of type NodeType."):\n        model_to_graphviz(simple_model, node_formatters={"Unknown Node Type": "dummy"})\n\n\ndef test_custom_node_formatting_networkx(simple_model):\n    node_formatters = {\n        "Free Random Variable": lambda var: {\n            "label": var.name,\n        },\n    }\n\n    G = model_to_networkx(simple_model, node_formatters=node_formatters)\n    assert G.__dict__["_node"] == {\n        "a": {"label": "a"},\n        "b": {"label": "b"},\n        "c": {"label": "c"},\n    }\n\n\ndef test_custom_node_formatting_graphviz(simple_model):\n    node_formatters = {\n        "Free Random Variable": lambda var: {\n            "label": var.name,\n        },\n    }\n\n    G = model_to_graphviz(simple_model, node_formatters=node_formatters)\n    body = {item.strip() for item in G.body}\n\n    items = {\n        "a [label=a]",\n        "b [label=b]",\n        "c [label=c]",\n        "a -> b",\n        "b -> c",\n    }\n    assert body == items\n\n\ndef test_none_dim_in_plate() -> None:\n    coords = {\n        "obs": range(5),\n    }\n    with pm.Model(coords=coords) as model:\n        data = pt.as_tensor_variable(\n            np.ones((5, 5)),\n            name="data",\n        )\n        pm.Deterministic("C", data, dims=("obs", None))\n        pm.Deterministic("D", data.T, dims=(None, "obs"))\n\n    graph = ModelGraph(model)\n\n    assert graph.get_plates() == [\n        Plate(\n            dim_info=DimInfo(names=("obs", None), lengths=(5, 5)),\n            variables=[NodeInfo(var=model["C"], node_type=NodeType.DETERMINISTIC)],\n        ),\n        Plate(\n            dim_info=DimInfo(names=(None, "obs"), lengths=(5, 5)),\n            variables=[NodeInfo(var=model["D"], node_type=NodeType.DETERMINISTIC)],\n        ),\n    ]\n    assert graph.edges() == []\n\n\ndef test_shape_without_dims() -> None:\n    with pm.Model() as model:\n        pm.Normal("mu", shape=5)\n\n    graph = ModelGraph(model)\n\n    assert graph.get_plates() == [\n        Plate(\n            dim_info=DimInfo(names=(None,), lengths=(5,)),\n            variables=[NodeInfo(var=model["mu"], node_type=NodeType.FREE_RV)],\n        ),\n    ]\n    assert graph.edges() == []\n\n\ndef test_scalars_dim_info() -> None:\n    with pm.Model() as model:\n        pm.Normal("x")\n\n    graph = ModelGraph(model)\n\n    assert graph.get_plates() == [\n        Plate(\n            dim_info=DimInfo(names=(), lengths=()),\n            variables=[NodeInfo(var=model["x"], node_type=NodeType.FREE_RV)],\n        )\n    ]\n\n    assert graph.edges() == []\n\n\ndef test_model_to_mermaid(simple_model):\n    expected_mermaid_string = dedent("""\n    graph TD\n    %% Nodes:\n    a([a ~ Normal])\n    a@{ shape: rounded }\n    b([b ~ Normal])\n    b@{ shape: rounded }\n    c([c ~ Normal])\n    c@{ shape: rounded }\n\n    %% Edges:\n    a --> b\n    b --> c\n\n    %% Plates:\n    """)\n    assert model_to_mermaid(simple_model) == expected_mermaid_string.strip()\n\n\ndef test_model_to_mermaid_with_variable_with_space():\n    with pm.Model() as variable_with_space:\n        pm.Normal("plant growth")\n\n    expected_mermaid_string = dedent("""\n    graph TD\n    %% Nodes:\n    plant_growth([plant growth ~ Normal])\n    plant_growth@{ shape: rounded }\n\n    %% Edges:\n\n    %% Plates:\n    """)\n    assert model_to_mermaid(variable_with_space) == expected_mermaid_string.strip()\n',
        }
